window.BIBLE["Romans"] = {"1":{"chapter":"1","title":"THE GOSPEL OF GOD — PAUL'S THEME","verses":{"1":{"text":"Paul, a servant of Jesus Christ, called to be an apostle, separated unto the gospel of God,","ref":"Romans 1:1","synthesized":"Paul, a servant of Christ Jesus, called to be an apostle, and set apart for the gospel of God—","sources":{"KJV":{"text":"Paul, a servant of Jesus Christ, called to be an apostle, separated unto the gospel of God,"},"BSB":{"text":"Paul, a servant of Christ Jesus, called to be an apostle, and set apart for the gospel of God—"}},"definableWords":["servant","Christ","apostle","gospel","God"],"peopleInVerse":["Paul","Jesus"]},"2":{"text":"(Which he had promised afore by his prophets in the holy scriptures,)","ref":"Romans 1:2","synthesized":"the gospel He promised beforehand through His prophets in the Holy Scriptures,","sources":{"KJV":{"text":"(Which he had promised afore by his prophets in the holy scriptures,)"},"BSB":{"text":"the gospel He promised beforehand through His prophets in the Holy Scriptures,"}},"definableWords":["gospel","holy"],"peopleInVerse":[]},"3":{"text":"Concerning his Son Jesus Christ our Lord, which was made of the seed of David according to the flesh;","ref":"Romans 1:3","synthesized":"regarding His Son, who was a descendant of David according to the flesh,","sources":{"KJV":{"text":"Concerning his Son Jesus Christ our Lord, which was made of the seed of David according to the flesh;"},"BSB":{"text":"regarding His Son, who was a descendant of David according to the flesh,"}},"definableWords":["Son","flesh"],"peopleInVerse":["David"]},"4":{"text":"And declared to be the Son of God with power, according to the spirit of holiness, by the resurrection from the dead:","ref":"Romans 1:4","synthesized":"and who through the Spirit of holiness was declared with power to be the Son of God by His resurrection from the dead: Jesus Christ our Lord.","sources":{"KJV":{"text":"And declared to be the Son of God with power, according to the spirit of holiness, by the resurrection from the dead:"},"BSB":{"text":"and who through the Spirit of holiness was declared with power to be the Son of God by His resurrection from the dead: Jesus Christ our Lord."}},"definableWords":["Spirit","Son","God","resurrection","Christ","Lord"],"peopleInVerse":["Jesus"]},"5":{"text":"By whom we have received grace and apostleship, for obedience to the faith among all nations, for his name:","ref":"Romans 1:5","synthesized":"Through Him and on behalf of His name, we received grace and apostleship to call all those among the Gentiles to the obedience that comes from faith.","sources":{"KJV":{"text":"By whom we have received grace and apostleship, for obedience to the faith among all nations, for his name:"},"BSB":{"text":"Through Him and on behalf of His name, we received grace and apostleship to call all those among the Gentiles to the obedience that comes from faith."}},"definableWords":["name","grace","faith"],"peopleInVerse":[]},"6":{"text":"Among whom are ye also the called of Jesus Christ:","ref":"Romans 1:6","synthesized":"And you also are among those who are called to belong to Jesus Christ.","sources":{"KJV":{"text":"Among whom are ye also the called of Jesus Christ:"},"BSB":{"text":"And you also are among those who are called to belong to Jesus Christ."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"7":{"text":"To all that be in Rome, beloved of God, called to be saints: Grace to you and peace from God our Father, and the Lord Jesus Christ.","ref":"Romans 1:7","synthesized":"To all in Rome who are loved by God and called to be saints:  Grace and peace to you from God our Father and the Lord Jesus Christ.","sources":{"KJV":{"text":"To all that be in Rome, beloved of God, called to be saints: Grace to you and peace from God our Father, and the Lord Jesus Christ."},"BSB":{"text":"To all in Rome who are loved by God and called to be saints:  Grace and peace to you from God our Father and the Lord Jesus Christ."}},"definableWords":["God","grace","peace","Father","Lord","Christ"],"peopleInVerse":["Jesus"]},"8":{"text":"First, I thank my God through Jesus Christ for you all, that your faith is spoken of throughout the whole world.","ref":"Romans 1:8","synthesized":"First, I thank my God through Jesus Christ for all of you, because your faith is being proclaimed all over the world.","sources":{"KJV":{"text":"First, I thank my God through Jesus Christ for you all, that your faith is spoken of throughout the whole world."},"BSB":{"text":"First, I thank my God through Jesus Christ for all of you, because your faith is being proclaimed all over the world."}},"definableWords":["God","Christ","faith"],"peopleInVerse":["Jesus"]},"9":{"text":"For God is my witness, whom I serve with my spirit in the gospel of his Son, that without ceasing I make mention of you always in my prayers;","ref":"Romans 1:9","synthesized":"God, whom I serve with my spirit in preaching the gospel of His Son, is my witness how constantly I remember you","sources":{"KJV":{"text":"For God is my witness, whom I serve with my spirit in the gospel of his Son, that without ceasing I make mention of you always in my prayers;"},"BSB":{"text":"God, whom I serve with my spirit in preaching the gospel of His Son, is my witness how constantly I remember you"}},"definableWords":["God","spirit","gospel","Son","remember"],"peopleInVerse":[]},"10":{"text":"Making request, if by any means now at length I might have a prosperous journey by the will of God to come unto you.","ref":"Romans 1:10","synthesized":"in my prayers at all times, asking that now at last by God’s will I may succeed in coming to you.","sources":{"KJV":{"text":"Making request, if by any means now at length I might have a prosperous journey by the will of God to come unto you."},"BSB":{"text":"in my prayers at all times, asking that now at last by God’s will I may succeed in coming to you."}},"definableWords":["God"],"peopleInVerse":[]},"11":{"text":"For I long to see you, that I may impart unto you some spiritual gift, to the end ye may be established;","ref":"Romans 1:11","synthesized":"For I long to see you so that I may impart to you some spiritual gift to strengthen you,","sources":{"KJV":{"text":"For I long to see you, that I may impart unto you some spiritual gift, to the end ye may be established;"},"BSB":{"text":"For I long to see you so that I may impart to you some spiritual gift to strengthen you,"}},"definableWords":["see"],"peopleInVerse":[]},"12":{"text":"That is, that I may be comforted together with you by the mutual faith both of you and me.","ref":"Romans 1:12","synthesized":"that is, that you and I may be mutually encouraged by each other’s faith.","sources":{"KJV":{"text":"That is, that I may be comforted together with you by the mutual faith both of you and me."},"BSB":{"text":"that is, that you and I may be mutually encouraged by each other’s faith."}},"definableWords":["faith"],"peopleInVerse":[]},"13":{"text":"Now I would not have you ignorant, brethren, that oftentimes I purposed to come unto you, (but was let hitherto,) that I might have some fruit among you also, even as among other Gentiles.","ref":"Romans 1:13","synthesized":"I do not want you to be unaware, brothers, how often I planned to come to you (but have been prevented from visiting until now), in order that I might have a harvest among you, just as I have had among the other Gentiles.","sources":{"KJV":{"text":"Now I would not have you ignorant, brethren, that oftentimes I purposed to come unto you, (but was let hitherto,) that I might have some fruit among you also, even as among other Gentiles."},"BSB":{"text":"I do not want you to be unaware, brothers, how often I planned to come to you (but have been prevented from visiting until now), in order that I might have a harvest among you, just as I have had among the other Gentiles."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"I am debtor both to the Greeks, and to the Barbarians; both to the wise, and to the unwise.","ref":"Romans 1:14","synthesized":"I am obligated both to Greeks and non-Greeks, both to the wise and the foolish.","sources":{"KJV":{"text":"I am debtor both to the Greeks, and to the Barbarians; both to the wise, and to the unwise."},"BSB":{"text":"I am obligated both to Greeks and non-Greeks, both to the wise and the foolish."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"So, as much as in me is, I am ready to preach the gospel to you that are at Rome also.","ref":"Romans 1:15","synthesized":"That is why I am so eager to preach the gospel also to you who are in Rome.","sources":{"KJV":{"text":"So, as much as in me is, I am ready to preach the gospel to you that are at Rome also."},"BSB":{"text":"That is why I am so eager to preach the gospel also to you who are in Rome."}},"definableWords":["gospel"],"peopleInVerse":[]},"16":{"text":"For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek.","ref":"Romans 1:16","synthesized":"I am not ashamed of the gospel, because it is the power of God for salvation to everyone who believes, first to the Jew, then to the Greek.","sources":{"KJV":{"text":"For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek."},"BSB":{"text":"I am not ashamed of the gospel, because it is the power of God for salvation to everyone who believes, first to the Jew, then to the Greek."}},"definableWords":["gospel","God","salvation","Jew","Greek"],"peopleInVerse":[]},"17":{"text":"For therein is the righteousness of God revealed from faith to faith: as it is written, The just shall live by faith.","ref":"Romans 1:17","synthesized":"For the gospel reveals the righteousness of God that comes by faith from start to finish, just as it is written: “The righteous will live by faith.”","sources":{"KJV":{"text":"For therein is the righteousness of God revealed from faith to faith: as it is written, The just shall live by faith."},"BSB":{"text":"For the gospel reveals the righteousness of God that comes by faith from start to finish, just as it is written: “The righteous will live by faith.”"}},"definableWords":["gospel","righteousness","God","faith","righteous","live"],"peopleInVerse":[]},"18":{"text":"For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men, who hold the truth in unrighteousness;","ref":"Romans 1:18","synthesized":"The wrath of God is being revealed from heaven against all the godlessness and wickedness of men who suppress the truth by their wickedness.","sources":{"KJV":{"text":"For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men, who hold the truth in unrighteousness;"},"BSB":{"text":"The wrath of God is being revealed from heaven against all the godlessness and wickedness of men who suppress the truth by their wickedness."}},"definableWords":["wrath","God","heaven","men","truth"],"peopleInVerse":[]},"19":{"text":"Because that which may be known of God is manifest in them; for God hath shewed it unto them.","ref":"Romans 1:19","synthesized":"For what may be known about God is plain to them, because God has made it plain to them.","sources":{"KJV":{"text":"Because that which may be known of God is manifest in them; for God hath shewed it unto them."},"BSB":{"text":"For what may be known about God is plain to them, because God has made it plain to them."}},"definableWords":["God","made"],"peopleInVerse":[]},"20":{"text":"For the invisible things of him from the creation of the world are clearly seen, being understood by the things that are made, even his eternal power and Godhead; so that they are without excuse:","ref":"Romans 1:20","synthesized":"For since the creation of the world God’s invisible qualities, His eternal power and divine nature, have been clearly seen, being understood from His workmanship, so that men are without excuse.","sources":{"KJV":{"text":"For the invisible things of him from the creation of the world are clearly seen, being understood by the things that are made, even his eternal power and Godhead; so that they are without excuse:"},"BSB":{"text":"For since the creation of the world God’s invisible qualities, His eternal power and divine nature, have been clearly seen, being understood from His workmanship, so that men are without excuse."}},"definableWords":["God","eternal","men"],"peopleInVerse":[]},"21":{"text":"Because that, when they knew God, they glorified him not as God, neither were thankful; but became vain in their imaginations, and their foolish heart was darkened.","ref":"Romans 1:21","synthesized":"For although they knew God, they neither glorified Him as God nor gave thanks to Him, but they became futile in their thinking and darkened in their foolish hearts.","sources":{"KJV":{"text":"Because that, when they knew God, they glorified him not as God, neither were thankful; but became vain in their imaginations, and their foolish heart was darkened."},"BSB":{"text":"For although they knew God, they neither glorified Him as God nor gave thanks to Him, but they became futile in their thinking and darkened in their foolish hearts."}},"definableWords":["God"],"peopleInVerse":[]},"22":{"text":"Professing themselves to be wise, they became fools,","ref":"Romans 1:22","synthesized":"Although they claimed to be wise, they became fools,","sources":{"KJV":{"text":"Professing themselves to be wise, they became fools,"},"BSB":{"text":"Although they claimed to be wise, they became fools,"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"And changed the glory of the uncorruptible God into an image made like to corruptible man, and to birds, and fourfooted beasts, and creeping things.","ref":"Romans 1:23","synthesized":"and exchanged the glory of the immortal God for images of mortal man and birds and animals and reptiles.","sources":{"KJV":{"text":"And changed the glory of the uncorruptible God into an image made like to corruptible man, and to birds, and fourfooted beasts, and creeping things."},"BSB":{"text":"and exchanged the glory of the immortal God for images of mortal man and birds and animals and reptiles."}},"definableWords":["glory","God","man","birds"],"peopleInVerse":[]},"24":{"text":"Wherefore God also gave them up to uncleanness through the lusts of their own hearts, to dishonour their own bodies between themselves:","ref":"Romans 1:24","synthesized":"Therefore God gave them over in the desires of their hearts to impurity for the dishonoring of their bodies with one another.","sources":{"KJV":{"text":"Wherefore God also gave them up to uncleanness through the lusts of their own hearts, to dishonour their own bodies between themselves:"},"BSB":{"text":"Therefore God gave them over in the desires of their hearts to impurity for the dishonoring of their bodies with one another."}},"definableWords":["God","one"],"peopleInVerse":[]},"25":{"text":"Who changed the truth of God into a lie, and worshipped and served the creature more than the Creator, who is blessed for ever. Amen.","ref":"Romans 1:25","synthesized":"They exchanged the truth of God for a lie, and worshiped and served the creature rather than the Creator, who is forever worthy of praise! Amen.","sources":{"KJV":{"text":"Who changed the truth of God into a lie, and worshipped and served the creature more than the Creator, who is blessed for ever. Amen."},"BSB":{"text":"They exchanged the truth of God for a lie, and worshiped and served the creature rather than the Creator, who is forever worthy of praise! Amen."}},"definableWords":["truth","God","praise"],"peopleInVerse":[]},"26":{"text":"For this cause God gave them up unto vile affections: for even their women did change the natural use into that which is against nature:","ref":"Romans 1:26","synthesized":"For this reason God gave them over to dishonorable passions. Even their women exchanged natural relations for unnatural ones.","sources":{"KJV":{"text":"For this cause God gave them up unto vile affections: for even their women did change the natural use into that which is against nature:"},"BSB":{"text":"For this reason God gave them over to dishonorable passions. Even their women exchanged natural relations for unnatural ones."}},"definableWords":["God","women"],"peopleInVerse":[]},"27":{"text":"And likewise also the men, leaving the natural use of the woman, burned in their lust one toward another; men with men working that which is unseemly, and receiving in themselves that recompence of their error which was meet.","ref":"Romans 1:27","synthesized":"Likewise, the men abandoned natural relations with women and burned with lust for one another. Men committed indecent acts with other men, and received in themselves the due penalty for their error.","sources":{"KJV":{"text":"And likewise also the men, leaving the natural use of the woman, burned in their lust one toward another; men with men working that which is unseemly, and receiving in themselves that recompence of their error which was meet."},"BSB":{"text":"Likewise, the men abandoned natural relations with women and burned with lust for one another. Men committed indecent acts with other men, and received in themselves the due penalty for their error."}},"definableWords":["men","women","one"],"peopleInVerse":[]},"28":{"text":"And even as they did not like to retain God in their knowledge, God gave them over to a reprobate mind, to do those things which are not convenient;","ref":"Romans 1:28","synthesized":"Furthermore, since they did not see fit to acknowledge God, He gave them up to a depraved mind, to do what ought not to be done.","sources":{"KJV":{"text":"And even as they did not like to retain God in their knowledge, God gave them over to a reprobate mind, to do those things which are not convenient;"},"BSB":{"text":"Furthermore, since they did not see fit to acknowledge God, He gave them up to a depraved mind, to do what ought not to be done."}},"definableWords":["see","God","mind"],"peopleInVerse":[]},"29":{"text":"Being filled with all unrighteousness, fornication, wickedness, covetousness, maliciousness; full of envy, murder, debate, deceit, malignity; whisperers,","ref":"Romans 1:29","synthesized":"They have become filled with every kind of wickedness, evil, greed, and depravity. They are full of envy, murder, strife, deceit, and malice. They are gossips,","sources":{"KJV":{"text":"Being filled with all unrighteousness, fornication, wickedness, covetousness, maliciousness; full of envy, murder, debate, deceit, malignity; whisperers,"},"BSB":{"text":"They have become filled with every kind of wickedness, evil, greed, and depravity. They are full of envy, murder, strife, deceit, and malice. They are gossips,"}},"definableWords":["evil"],"peopleInVerse":[]},"30":{"text":"Backbiters, haters of God, despiteful, proud, boasters, inventors of evil things, disobedient to parents,","ref":"Romans 1:30","synthesized":"slanderers, God-haters, insolent, arrogant, and boastful. They invent new forms of evil; they disobey their parents.","sources":{"KJV":{"text":"Backbiters, haters of God, despiteful, proud, boasters, inventors of evil things, disobedient to parents,"},"BSB":{"text":"slanderers, God-haters, insolent, arrogant, and boastful. They invent new forms of evil; they disobey their parents."}},"definableWords":["God","evil"],"peopleInVerse":[]},"31":{"text":"Without understanding, covenantbreakers, without natural affection, implacable, unmerciful:","ref":"Romans 1:31","synthesized":"They are senseless, faithless, heartless, merciless.","sources":{"KJV":{"text":"Without understanding, covenantbreakers, without natural affection, implacable, unmerciful:"},"BSB":{"text":"They are senseless, faithless, heartless, merciless."}},"definableWords":[],"peopleInVerse":[]},"32":{"text":"Who knowing the judgment of God, that they which commit such things are worthy of death, not only do the same, but have pleasure in them that do them.","ref":"Romans 1:32","synthesized":"Although they know God’s righteous decree that those who do such things are worthy of death, they not only continue to do these things, but also approve of those who practice them.","sources":{"KJV":{"text":"Who knowing the judgment of God, that they which commit such things are worthy of death, not only do the same, but have pleasure in them that do them."},"BSB":{"text":"Although they know God’s righteous decree that those who do such things are worthy of death, they not only continue to do these things, but also approve of those who practice them."}},"definableWords":["God","righteous","death"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"GOD JUDGES ACCORDING TO TRUTH","verses":{"1":{"text":"Therefore thou art inexcusable, O man, whosoever thou art that judgest: for wherein thou judgest another, thou condemnest thyself; for thou that judgest doest the same things.","ref":"Romans 2:1","synthesized":"You, therefore, have no excuse, you who pass judgment on another. For on whatever grounds you judge the other, you are condemning yourself, because you who pass judgment do the same things.","sources":{"KJV":{"text":"Therefore thou art inexcusable, O man, whosoever thou art that judgest: for wherein thou judgest another, thou condemnest thyself; for thou that judgest doest the same things."},"BSB":{"text":"You, therefore, have no excuse, you who pass judgment on another. For on whatever grounds you judge the other, you are condemning yourself, because you who pass judgment do the same things."}},"definableWords":["judgment"],"peopleInVerse":[]},"2":{"text":"But we are sure that the judgment of God is according to truth against them which commit such things.","ref":"Romans 2:2","synthesized":"And we know that God’s judgment against those who do such things is based on truth.","sources":{"KJV":{"text":"But we are sure that the judgment of God is according to truth against them which commit such things."},"BSB":{"text":"And we know that God’s judgment against those who do such things is based on truth."}},"definableWords":["God","judgment","truth"],"peopleInVerse":[]},"3":{"text":"And thinkest thou this, O man, that judgest them which do such things, and doest the same, that thou shalt escape the judgment of God?","ref":"Romans 2:3","synthesized":"So when you, O man, pass judgment on others, yet do the same things, do you think you will escape God’s judgment?","sources":{"KJV":{"text":"And thinkest thou this, O man, that judgest them which do such things, and doest the same, that thou shalt escape the judgment of God?"},"BSB":{"text":"So when you, O man, pass judgment on others, yet do the same things, do you think you will escape God’s judgment?"}},"definableWords":["man","judgment","God"],"peopleInVerse":[]},"4":{"text":"Or despisest thou the riches of his goodness and forbearance and longsuffering; not knowing that the goodness of God leadeth thee to repentance?","ref":"Romans 2:4","synthesized":"Or do you disregard the riches of His kindness, tolerance, and patience, not realizing that God’s kindness leads you to repentance?","sources":{"KJV":{"text":"Or despisest thou the riches of his goodness and forbearance and longsuffering; not knowing that the goodness of God leadeth thee to repentance?"},"BSB":{"text":"Or do you disregard the riches of His kindness, tolerance, and patience, not realizing that God’s kindness leads you to repentance?"}},"definableWords":["or","kindness","patience","God","repentance"],"peopleInVerse":[]},"5":{"text":"But after thy hardness and impenitent heart treasurest up unto thyself wrath against the day of wrath and revelation of the righteous judgment of God;","ref":"Romans 2:5","synthesized":"But because of your hard and unrepentant heart, you are storing up wrath against yourself for the day of wrath, when God’s righteous judgment will be revealed.","sources":{"KJV":{"text":"But after thy hardness and impenitent heart treasurest up unto thyself wrath against the day of wrath and revelation of the righteous judgment of God;"},"BSB":{"text":"But because of your hard and unrepentant heart, you are storing up wrath against yourself for the day of wrath, when God’s righteous judgment will be revealed."}},"definableWords":["heart","wrath","day","God","righteous","judgment"],"peopleInVerse":[]},"6":{"text":"Who will render to every man according to his deeds:","ref":"Romans 2:6","synthesized":"God “will repay each one according to his deeds.”","sources":{"KJV":{"text":"Who will render to every man according to his deeds:"},"BSB":{"text":"God “will repay each one according to his deeds.”"}},"definableWords":["God","one"],"peopleInVerse":[]},"7":{"text":"To them who by patient continuance in well doing seek for glory and honour and immortality, eternal life:","ref":"Romans 2:7","synthesized":"To those who by perseverance in doing good seek glory, honor, and immortality, He will give eternal life.","sources":{"KJV":{"text":"To them who by patient continuance in well doing seek for glory and honour and immortality, eternal life:"},"BSB":{"text":"To those who by perseverance in doing good seek glory, honor, and immortality, He will give eternal life."}},"definableWords":["good","seek","glory","eternal","life"],"peopleInVerse":[]},"8":{"text":"But unto them that are contentious, and do not obey the truth, but obey unrighteousness, indignation and wrath,","ref":"Romans 2:8","synthesized":"But for those who are self-seeking and who reject the truth and follow wickedness, there will be wrath and anger.","sources":{"KJV":{"text":"But unto them that are contentious, and do not obey the truth, but obey unrighteousness, indignation and wrath,"},"BSB":{"text":"But for those who are self-seeking and who reject the truth and follow wickedness, there will be wrath and anger."}},"definableWords":["truth","wrath","anger"],"peopleInVerse":[]},"9":{"text":"Tribulation and anguish, upon every soul of man that doeth evil, of the Jew first, and also of the Gentile;","ref":"Romans 2:9","synthesized":"There will be trouble and distress for every human being who does evil, first for the Jew, then for the Greek;","sources":{"KJV":{"text":"Tribulation and anguish, upon every soul of man that doeth evil, of the Jew first, and also of the Gentile;"},"BSB":{"text":"There will be trouble and distress for every human being who does evil, first for the Jew, then for the Greek;"}},"definableWords":["evil","Jew","Greek"],"peopleInVerse":[]},"10":{"text":"But glory, honour, and peace, to every man that worketh good, to the Jew first, and also to the Gentile:","ref":"Romans 2:10","synthesized":"but glory, honor, and peace for everyone who does good, first for the Jew, then for the Greek.","sources":{"KJV":{"text":"But glory, honour, and peace, to every man that worketh good, to the Jew first, and also to the Gentile:"},"BSB":{"text":"but glory, honor, and peace for everyone who does good, first for the Jew, then for the Greek."}},"definableWords":["glory","peace","good","Jew","Greek"],"peopleInVerse":[]},"11":{"text":"For there is no respect of persons with God.","ref":"Romans 2:11","synthesized":"For God does not show favoritism.","sources":{"KJV":{"text":"For there is no respect of persons with God."},"BSB":{"text":"For God does not show favoritism."}},"definableWords":["God"],"peopleInVerse":[]},"12":{"text":"For as many as have sinned without law shall also perish without law: and as many as have sinned in the law shall be judged by the law;","ref":"Romans 2:12","synthesized":"All who sin apart from the law will also perish apart from the law, and all who sin under the law will be judged by the law.","sources":{"KJV":{"text":"For as many as have sinned without law shall also perish without law: and as many as have sinned in the law shall be judged by the law;"},"BSB":{"text":"All who sin apart from the law will also perish apart from the law, and all who sin under the law will be judged by the law."}},"definableWords":["sin","law"],"peopleInVerse":[]},"13":{"text":"(For not the hearers of the law are just before God, but the doers of the law shall be justified.","ref":"Romans 2:13","synthesized":"For it is not the hearers of the law who are righteous before God, but it is the doers of the law who will be declared righteous.","sources":{"KJV":{"text":"(For not the hearers of the law are just before God, but the doers of the law shall be justified."},"BSB":{"text":"For it is not the hearers of the law who are righteous before God, but it is the doers of the law who will be declared righteous."}},"definableWords":["law","righteous","God"],"peopleInVerse":[]},"14":{"text":"For when the Gentiles, which have not the law, do by nature the things contained in the law, these, having not the law, are a law unto themselves:","ref":"Romans 2:14","synthesized":"Indeed, when Gentiles, who do not have the law, do by nature what the law requires, they are a law to themselves, even though they do not have the law.","sources":{"KJV":{"text":"For when the Gentiles, which have not the law, do by nature the things contained in the law, these, having not the law, are a law unto themselves:"},"BSB":{"text":"Indeed, when Gentiles, who do not have the law, do by nature what the law requires, they are a law to themselves, even though they do not have the law."}},"definableWords":["law"],"peopleInVerse":[]},"15":{"text":"Which shew the work of the law written in their hearts, their conscience also bearing witness, and their thoughts the mean while accusing or else excusing one another;)","ref":"Romans 2:15","synthesized":"So they show that the work of the law is written on their hearts, their consciences also bearing witness, and their thoughts either accusing or defending them","sources":{"KJV":{"text":"Which shew the work of the law written in their hearts, their conscience also bearing witness, and their thoughts the mean while accusing or else excusing one another;)"},"BSB":{"text":"So they show that the work of the law is written on their hearts, their consciences also bearing witness, and their thoughts either accusing or defending them"}},"definableWords":["work","law","or"],"peopleInVerse":[]},"16":{"text":"In the day when God shall judge the secrets of men by Jesus Christ according to my gospel.","ref":"Romans 2:16","synthesized":"on the day when God will judge men’s secrets through Christ Jesus, as proclaimed by my gospel.","sources":{"KJV":{"text":"In the day when God shall judge the secrets of men by Jesus Christ according to my gospel."},"BSB":{"text":"on the day when God will judge men’s secrets through Christ Jesus, as proclaimed by my gospel."}},"definableWords":["day","God","men","Christ","gospel"],"peopleInVerse":["Jesus"]},"17":{"text":"Behold, thou art called a Jew, and restest in the law, and makest thy boast of God,","ref":"Romans 2:17","synthesized":"Now you, if you call yourself a Jew; if you rely on the law and boast in God;","sources":{"KJV":{"text":"Behold, thou art called a Jew, and restest in the law, and makest thy boast of God,"},"BSB":{"text":"Now you, if you call yourself a Jew; if you rely on the law and boast in God;"}},"definableWords":["Jew","law","God"],"peopleInVerse":[]},"18":{"text":"And knowest his will, and approvest the things that are more excellent, being instructed out of the law;","ref":"Romans 2:18","synthesized":"if you know His will and approve of what is superior because you are instructed by the law;","sources":{"KJV":{"text":"And knowest his will, and approvest the things that are more excellent, being instructed out of the law;"},"BSB":{"text":"if you know His will and approve of what is superior because you are instructed by the law;"}},"definableWords":["law"],"peopleInVerse":[]},"19":{"text":"And art confident that thou thyself art a guide of the blind, a light of them which are in darkness,","ref":"Romans 2:19","synthesized":"if you are convinced that you are a guide for the blind, a light for those in darkness,","sources":{"KJV":{"text":"And art confident that thou thyself art a guide of the blind, a light of them which are in darkness,"},"BSB":{"text":"if you are convinced that you are a guide for the blind, a light for those in darkness,"}},"definableWords":["light","darkness"],"peopleInVerse":[]},"20":{"text":"An instructor of the foolish, a teacher of babes, which hast the form of knowledge and of the truth in the law.","ref":"Romans 2:20","synthesized":"an instructor of the foolish, a teacher of infants, because you have in the law the embodiment of knowledge and truth—","sources":{"KJV":{"text":"An instructor of the foolish, a teacher of babes, which hast the form of knowledge and of the truth in the law."},"BSB":{"text":"an instructor of the foolish, a teacher of infants, because you have in the law the embodiment of knowledge and truth—"}},"definableWords":["law","knowledge","truth"],"peopleInVerse":[]},"21":{"text":"Thou therefore which teachest another, teachest thou not thyself? thou that preachest a man should not steal, dost thou steal?","ref":"Romans 2:21","synthesized":"you, then, who teach others, do you not teach yourself? You who preach against stealing, do you steal?","sources":{"KJV":{"text":"Thou therefore which teachest another, teachest thou not thyself? thou that preachest a man should not steal, dost thou steal?"},"BSB":{"text":"you, then, who teach others, do you not teach yourself? You who preach against stealing, do you steal?"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"Thou that sayest a man should not commit adultery, dost thou commit adultery? thou that abhorrest idols, dost thou commit sacrilege?","ref":"Romans 2:22","synthesized":"You who forbid adultery, do you commit adultery? You who abhor idols, do you rob temples?","sources":{"KJV":{"text":"Thou that sayest a man should not commit adultery, dost thou commit adultery? thou that abhorrest idols, dost thou commit sacrilege?"},"BSB":{"text":"You who forbid adultery, do you commit adultery? You who abhor idols, do you rob temples?"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"Thou that makest thy boast of the law, through breaking the law dishonourest thou God?","ref":"Romans 2:23","synthesized":"You who boast in the law, do you dishonor God by breaking the law?","sources":{"KJV":{"text":"Thou that makest thy boast of the law, through breaking the law dishonourest thou God?"},"BSB":{"text":"You who boast in the law, do you dishonor God by breaking the law?"}},"definableWords":["law","God"],"peopleInVerse":[]},"24":{"text":"For the name of God is blasphemed among the Gentiles through you, as it is written.","ref":"Romans 2:24","synthesized":"As it is written: “God’s name is blasphemed among the Gentiles because of you.”","sources":{"KJV":{"text":"For the name of God is blasphemed among the Gentiles through you, as it is written."},"BSB":{"text":"As it is written: “God’s name is blasphemed among the Gentiles because of you.”"}},"definableWords":["God","name"],"peopleInVerse":[]},"25":{"text":"For circumcision verily profiteth, if thou keep the law: but if thou be a breaker of the law, thy circumcision is made uncircumcision.","ref":"Romans 2:25","synthesized":"Circumcision has value if you observe the law, but if you break the law, your circumcision has become uncircumcision.","sources":{"KJV":{"text":"For circumcision verily profiteth, if thou keep the law: but if thou be a breaker of the law, thy circumcision is made uncircumcision."},"BSB":{"text":"Circumcision has value if you observe the law, but if you break the law, your circumcision has become uncircumcision."}},"definableWords":["circumcision","law"],"peopleInVerse":[]},"26":{"text":"Therefore if the uncircumcision keep the righteousness of the law, shall not his uncircumcision be counted for circumcision?","ref":"Romans 2:26","synthesized":"If a man who is not circumcised keeps the requirements of the law, will not his uncircumcision be regarded as circumcision?","sources":{"KJV":{"text":"Therefore if the uncircumcision keep the righteousness of the law, shall not his uncircumcision be counted for circumcision?"},"BSB":{"text":"If a man who is not circumcised keeps the requirements of the law, will not his uncircumcision be regarded as circumcision?"}},"definableWords":["man","circumcised","law","circumcision"],"peopleInVerse":[]},"27":{"text":"And shall not uncircumcision which is by nature, if it fulfil the law, judge thee, who by the letter and circumcision dost transgress the law?","ref":"Romans 2:27","synthesized":"The one who is physically uncircumcised yet keeps the law will condemn you who, even though you have the written code and circumcision, are a lawbreaker.","sources":{"KJV":{"text":"And shall not uncircumcision which is by nature, if it fulfil the law, judge thee, who by the letter and circumcision dost transgress the law?"},"BSB":{"text":"The one who is physically uncircumcised yet keeps the law will condemn you who, even though you have the written code and circumcision, are a lawbreaker."}},"definableWords":["one","law","circumcision"],"peopleInVerse":[]},"28":{"text":"For he is not a Jew, which is one outwardly; neither is that circumcision, which is outward in the flesh:","ref":"Romans 2:28","synthesized":"A man is not a Jew because he is one outwardly, nor is circumcision only outward and physical.","sources":{"KJV":{"text":"For he is not a Jew, which is one outwardly; neither is that circumcision, which is outward in the flesh:"},"BSB":{"text":"A man is not a Jew because he is one outwardly, nor is circumcision only outward and physical."}},"definableWords":["man","Jew","one","circumcision"],"peopleInVerse":[]},"29":{"text":"But he is a Jew, which is one inwardly; and circumcision is that of the heart, in the spirit, and not in the letter; whose praise is not of men, but of God.","ref":"Romans 2:29","synthesized":"No, a man is a Jew because he is one inwardly, and circumcision is a matter of the heart, by the Spirit, not by the written code. Such a man’s praise does not come from men, but from God.","sources":{"KJV":{"text":"But he is a Jew, which is one inwardly; and circumcision is that of the heart, in the spirit, and not in the letter; whose praise is not of men, but of God."},"BSB":{"text":"No, a man is a Jew because he is one inwardly, and circumcision is a matter of the heart, by the Spirit, not by the written code. Such a man’s praise does not come from men, but from God."}},"definableWords":["man","Jew","one","circumcision","heart","Spirit","praise","men","God"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"ALL HAVE SINNED","verses":{"1":{"text":"What advantage then hath the Jew? or what profit is there of circumcision?","ref":"Romans 3:1","synthesized":"What, then, is the advantage of being a Jew? Or what is the value of circumcision?","sources":{"KJV":{"text":"What advantage then hath the Jew? or what profit is there of circumcision?"},"BSB":{"text":"What, then, is the advantage of being a Jew? Or what is the value of circumcision?"}},"definableWords":["Jew","or","circumcision"],"peopleInVerse":[]},"2":{"text":"Much every way: chiefly, because that unto them were committed the oracles of God.","ref":"Romans 3:2","synthesized":"Much in every way. First of all, they have been entrusted with the very words of God.","sources":{"KJV":{"text":"Much every way: chiefly, because that unto them were committed the oracles of God."},"BSB":{"text":"Much in every way. First of all, they have been entrusted with the very words of God."}},"definableWords":["way","God"],"peopleInVerse":[]},"3":{"text":"For what if some did not believe? shall their unbelief make the faith of God without effect?","ref":"Romans 3:3","synthesized":"What if some did not have faith? Will their lack of faith nullify God’s faithfulness?","sources":{"KJV":{"text":"For what if some did not believe? shall their unbelief make the faith of God without effect?"},"BSB":{"text":"What if some did not have faith? Will their lack of faith nullify God’s faithfulness?"}},"definableWords":["faith","God"],"peopleInVerse":[]},"4":{"text":"God forbid: yea, let God be true, but every man a liar; as it is written, That thou mightest be justified in thy sayings, and mightest overcome when thou art judged.","ref":"Romans 3:4","synthesized":"Certainly not! Let God be true and every man a liar. As it is written:  “So that You may be proved right when You speak and victorious when You judge.”","sources":{"KJV":{"text":"God forbid: yea, let God be true, but every man a liar; as it is written, That thou mightest be justified in thy sayings, and mightest overcome when thou art judged."},"BSB":{"text":"Certainly not! Let God be true and every man a liar. As it is written:  “So that You may be proved right when You speak and victorious when You judge.”"}},"definableWords":["God","man"],"peopleInVerse":[]},"5":{"text":"But if our unrighteousness commend the righteousness of God, what shall we say? Is God unrighteous who taketh vengeance? (I speak as a man)","ref":"Romans 3:5","synthesized":"But if our unrighteousness highlights the righteousness of God, what shall we say? That God is unjust to inflict His wrath on us? I am speaking in human terms.","sources":{"KJV":{"text":"But if our unrighteousness commend the righteousness of God, what shall we say? Is God unrighteous who taketh vengeance? (I speak as a man)"},"BSB":{"text":"But if our unrighteousness highlights the righteousness of God, what shall we say? That God is unjust to inflict His wrath on us? I am speaking in human terms."}},"definableWords":["righteousness","God","wrath"],"peopleInVerse":[]},"6":{"text":"God forbid: for then how shall God judge the world?","ref":"Romans 3:6","synthesized":"Certainly not! In that case, how could God judge the world?","sources":{"KJV":{"text":"God forbid: for then how shall God judge the world?"},"BSB":{"text":"Certainly not! In that case, how could God judge the world?"}},"definableWords":["God"],"peopleInVerse":[]},"7":{"text":"For if the truth of God hath more abounded through my lie unto his glory; why yet am I also judged as a sinner?","ref":"Romans 3:7","synthesized":"However, if my falsehood accentuates God’s truthfulness, to the increase of His glory, why am I still condemned as a sinner?","sources":{"KJV":{"text":"For if the truth of God hath more abounded through my lie unto his glory; why yet am I also judged as a sinner?"},"BSB":{"text":"However, if my falsehood accentuates God’s truthfulness, to the increase of His glory, why am I still condemned as a sinner?"}},"definableWords":["God","glory"],"peopleInVerse":[]},"8":{"text":"And not rather, (as we be slanderously reported, and as some affirm that we say,) Let us do evil, that good may come? whose damnation is just.","ref":"Romans 3:8","synthesized":"Why not say, as some slanderously claim that we say, “Let us do evil that good may result”? Their condemnation is deserved!","sources":{"KJV":{"text":"And not rather, (as we be slanderously reported, and as some affirm that we say,) Let us do evil, that good may come? whose damnation is just."},"BSB":{"text":"Why not say, as some slanderously claim that we say, “Let us do evil that good may result”? Their condemnation is deserved!"}},"definableWords":["evil","good"],"peopleInVerse":[]},"9":{"text":"What then? are we better than they? No, in no wise: for we have before proved both Jews and Gentiles, that they are all under sin;","ref":"Romans 3:9","synthesized":"What then? Are we any better? Not at all. For we have already made the charge that Jews and Greeks alike are all under sin.","sources":{"KJV":{"text":"What then? are we better than they? No, in no wise: for we have before proved both Jews and Gentiles, that they are all under sin;"},"BSB":{"text":"What then? Are we any better? Not at all. For we have already made the charge that Jews and Greeks alike are all under sin."}},"definableWords":["made","charge","sin"],"peopleInVerse":[]},"10":{"text":"As it is written, There is none righteous, no, not one:","ref":"Romans 3:10","synthesized":"As it is written:  “There is no one righteous, not even one.","sources":{"KJV":{"text":"As it is written, There is none righteous, no, not one:"},"BSB":{"text":"As it is written:  “There is no one righteous, not even one."}},"definableWords":["one","righteous"],"peopleInVerse":[]},"11":{"text":"There is none that understandeth, there is none that seeketh after God.","ref":"Romans 3:11","synthesized":"There is no one who understands, no one who seeks God.","sources":{"KJV":{"text":"There is none that understandeth, there is none that seeketh after God."},"BSB":{"text":"There is no one who understands, no one who seeks God."}},"definableWords":["one","God"],"peopleInVerse":[]},"12":{"text":"They are all gone out of the way, they are together become unprofitable; there is none that doeth good, no, not one.","ref":"Romans 3:12","synthesized":"All have turned away, they have together become worthless; there is no one who does good, not even one.”","sources":{"KJV":{"text":"They are all gone out of the way, they are together become unprofitable; there is none that doeth good, no, not one."},"BSB":{"text":"All have turned away, they have together become worthless; there is no one who does good, not even one.”"}},"definableWords":["one","good"],"peopleInVerse":[]},"13":{"text":"Their throat is an open sepulchre; with their tongues they have used deceit; the poison of asps is under their lips:","ref":"Romans 3:13","synthesized":"“Their throats are open graves; their tongues practice deceit.” “The venom of vipers is on their lips.”","sources":{"KJV":{"text":"Their throat is an open sepulchre; with their tongues they have used deceit; the poison of asps is under their lips:"},"BSB":{"text":"“Their throats are open graves; their tongues practice deceit.” “The venom of vipers is on their lips.”"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Whose mouth is full of cursing and bitterness:","ref":"Romans 3:14","synthesized":"“Their mouths are full of cursing and bitterness.”","sources":{"KJV":{"text":"Whose mouth is full of cursing and bitterness:"},"BSB":{"text":"“Their mouths are full of cursing and bitterness.”"}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Their feet are swift to shed blood:","ref":"Romans 3:15","synthesized":"“Their feet are swift to shed blood;","sources":{"KJV":{"text":"Their feet are swift to shed blood:"},"BSB":{"text":"“Their feet are swift to shed blood;"}},"definableWords":["blood"],"peopleInVerse":[]},"16":{"text":"Destruction and misery are in their ways:","ref":"Romans 3:16","synthesized":"ruin and misery lie in their wake,","sources":{"KJV":{"text":"Destruction and misery are in their ways:"},"BSB":{"text":"ruin and misery lie in their wake,"}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"And the way of peace have they not known:","ref":"Romans 3:17","synthesized":"and the way of peace they have not known.”","sources":{"KJV":{"text":"And the way of peace have they not known:"},"BSB":{"text":"and the way of peace they have not known.”"}},"definableWords":["way","peace"],"peopleInVerse":[]},"18":{"text":"There is no fear of God before their eyes.","ref":"Romans 3:18","synthesized":"“There is no fear of God before their eyes.”","sources":{"KJV":{"text":"There is no fear of God before their eyes."},"BSB":{"text":"“There is no fear of God before their eyes.”"}},"definableWords":["fear","God"],"peopleInVerse":[]},"19":{"text":"Now we know that what things soever the law saith, it saith to them who are under the law: that every mouth may be stopped, and all the world may become guilty before God.","ref":"Romans 3:19","synthesized":"Now we know that whatever the law says, it says to those who are under the law, so that every mouth may be silenced and the whole world held accountable to God.","sources":{"KJV":{"text":"Now we know that what things soever the law saith, it saith to them who are under the law: that every mouth may be stopped, and all the world may become guilty before God."},"BSB":{"text":"Now we know that whatever the law says, it says to those who are under the law, so that every mouth may be silenced and the whole world held accountable to God."}},"definableWords":["law","God"],"peopleInVerse":[]},"20":{"text":"Therefore by the deeds of the law there shall no flesh be justified in his sight: for by the law is the knowledge of sin.","ref":"Romans 3:20","synthesized":"Therefore no one will be justified in His sight by works of the law. For the law merely brings awareness of sin.","sources":{"KJV":{"text":"Therefore by the deeds of the law there shall no flesh be justified in his sight: for by the law is the knowledge of sin."},"BSB":{"text":"Therefore no one will be justified in His sight by works of the law. For the law merely brings awareness of sin."}},"definableWords":["one","works","law","sin"],"peopleInVerse":[]},"21":{"text":"But now the righteousness of God without the law is manifested, being witnessed by the law and the prophets;","ref":"Romans 3:21","synthesized":"But now, apart from the law, the righteousness of God has been revealed, as attested by the Law and the Prophets.","sources":{"KJV":{"text":"But now the righteousness of God without the law is manifested, being witnessed by the law and the prophets;"},"BSB":{"text":"But now, apart from the law, the righteousness of God has been revealed, as attested by the Law and the Prophets."}},"definableWords":["law","righteousness","God"],"peopleInVerse":[]},"22":{"text":"Even the righteousness of God which is by faith of Jesus Christ unto all and upon all them that believe: for there is no difference:","ref":"Romans 3:22","synthesized":"And this righteousness from God comes through faith in Jesus Christ to all who believe. There is no distinction,","sources":{"KJV":{"text":"Even the righteousness of God which is by faith of Jesus Christ unto all and upon all them that believe: for there is no difference:"},"BSB":{"text":"And this righteousness from God comes through faith in Jesus Christ to all who believe. There is no distinction,"}},"definableWords":["righteousness","God","faith","Christ"],"peopleInVerse":["Jesus"]},"23":{"text":"For all have sinned, and come short of the glory of God;","ref":"Romans 3:23","synthesized":"for all have sinned and fall short of the glory of God,","sources":{"KJV":{"text":"For all have sinned, and come short of the glory of God;"},"BSB":{"text":"for all have sinned and fall short of the glory of God,"}},"definableWords":["glory","God"],"peopleInVerse":[]},"24":{"text":"Being justified freely by his grace through the redemption that is in Christ Jesus:","ref":"Romans 3:24","synthesized":"and are justified freely by His grace through the redemption that is in Christ Jesus.","sources":{"KJV":{"text":"Being justified freely by his grace through the redemption that is in Christ Jesus:"},"BSB":{"text":"and are justified freely by His grace through the redemption that is in Christ Jesus."}},"definableWords":["grace","redemption","Christ"],"peopleInVerse":["Jesus"]},"25":{"text":"Whom God hath set forth to be a propitiation through faith in his blood, to declare his righteousness for the remission of sins that are past, through the forbearance of God;","ref":"Romans 3:25","synthesized":"God presented Him as the atoning sacrifice through faith in His blood, in order to demonstrate His righteousness, because in His forbearance He had passed over the sins committed beforehand.","sources":{"KJV":{"text":"Whom God hath set forth to be a propitiation through faith in his blood, to declare his righteousness for the remission of sins that are past, through the forbearance of God;"},"BSB":{"text":"God presented Him as the atoning sacrifice through faith in His blood, in order to demonstrate His righteousness, because in His forbearance He had passed over the sins committed beforehand."}},"definableWords":["God","sacrifice","faith","blood","righteousness"],"peopleInVerse":[]},"26":{"text":"To declare, I say, at this time his righteousness: that he might be just, and the justifier of him which believeth in Jesus.","ref":"Romans 3:26","synthesized":"He did this to demonstrate His righteousness at the present time, so as to be just and to justify the one who has faith in Jesus.","sources":{"KJV":{"text":"To declare, I say, at this time his righteousness: that he might be just, and the justifier of him which believeth in Jesus."},"BSB":{"text":"He did this to demonstrate His righteousness at the present time, so as to be just and to justify the one who has faith in Jesus."}},"definableWords":["righteousness","one","faith"],"peopleInVerse":["Jesus"]},"27":{"text":"Where is boasting then? It is excluded. By what law? of works? Nay: but by the law of faith.","ref":"Romans 3:27","synthesized":"Where, then, is boasting? It is excluded. On what principle? On that of works? No, but on that of faith.","sources":{"KJV":{"text":"Where is boasting then? It is excluded. By what law? of works? Nay: but by the law of faith."},"BSB":{"text":"Where, then, is boasting? It is excluded. On what principle? On that of works? No, but on that of faith."}},"definableWords":["works","faith"],"peopleInVerse":[]},"28":{"text":"Therefore we conclude that a man is justified by faith without the deeds of the law.","ref":"Romans 3:28","synthesized":"For we maintain that a man is justified by faith apart from works of the law.","sources":{"KJV":{"text":"Therefore we conclude that a man is justified by faith without the deeds of the law."},"BSB":{"text":"For we maintain that a man is justified by faith apart from works of the law."}},"definableWords":["man","faith","works","law"],"peopleInVerse":[]},"29":{"text":"Is he the God of the Jews only? is he not also of the Gentiles? Yes, of the Gentiles also:","ref":"Romans 3:29","synthesized":"Is God the God of Jews only? Is He not the God of Gentiles too? Yes, of Gentiles too,","sources":{"KJV":{"text":"Is he the God of the Jews only? is he not also of the Gentiles? Yes, of the Gentiles also:"},"BSB":{"text":"Is God the God of Jews only? Is He not the God of Gentiles too? Yes, of Gentiles too,"}},"definableWords":["God"],"peopleInVerse":[]},"30":{"text":"Seeing it is one God, which shall justify the circumcision by faith, and uncircumcision through faith.","ref":"Romans 3:30","synthesized":"since there is only one God, who will justify the circumcised by faith and the uncircumcised through that same faith.","sources":{"KJV":{"text":"Seeing it is one God, which shall justify the circumcision by faith, and uncircumcision through faith."},"BSB":{"text":"since there is only one God, who will justify the circumcised by faith and the uncircumcised through that same faith."}},"definableWords":["one","God","circumcised","faith"],"peopleInVerse":[]},"31":{"text":"Do we then make void the law through faith? God forbid: yea, we establish the law.","ref":"Romans 3:31","synthesized":"Do we, then, nullify the law by this faith? Certainly not! Instead, we uphold the law.","sources":{"KJV":{"text":"Do we then make void the law through faith? God forbid: yea, we establish the law."},"BSB":{"text":"Do we, then, nullify the law by this faith? Certainly not! Instead, we uphold the law."}},"definableWords":["law","faith"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"ABRAHAM'S FAITH","verses":{"1":{"text":"What shall we say then that Abraham our father, as pertaining to the flesh, hath found?","ref":"Romans 4:1","synthesized":"What then shall we say that Abraham, our forefather, has discovered?","sources":{"KJV":{"text":"What shall we say then that Abraham our father, as pertaining to the flesh, hath found?"},"BSB":{"text":"What then shall we say that Abraham, our forefather, has discovered?"}},"definableWords":["Abraham"],"peopleInVerse":["Abraham"]},"2":{"text":"For if Abraham were justified by works, he hath whereof to glory; but not before God.","ref":"Romans 4:2","synthesized":"If Abraham was indeed justified by works, he had something to boast about, but not before God.","sources":{"KJV":{"text":"For if Abraham were justified by works, he hath whereof to glory; but not before God."},"BSB":{"text":"If Abraham was indeed justified by works, he had something to boast about, but not before God."}},"definableWords":["Abraham","works","God"],"peopleInVerse":["Abraham"]},"3":{"text":"For what saith the scripture? Abraham believed God, and it was counted unto him for righteousness.","ref":"Romans 4:3","synthesized":"For what does the Scripture say? “Abraham believed God, and it was credited to him as righteousness.”","sources":{"KJV":{"text":"For what saith the scripture? Abraham believed God, and it was counted unto him for righteousness."},"BSB":{"text":"For what does the Scripture say? “Abraham believed God, and it was credited to him as righteousness.”"}},"definableWords":["Abraham","believed","God","righteousness"],"peopleInVerse":["Abraham"]},"4":{"text":"Now to him that worketh is the reward not reckoned of grace, but of debt.","ref":"Romans 4:4","synthesized":"Now the wages of the worker are not credited as a gift, but as an obligation.","sources":{"KJV":{"text":"Now to him that worketh is the reward not reckoned of grace, but of debt."},"BSB":{"text":"Now the wages of the worker are not credited as a gift, but as an obligation."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"But to him that worketh not, but believeth on him that justifieth the ungodly, his faith is counted for righteousness.","ref":"Romans 4:5","synthesized":"However, to the one who does not work, but believes in Him who justifies the wicked, his faith is credited as righteousness.","sources":{"KJV":{"text":"But to him that worketh not, but believeth on him that justifieth the ungodly, his faith is counted for righteousness."},"BSB":{"text":"However, to the one who does not work, but believes in Him who justifies the wicked, his faith is credited as righteousness."}},"definableWords":["one","work","faith","righteousness"],"peopleInVerse":[]},"6":{"text":"Even as David also describeth the blessedness of the man, unto whom God imputeth righteousness without works,","ref":"Romans 4:6","synthesized":"And David speaks likewise of the blessedness of the man to whom God credits righteousness apart from works:","sources":{"KJV":{"text":"Even as David also describeth the blessedness of the man, unto whom God imputeth righteousness without works,"},"BSB":{"text":"And David speaks likewise of the blessedness of the man to whom God credits righteousness apart from works:"}},"definableWords":["man","God","righteousness","works"],"peopleInVerse":["David"]},"7":{"text":"Saying, Blessed are they whose iniquities are forgiven, and whose sins are covered.","ref":"Romans 4:7","synthesized":"“Blessed are they whose lawless acts are forgiven, whose sins are covered.","sources":{"KJV":{"text":"Saying, Blessed are they whose iniquities are forgiven, and whose sins are covered."},"BSB":{"text":"“Blessed are they whose lawless acts are forgiven, whose sins are covered."}},"definableWords":["blessed"],"peopleInVerse":[]},"8":{"text":"Blessed is the man to whom the Lord will not impute sin.","ref":"Romans 4:8","synthesized":"Blessed is the man whose sin the Lord will never count against him.”","sources":{"KJV":{"text":"Blessed is the man to whom the Lord will not impute sin."},"BSB":{"text":"Blessed is the man whose sin the Lord will never count against him.”"}},"definableWords":["blessed","man","sin","Lord"],"peopleInVerse":[]},"9":{"text":"Cometh this blessedness then upon the circumcision only, or upon the uncircumcision also? for we say that faith was reckoned to Abraham for righteousness.","ref":"Romans 4:9","synthesized":"Is this blessing only on the circumcised, or also on the uncircumcised? We have been saying that Abraham’s faith was credited to him as righteousness.","sources":{"KJV":{"text":"Cometh this blessedness then upon the circumcision only, or upon the uncircumcision also? for we say that faith was reckoned to Abraham for righteousness."},"BSB":{"text":"Is this blessing only on the circumcised, or also on the uncircumcised? We have been saying that Abraham’s faith was credited to him as righteousness."}},"definableWords":["blessing","circumcised","or","Abraham","faith","righteousness"],"peopleInVerse":["Abraham"]},"10":{"text":"How was it then reckoned? when he was in circumcision, or in uncircumcision? Not in circumcision, but in uncircumcision.","ref":"Romans 4:10","synthesized":"In what context was it credited? Was it after his circumcision, or before? It was not after, but before.","sources":{"KJV":{"text":"How was it then reckoned? when he was in circumcision, or in uncircumcision? Not in circumcision, but in uncircumcision."},"BSB":{"text":"In what context was it credited? Was it after his circumcision, or before? It was not after, but before."}},"definableWords":["circumcision","or"],"peopleInVerse":[]},"11":{"text":"And he received the sign of circumcision, a seal of the righteousness of the faith which he had yet being uncircumcised: that he might be the father of all them that believe, though they be not circumcised; that righteousness might be imputed unto them also:","ref":"Romans 4:11","synthesized":"And he received the sign of circumcision as a seal of the righteousness that he had by faith while he was still uncircumcised. So then, he is the father of all who believe but are not circumcised, in order that righteousness might be credited to them.","sources":{"KJV":{"text":"And he received the sign of circumcision, a seal of the righteousness of the faith which he had yet being uncircumcised: that he might be the father of all them that believe, though they be not circumcised; that righteousness might be imputed unto them also:"},"BSB":{"text":"And he received the sign of circumcision as a seal of the righteousness that he had by faith while he was still uncircumcised. So then, he is the father of all who believe but are not circumcised, in order that righteousness might be credited to them."}},"definableWords":["circumcision","righteousness","faith","father","circumcised"],"peopleInVerse":[]},"12":{"text":"And the father of circumcision to them who are not of the circumcision only, but who also walk in the steps of that faith of our father Abraham, which he had being yet uncircumcised.","ref":"Romans 4:12","synthesized":"And he is also the father of the circumcised who not only are circumcised, but who also walk in the footsteps of the faith that our father Abraham had before he was circumcised.","sources":{"KJV":{"text":"And the father of circumcision to them who are not of the circumcision only, but who also walk in the steps of that faith of our father Abraham, which he had being yet uncircumcised."},"BSB":{"text":"And he is also the father of the circumcised who not only are circumcised, but who also walk in the footsteps of the faith that our father Abraham had before he was circumcised."}},"definableWords":["father","circumcised","walk","faith","Father","Abraham"],"peopleInVerse":["Abraham"]},"13":{"text":"For the promise, that he should be the heir of the world, was not to Abraham, or to his seed, through the law, but through the righteousness of faith.","ref":"Romans 4:13","synthesized":"For the promise to Abraham and his offspring that he would be heir of the world was not given through the law, but through the righteousness that comes by faith.","sources":{"KJV":{"text":"For the promise, that he should be the heir of the world, was not to Abraham, or to his seed, through the law, but through the righteousness of faith."},"BSB":{"text":"For the promise to Abraham and his offspring that he would be heir of the world was not given through the law, but through the righteousness that comes by faith."}},"definableWords":["promise","Abraham","law","righteousness","faith"],"peopleInVerse":["Abraham"]},"14":{"text":"For if they which are of the law be heirs, faith is made void, and the promise made of none effect:","ref":"Romans 4:14","synthesized":"For if those who live by the law are heirs, faith is useless and the promise is worthless,","sources":{"KJV":{"text":"For if they which are of the law be heirs, faith is made void, and the promise made of none effect:"},"BSB":{"text":"For if those who live by the law are heirs, faith is useless and the promise is worthless,"}},"definableWords":["live","law","faith","promise"],"peopleInVerse":[]},"15":{"text":"Because the law worketh wrath: for where no law is, there is no transgression.","ref":"Romans 4:15","synthesized":"because the law brings wrath. And where there is no law, there is no transgression.","sources":{"KJV":{"text":"Because the law worketh wrath: for where no law is, there is no transgression."},"BSB":{"text":"because the law brings wrath. And where there is no law, there is no transgression."}},"definableWords":["law","wrath","transgression"],"peopleInVerse":[]},"16":{"text":"Therefore it is of faith, that it might be by grace; to the end the promise might be sure to all the seed; not to that only which is of the law, but to that also which is of the faith of Abraham; who is the father of us all,","ref":"Romans 4:16","synthesized":"Therefore, the promise comes by faith, so that it may rest on grace and may be guaranteed to all Abraham’s offspring—not only to those who are of the law, but also to those who are of the faith of Abraham. He is the father of us all.","sources":{"KJV":{"text":"Therefore it is of faith, that it might be by grace; to the end the promise might be sure to all the seed; not to that only which is of the law, but to that also which is of the faith of Abraham; who is the father of us all,"},"BSB":{"text":"Therefore, the promise comes by faith, so that it may rest on grace and may be guaranteed to all Abraham’s offspring—not only to those who are of the law, but also to those who are of the faith of Abraham. He is the father of us all."}},"definableWords":["promise","faith","rest","grace","Abraham","law","father"],"peopleInVerse":["Abraham"]},"17":{"text":"(As it is written, I have made thee a father of many nations,) before him whom he believed, even God, who quickeneth the dead, and calleth those things which be not as though they were.","ref":"Romans 4:17","synthesized":"As it is written: “I have made you a father of many nations.” He is our father in the presence of God, in whom he believed, the God who gives life to the dead and calls into being what does not yet exist.","sources":{"KJV":{"text":"(As it is written, I have made thee a father of many nations,) before him whom he believed, even God, who quickeneth the dead, and calleth those things which be not as though they were."},"BSB":{"text":"As it is written: “I have made you a father of many nations.” He is our father in the presence of God, in whom he believed, the God who gives life to the dead and calls into being what does not yet exist."}},"definableWords":["made","father","nations","Father","God","believed","life"],"peopleInVerse":[]},"18":{"text":"Who against hope believed in hope, that he might become the father of many nations, according to that which was spoken, So shall thy seed be.","ref":"Romans 4:18","synthesized":"Against all hope, Abraham in hope believed and so became the father of many nations, just as he had been told, “So shall your offspring be.”","sources":{"KJV":{"text":"Who against hope believed in hope, that he might become the father of many nations, according to that which was spoken, So shall thy seed be."},"BSB":{"text":"Against all hope, Abraham in hope believed and so became the father of many nations, just as he had been told, “So shall your offspring be.”"}},"definableWords":["hope","Abraham","believed","father","nations"],"peopleInVerse":["Abraham"]},"19":{"text":"And being not weak in faith, he considered not his own body now dead, when he was about an hundred years old, neither yet the deadness of Sarah’s womb:","ref":"Romans 4:19","synthesized":"Without weakening in his faith, he acknowledged the decrepitness of his body (since he was about a hundred years old) and the lifelessness of Sarah’s womb.","sources":{"KJV":{"text":"And being not weak in faith, he considered not his own body now dead, when he was about an hundred years old, neither yet the deadness of Sarah’s womb:"},"BSB":{"text":"Without weakening in his faith, he acknowledged the decrepitness of his body (since he was about a hundred years old) and the lifelessness of Sarah’s womb."}},"definableWords":["faith","years","Sarah"],"peopleInVerse":["Sarah"]},"20":{"text":"He staggered not at the promise of God through unbelief; but was strong in faith, giving glory to God;","ref":"Romans 4:20","synthesized":"Yet he did not waver through disbelief in the promise of God, but was strengthened in his faith and gave glory to God,","sources":{"KJV":{"text":"He staggered not at the promise of God through unbelief; but was strong in faith, giving glory to God;"},"BSB":{"text":"Yet he did not waver through disbelief in the promise of God, but was strengthened in his faith and gave glory to God,"}},"definableWords":["promise","God","faith","glory"],"peopleInVerse":[]},"21":{"text":"And being fully persuaded that, what he had promised, he was able also to perform.","ref":"Romans 4:21","synthesized":"being fully persuaded that God was able to do what He had promised.","sources":{"KJV":{"text":"And being fully persuaded that, what he had promised, he was able also to perform."},"BSB":{"text":"being fully persuaded that God was able to do what He had promised."}},"definableWords":["God"],"peopleInVerse":[]},"22":{"text":"And therefore it was imputed to him for righteousness.","ref":"Romans 4:22","synthesized":"This is why “it was credited to him as righteousness.”","sources":{"KJV":{"text":"And therefore it was imputed to him for righteousness."},"BSB":{"text":"This is why “it was credited to him as righteousness.”"}},"definableWords":["righteousness"],"peopleInVerse":[]},"23":{"text":"Now it was not written for his sake alone, that it was imputed to him;","ref":"Romans 4:23","synthesized":"Now the words “it was credited to him” were written not only for Abraham,","sources":{"KJV":{"text":"Now it was not written for his sake alone, that it was imputed to him;"},"BSB":{"text":"Now the words “it was credited to him” were written not only for Abraham,"}},"definableWords":["Abraham"],"peopleInVerse":["Abraham"]},"24":{"text":"But for us also, to whom it shall be imputed, if we believe on him that raised up Jesus our Lord from the dead;","ref":"Romans 4:24","synthesized":"but also for us, to whom righteousness will be credited—for us who believe in Him who raised Jesus our Lord from the dead.","sources":{"KJV":{"text":"But for us also, to whom it shall be imputed, if we believe on him that raised up Jesus our Lord from the dead;"},"BSB":{"text":"but also for us, to whom righteousness will be credited—for us who believe in Him who raised Jesus our Lord from the dead."}},"definableWords":["righteousness","Lord"],"peopleInVerse":["Jesus"]},"25":{"text":"Who was delivered for our offences, and was raised again for our justification.","ref":"Romans 4:25","synthesized":"He was delivered over to death for our trespasses and was raised to life for our justification.","sources":{"KJV":{"text":"Who was delivered for our offences, and was raised again for our justification."},"BSB":{"text":"He was delivered over to death for our trespasses and was raised to life for our justification."}},"definableWords":["death","life","justification"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"JUSTIFIED BY FAITH","verses":{"1":{"text":"Therefore being justified by faith, we have peace with God through our Lord Jesus Christ:","ref":"Romans 5:1","synthesized":"Therefore, since we have been justified through faith, we have peace with God through our Lord Jesus Christ,","sources":{"KJV":{"text":"Therefore being justified by faith, we have peace with God through our Lord Jesus Christ:"},"BSB":{"text":"Therefore, since we have been justified through faith, we have peace with God through our Lord Jesus Christ,"}},"definableWords":["faith","peace","God","Lord","Christ"],"peopleInVerse":["Jesus"]},"2":{"text":"By whom also we have access by faith into this grace wherein we stand, and rejoice in hope of the glory of God.","ref":"Romans 5:2","synthesized":"through whom we have gained access by faith into this grace in which we stand. And we rejoice in the hope of the glory of God.","sources":{"KJV":{"text":"By whom also we have access by faith into this grace wherein we stand, and rejoice in hope of the glory of God."},"BSB":{"text":"through whom we have gained access by faith into this grace in which we stand. And we rejoice in the hope of the glory of God."}},"definableWords":["faith","grace","stand","hope","glory","God"],"peopleInVerse":[]},"3":{"text":"And not only so, but we glory in tribulations also: knowing that tribulation worketh patience;","ref":"Romans 5:3","synthesized":"Not only that, but we also rejoice in our sufferings, because we know that suffering produces perseverance;","sources":{"KJV":{"text":"And not only so, but we glory in tribulations also: knowing that tribulation worketh patience;"},"BSB":{"text":"Not only that, but we also rejoice in our sufferings, because we know that suffering produces perseverance;"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"And patience, experience; and experience, hope:","ref":"Romans 5:4","synthesized":"perseverance, character; and character, hope.","sources":{"KJV":{"text":"And patience, experience; and experience, hope:"},"BSB":{"text":"perseverance, character; and character, hope."}},"definableWords":["hope"],"peopleInVerse":[]},"5":{"text":"And hope maketh not ashamed; because the love of God is shed abroad in our hearts by the Holy Ghost which is given unto us.","ref":"Romans 5:5","synthesized":"And hope does not disappoint us, because God has poured out His love into our hearts through the Holy Spirit, whom He has given us.","sources":{"KJV":{"text":"And hope maketh not ashamed; because the love of God is shed abroad in our hearts by the Holy Ghost which is given unto us."},"BSB":{"text":"And hope does not disappoint us, because God has poured out His love into our hearts through the Holy Spirit, whom He has given us."}},"definableWords":["hope","God","love","holy","Spirit"],"peopleInVerse":[]},"6":{"text":"For when we were yet without strength, in due time Christ died for the ungodly.","ref":"Romans 5:6","synthesized":"For at just the right time, while we were still powerless, Christ died for the ungodly.","sources":{"KJV":{"text":"For when we were yet without strength, in due time Christ died for the ungodly."},"BSB":{"text":"For at just the right time, while we were still powerless, Christ died for the ungodly."}},"definableWords":["Christ"],"peopleInVerse":[]},"7":{"text":"For scarcely for a righteous man will one die: yet peradventure for a good man some would even dare to die.","ref":"Romans 5:7","synthesized":"Very rarely will anyone die for a righteous man, though for a good man someone might possibly dare to die.","sources":{"KJV":{"text":"For scarcely for a righteous man will one die: yet peradventure for a good man some would even dare to die."},"BSB":{"text":"Very rarely will anyone die for a righteous man, though for a good man someone might possibly dare to die."}},"definableWords":["die","righteous","man","good"],"peopleInVerse":[]},"8":{"text":"But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us.","ref":"Romans 5:8","synthesized":"But God proves His love for us in this: While we were still sinners, Christ died for us.","sources":{"KJV":{"text":"But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us."},"BSB":{"text":"But God proves His love for us in this: While we were still sinners, Christ died for us."}},"definableWords":["God","love","Christ"],"peopleInVerse":[]},"9":{"text":"Much more then, being now justified by his blood, we shall be saved from wrath through him.","ref":"Romans 5:9","synthesized":"Therefore, since we have now been justified by His blood, how much more shall we be saved from wrath through Him!","sources":{"KJV":{"text":"Much more then, being now justified by his blood, we shall be saved from wrath through him."},"BSB":{"text":"Therefore, since we have now been justified by His blood, how much more shall we be saved from wrath through Him!"}},"definableWords":["blood","wrath"],"peopleInVerse":[]},"10":{"text":"For if, when we were enemies, we were reconciled to God by the death of his Son, much more, being reconciled, we shall be saved by his life.","ref":"Romans 5:10","synthesized":"For if, when we were enemies of God, we were reconciled to Him through the death of His Son, how much more, having been reconciled, shall we be saved through His life!","sources":{"KJV":{"text":"For if, when we were enemies, we were reconciled to God by the death of his Son, much more, being reconciled, we shall be saved by his life."},"BSB":{"text":"For if, when we were enemies of God, we were reconciled to Him through the death of His Son, how much more, having been reconciled, shall we be saved through His life!"}},"definableWords":["God","death","Son","life"],"peopleInVerse":[]},"11":{"text":"And not only so, but we also joy in God through our Lord Jesus Christ, by whom we have now received the atonement.","ref":"Romans 5:11","synthesized":"Not only that, but we also rejoice in God through our Lord Jesus Christ, through whom we have now received reconciliation.","sources":{"KJV":{"text":"And not only so, but we also joy in God through our Lord Jesus Christ, by whom we have now received the atonement."},"BSB":{"text":"Not only that, but we also rejoice in God through our Lord Jesus Christ, through whom we have now received reconciliation."}},"definableWords":["God","Lord","Christ"],"peopleInVerse":["Jesus"]},"12":{"text":"Wherefore, as by one man sin entered into the world, and death by sin; and so death passed upon all men, for that all have sinned:","ref":"Romans 5:12","synthesized":"Therefore, just as sin entered the world through one man, and death through sin, so also death was passed on to all men, because all sinned.","sources":{"KJV":{"text":"Wherefore, as by one man sin entered into the world, and death by sin; and so death passed upon all men, for that all have sinned:"},"BSB":{"text":"Therefore, just as sin entered the world through one man, and death through sin, so also death was passed on to all men, because all sinned."}},"definableWords":["sin","one","man","death","men"],"peopleInVerse":[]},"13":{"text":"(For until the law sin was in the world: but sin is not imputed when there is no law.","ref":"Romans 5:13","synthesized":"For sin was in the world before the law was given; but sin is not taken into account when there is no law.","sources":{"KJV":{"text":"(For until the law sin was in the world: but sin is not imputed when there is no law."},"BSB":{"text":"For sin was in the world before the law was given; but sin is not taken into account when there is no law."}},"definableWords":["sin","law"],"peopleInVerse":[]},"14":{"text":"Nevertheless death reigned from Adam to Moses, even over them that had not sinned after the similitude of Adam’s transgression, who is the figure of him that was to come.","ref":"Romans 5:14","synthesized":"Nevertheless, death reigned from Adam until Moses, even over those who did not sin in the way that Adam transgressed. He is a pattern of the One to come.","sources":{"KJV":{"text":"Nevertheless death reigned from Adam to Moses, even over them that had not sinned after the similitude of Adam’s transgression, who is the figure of him that was to come."},"BSB":{"text":"Nevertheless, death reigned from Adam until Moses, even over those who did not sin in the way that Adam transgressed. He is a pattern of the One to come."}},"definableWords":["death","Adam","sin","way","adam","one"],"peopleInVerse":["Adam","Moses"]},"15":{"text":"But not as the offence, so also is the free gift. For if through the offence of one many be dead, much more the grace of God, and the gift by grace, which is by one man, Jesus Christ, hath abounded unto many.","ref":"Romans 5:15","synthesized":"But the gift is not like the trespass. For if the many died by the trespass of the one man, how much more did God’s grace and the gift that came by the grace of the one man, Jesus Christ, abound to the many!","sources":{"KJV":{"text":"But not as the offence, so also is the free gift. For if through the offence of one many be dead, much more the grace of God, and the gift by grace, which is by one man, Jesus Christ, hath abounded unto many."},"BSB":{"text":"But the gift is not like the trespass. For if the many died by the trespass of the one man, how much more did God’s grace and the gift that came by the grace of the one man, Jesus Christ, abound to the many!"}},"definableWords":["one","man","God","grace","Christ"],"peopleInVerse":["Jesus"]},"16":{"text":"And not as it was by one that sinned, so is the gift: for the judgment was by one to condemnation, but the free gift is of many offences unto justification.","ref":"Romans 5:16","synthesized":"Again, the gift is not like the result of the one man’s sin: The judgment that followed one sin brought condemnation, but the gift that followed many trespasses brought justification.","sources":{"KJV":{"text":"And not as it was by one that sinned, so is the gift: for the judgment was by one to condemnation, but the free gift is of many offences unto justification."},"BSB":{"text":"Again, the gift is not like the result of the one man’s sin: The judgment that followed one sin brought condemnation, but the gift that followed many trespasses brought justification."}},"definableWords":["one","man","sin","judgment","justification"],"peopleInVerse":[]},"17":{"text":"For if by one man’s offence death reigned by one; much more they which receive abundance of grace and of the gift of righteousness shall reign in life by one, Jesus Christ.)","ref":"Romans 5:17","synthesized":"For if, by the trespass of the one man, death reigned through that one man, how much more will those who receive an abundance of grace and of the gift of righteousness reign in life through the one man, Jesus Christ!","sources":{"KJV":{"text":"For if by one man’s offence death reigned by one; much more they which receive abundance of grace and of the gift of righteousness shall reign in life by one, Jesus Christ.)"},"BSB":{"text":"For if, by the trespass of the one man, death reigned through that one man, how much more will those who receive an abundance of grace and of the gift of righteousness reign in life through the one man, Jesus Christ!"}},"definableWords":["one","man","death","grace","righteousness","reign","life","Christ"],"peopleInVerse":["Jesus"]},"18":{"text":"Therefore as by the offence of one judgment came upon all men to condemnation; even so by the righteousness of one the free gift came upon all men unto justification of life.","ref":"Romans 5:18","synthesized":"So then, just as one trespass brought condemnation for all men, so also one act of righteousness brought justification and life for all men.","sources":{"KJV":{"text":"Therefore as by the offence of one judgment came upon all men to condemnation; even so by the righteousness of one the free gift came upon all men unto justification of life."},"BSB":{"text":"So then, just as one trespass brought condemnation for all men, so also one act of righteousness brought justification and life for all men."}},"definableWords":["one","men","righteousness","justification","life"],"peopleInVerse":[]},"19":{"text":"For as by one man’s disobedience many were made sinners, so by the obedience of one shall many be made righteous.","ref":"Romans 5:19","synthesized":"For just as through the disobedience of the one man the many were made sinners, so also through the obedience of the one man the many will be made righteous.","sources":{"KJV":{"text":"For as by one man’s disobedience many were made sinners, so by the obedience of one shall many be made righteous."},"BSB":{"text":"For just as through the disobedience of the one man the many were made sinners, so also through the obedience of the one man the many will be made righteous."}},"definableWords":["one","man","made","righteous"],"peopleInVerse":[]},"20":{"text":"Moreover the law entered, that the offence might abound. But where sin abounded, grace did much more abound:","ref":"Romans 5:20","synthesized":"The law came in so that the trespass would increase; but where sin increased, grace increased all the more,","sources":{"KJV":{"text":"Moreover the law entered, that the offence might abound. But where sin abounded, grace did much more abound:"},"BSB":{"text":"The law came in so that the trespass would increase; but where sin increased, grace increased all the more,"}},"definableWords":["law","sin","grace"],"peopleInVerse":[]},"21":{"text":"That as sin hath reigned unto death, even so might grace reign through righteousness unto eternal life by Jesus Christ our Lord.","ref":"Romans 5:21","synthesized":"so that, just as sin reigned in death, so also grace might reign through righteousness to bring eternal life through Jesus Christ our Lord.","sources":{"KJV":{"text":"That as sin hath reigned unto death, even so might grace reign through righteousness unto eternal life by Jesus Christ our Lord."},"BSB":{"text":"so that, just as sin reigned in death, so also grace might reign through righteousness to bring eternal life through Jesus Christ our Lord."}},"definableWords":["sin","death","grace","reign","righteousness","eternal","life","Christ","Lord"],"peopleInVerse":["Jesus"]}}},"6":{"chapter":"6","title":"DEAD TO SIN, ALIVE IN CHRIST","verses":{"1":{"text":"What shall we say then? Shall we continue in sin, that grace may abound?","ref":"Romans 6:1","synthesized":"What then shall we say? Shall we continue in sin so that grace may increase?","sources":{"KJV":{"text":"What shall we say then? Shall we continue in sin, that grace may abound?"},"BSB":{"text":"What then shall we say? Shall we continue in sin so that grace may increase?"}},"definableWords":["sin","grace"],"peopleInVerse":[]},"2":{"text":"God forbid. How shall we, that are dead to sin, live any longer therein?","ref":"Romans 6:2","synthesized":"Certainly not! How can we who died to sin live in it any longer?","sources":{"KJV":{"text":"God forbid. How shall we, that are dead to sin, live any longer therein?"},"BSB":{"text":"Certainly not! How can we who died to sin live in it any longer?"}},"definableWords":["sin","live"],"peopleInVerse":[]},"3":{"text":"Know ye not, that so many of us as were baptized into Jesus Christ were baptized into his death?","ref":"Romans 6:3","synthesized":"Or aren’t you aware that all of us who were baptized into Christ Jesus were baptized into His death?","sources":{"KJV":{"text":"Know ye not, that so many of us as were baptized into Jesus Christ were baptized into his death?"},"BSB":{"text":"Or aren’t you aware that all of us who were baptized into Christ Jesus were baptized into His death?"}},"definableWords":["or","Christ","death"],"peopleInVerse":["Jesus"]},"4":{"text":"Therefore we are buried with him by baptism into death: that like as Christ was raised up from the dead by the glory of the Father, even so we also should walk in newness of life.","ref":"Romans 6:4","synthesized":"We were therefore buried with Him through baptism into death, in order that, just as Christ was raised from the dead through the glory of the Father, we too may walk in newness of life.","sources":{"KJV":{"text":"Therefore we are buried with him by baptism into death: that like as Christ was raised up from the dead by the glory of the Father, even so we also should walk in newness of life."},"BSB":{"text":"We were therefore buried with Him through baptism into death, in order that, just as Christ was raised from the dead through the glory of the Father, we too may walk in newness of life."}},"definableWords":["baptism","death","Christ","glory","Father","walk","life"],"peopleInVerse":[]},"5":{"text":"For if we have been planted together in the likeness of his death, we shall be also in the likeness of his resurrection:","ref":"Romans 6:5","synthesized":"For if we have been united with Him like this in His death, we will certainly also be united with Him in His resurrection.","sources":{"KJV":{"text":"For if we have been planted together in the likeness of his death, we shall be also in the likeness of his resurrection:"},"BSB":{"text":"For if we have been united with Him like this in His death, we will certainly also be united with Him in His resurrection."}},"definableWords":["death","resurrection"],"peopleInVerse":[]},"6":{"text":"Knowing this, that our old man is crucified with him, that the body of sin might be destroyed, that henceforth we should not serve sin.","ref":"Romans 6:6","synthesized":"We know that our old self was crucified with Him so that the body of sin might be rendered powerless, that we should no longer be slaves to sin.","sources":{"KJV":{"text":"Knowing this, that our old man is crucified with him, that the body of sin might be destroyed, that henceforth we should not serve sin."},"BSB":{"text":"We know that our old self was crucified with Him so that the body of sin might be rendered powerless, that we should no longer be slaves to sin."}},"definableWords":["sin"],"peopleInVerse":[]},"7":{"text":"For he that is dead is freed from sin.","ref":"Romans 6:7","synthesized":"For anyone who has died has been freed from sin.","sources":{"KJV":{"text":"For he that is dead is freed from sin."},"BSB":{"text":"For anyone who has died has been freed from sin."}},"definableWords":["sin"],"peopleInVerse":[]},"8":{"text":"Now if we be dead with Christ, we believe that we shall also live with him:","ref":"Romans 6:8","synthesized":"Now if we died with Christ, we believe that we will also live with Him.","sources":{"KJV":{"text":"Now if we be dead with Christ, we believe that we shall also live with him:"},"BSB":{"text":"Now if we died with Christ, we believe that we will also live with Him."}},"definableWords":["Christ","live"],"peopleInVerse":[]},"9":{"text":"Knowing that Christ being raised from the dead dieth no more; death hath no more dominion over him.","ref":"Romans 6:9","synthesized":"For we know that since Christ was raised from the dead, He cannot die again; death no longer has dominion over Him.","sources":{"KJV":{"text":"Knowing that Christ being raised from the dead dieth no more; death hath no more dominion over him."},"BSB":{"text":"For we know that since Christ was raised from the dead, He cannot die again; death no longer has dominion over Him."}},"definableWords":["Christ","die","death","dominion"],"peopleInVerse":[]},"10":{"text":"For in that he died, he died unto sin once: but in that he liveth, he liveth unto God.","ref":"Romans 6:10","synthesized":"The death He died, He died to sin once for all; but the life He lives, He lives to God.","sources":{"KJV":{"text":"For in that he died, he died unto sin once: but in that he liveth, he liveth unto God."},"BSB":{"text":"The death He died, He died to sin once for all; but the life He lives, He lives to God."}},"definableWords":["death","sin","life","God"],"peopleInVerse":[]},"11":{"text":"Likewise reckon ye also yourselves to be dead indeed unto sin, but alive unto God through Jesus Christ our Lord.","ref":"Romans 6:11","synthesized":"So you too must count yourselves dead to sin, but alive to God in Christ Jesus.","sources":{"KJV":{"text":"Likewise reckon ye also yourselves to be dead indeed unto sin, but alive unto God through Jesus Christ our Lord."},"BSB":{"text":"So you too must count yourselves dead to sin, but alive to God in Christ Jesus."}},"definableWords":["sin","God","Christ"],"peopleInVerse":["Jesus"]},"12":{"text":"Let not sin therefore reign in your mortal body, that ye should obey it in the lusts thereof.","ref":"Romans 6:12","synthesized":"Therefore do not let sin reign in your mortal body so that you obey its desires.","sources":{"KJV":{"text":"Let not sin therefore reign in your mortal body, that ye should obey it in the lusts thereof."},"BSB":{"text":"Therefore do not let sin reign in your mortal body so that you obey its desires."}},"definableWords":["sin","reign"],"peopleInVerse":[]},"13":{"text":"Neither yield ye your members as instruments of unrighteousness unto sin: but yield yourselves unto God, as those that are alive from the dead, and your members as instruments of righteousness unto God.","ref":"Romans 6:13","synthesized":"Do not present the parts of your body to sin as instruments of wickedness, but present yourselves to God as those who have been brought from death to life; and present the parts of your body to Him as instruments of righteousness.","sources":{"KJV":{"text":"Neither yield ye your members as instruments of unrighteousness unto sin: but yield yourselves unto God, as those that are alive from the dead, and your members as instruments of righteousness unto God."},"BSB":{"text":"Do not present the parts of your body to sin as instruments of wickedness, but present yourselves to God as those who have been brought from death to life; and present the parts of your body to Him as instruments of righteousness."}},"definableWords":["sin","God","death","life","righteousness"],"peopleInVerse":[]},"14":{"text":"For sin shall not have dominion over you: for ye are not under the law, but under grace.","ref":"Romans 6:14","synthesized":"For sin shall not be your master, because you are not under law, but under grace.","sources":{"KJV":{"text":"For sin shall not have dominion over you: for ye are not under the law, but under grace."},"BSB":{"text":"For sin shall not be your master, because you are not under law, but under grace."}},"definableWords":["sin","law","grace"],"peopleInVerse":[]},"15":{"text":"What then? shall we sin, because we are not under the law, but under grace? God forbid.","ref":"Romans 6:15","synthesized":"What then? Shall we sin because we are not under law, but under grace? Certainly not!","sources":{"KJV":{"text":"What then? shall we sin, because we are not under the law, but under grace? God forbid."},"BSB":{"text":"What then? Shall we sin because we are not under law, but under grace? Certainly not!"}},"definableWords":["sin","law","grace"],"peopleInVerse":[]},"16":{"text":"Know ye not, that to whom ye yield yourselves servants to obey, his servants ye are to whom ye obey; whether of sin unto death, or of obedience unto righteousness?","ref":"Romans 6:16","synthesized":"Do you not know that when you offer yourselves as obedient slaves, you are slaves to the one you obey, whether you are slaves to sin leading to death, or to obedience leading to righteousness?","sources":{"KJV":{"text":"Know ye not, that to whom ye yield yourselves servants to obey, his servants ye are to whom ye obey; whether of sin unto death, or of obedience unto righteousness?"},"BSB":{"text":"Do you not know that when you offer yourselves as obedient slaves, you are slaves to the one you obey, whether you are slaves to sin leading to death, or to obedience leading to righteousness?"}},"definableWords":["one","sin","death","or","righteousness"],"peopleInVerse":[]},"17":{"text":"But God be thanked, that ye were the servants of sin, but ye have obeyed from the heart that form of doctrine which was delivered you.","ref":"Romans 6:17","synthesized":"But thanks be to God that, though you once were slaves to sin, you wholeheartedly obeyed the form of teaching to which you were committed.","sources":{"KJV":{"text":"But God be thanked, that ye were the servants of sin, but ye have obeyed from the heart that form of doctrine which was delivered you."},"BSB":{"text":"But thanks be to God that, though you once were slaves to sin, you wholeheartedly obeyed the form of teaching to which you were committed."}},"definableWords":["God","sin","form"],"peopleInVerse":[]},"18":{"text":"Being then made free from sin, ye became the servants of righteousness.","ref":"Romans 6:18","synthesized":"You have been set free from sin and have become slaves to righteousness.","sources":{"KJV":{"text":"Being then made free from sin, ye became the servants of righteousness."},"BSB":{"text":"You have been set free from sin and have become slaves to righteousness."}},"definableWords":["sin","righteousness"],"peopleInVerse":[]},"19":{"text":"I speak after the manner of men because of the infirmity of your flesh: for as ye have yielded your members servants to uncleanness and to iniquity unto iniquity; even so now yield your members servants to righteousness unto holiness.","ref":"Romans 6:19","synthesized":"I am speaking in human terms because of the weakness of your flesh. Just as you used to offer the parts of your body in slavery to impurity and to escalating wickedness, so now offer them in slavery to righteousness leading to holiness.","sources":{"KJV":{"text":"I speak after the manner of men because of the infirmity of your flesh: for as ye have yielded your members servants to uncleanness and to iniquity unto iniquity; even so now yield your members servants to righteousness unto holiness."},"BSB":{"text":"I am speaking in human terms because of the weakness of your flesh. Just as you used to offer the parts of your body in slavery to impurity and to escalating wickedness, so now offer them in slavery to righteousness leading to holiness."}},"definableWords":["flesh","righteousness"],"peopleInVerse":[]},"20":{"text":"For when ye were the servants of sin, ye were free from righteousness.","ref":"Romans 6:20","synthesized":"For when you were slaves to sin, you were free of obligation to righteousness.","sources":{"KJV":{"text":"For when ye were the servants of sin, ye were free from righteousness."},"BSB":{"text":"For when you were slaves to sin, you were free of obligation to righteousness."}},"definableWords":["sin","righteousness"],"peopleInVerse":[]},"21":{"text":"What fruit had ye then in those things whereof ye are now ashamed? for the end of those things is death.","ref":"Romans 6:21","synthesized":"What fruit did you reap at that time from the things of which you are now ashamed? The outcome of those things is death.","sources":{"KJV":{"text":"What fruit had ye then in those things whereof ye are now ashamed? for the end of those things is death."},"BSB":{"text":"What fruit did you reap at that time from the things of which you are now ashamed? The outcome of those things is death."}},"definableWords":["death"],"peopleInVerse":[]},"22":{"text":"But now being made free from sin, and become servants to God, ye have your fruit unto holiness, and the end everlasting life.","ref":"Romans 6:22","synthesized":"But now that you have been set free from sin and have become slaves to God, the fruit you reap leads to holiness, and the outcome is eternal life.","sources":{"KJV":{"text":"But now being made free from sin, and become servants to God, ye have your fruit unto holiness, and the end everlasting life."},"BSB":{"text":"But now that you have been set free from sin and have become slaves to God, the fruit you reap leads to holiness, and the outcome is eternal life."}},"definableWords":["sin","God","eternal","life"],"peopleInVerse":[]},"23":{"text":"For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord.","ref":"Romans 6:23","synthesized":"For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord.","sources":{"KJV":{"text":"For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord."},"BSB":{"text":"For the wages of sin is death, but the gift of God is eternal life in Christ Jesus our Lord."}},"definableWords":["sin","death","God","eternal","life","Christ","Lord"],"peopleInVerse":["Jesus"]}}},"7":{"chapter":"7","title":"THE WAR WITHIN","verses":{"1":{"text":"Know ye not, brethren, (for I speak to them that know the law,) how that the law hath dominion over a man as long as he liveth?","ref":"Romans 7:1","synthesized":"Do you not know, brothers (for I am speaking to those who know the law), that the law has authority over a man only as long as he lives?","sources":{"KJV":{"text":"Know ye not, brethren, (for I speak to them that know the law,) how that the law hath dominion over a man as long as he liveth?"},"BSB":{"text":"Do you not know, brothers (for I am speaking to those who know the law), that the law has authority over a man only as long as he lives?"}},"definableWords":["law","man"],"peopleInVerse":[]},"2":{"text":"For the woman which hath an husband is bound by the law to her husband so long as he liveth; but if the husband be dead, she is loosed from the law of her husband.","ref":"Romans 7:2","synthesized":"For instance, a married woman is bound by law to her husband as long as he lives. But if her husband dies, she is released from the law of marriage.","sources":{"KJV":{"text":"For the woman which hath an husband is bound by the law to her husband so long as he liveth; but if the husband be dead, she is loosed from the law of her husband."},"BSB":{"text":"For instance, a married woman is bound by law to her husband as long as he lives. But if her husband dies, she is released from the law of marriage."}},"definableWords":["woman","law","husband"],"peopleInVerse":[]},"3":{"text":"So then if, while her husband liveth, she be married to another man, she shall be called an adulteress: but if her husband be dead, she is free from that law; so that she is no adulteress, though she be married to another man.","ref":"Romans 7:3","synthesized":"So then, if she is joined to another man while her husband is still alive, she is called an adulteress; but if her husband dies, she is free from that law and is not an adulteress, even if she marries another man.","sources":{"KJV":{"text":"So then if, while her husband liveth, she be married to another man, she shall be called an adulteress: but if her husband be dead, she is free from that law; so that she is no adulteress, though she be married to another man."},"BSB":{"text":"So then, if she is joined to another man while her husband is still alive, she is called an adulteress; but if her husband dies, she is free from that law and is not an adulteress, even if she marries another man."}},"definableWords":["man","husband","law"],"peopleInVerse":[]},"4":{"text":"Wherefore, my brethren, ye also are become dead to the law by the body of Christ; that ye should be married to another, even to him who is raised from the dead, that we should bring forth fruit unto God.","ref":"Romans 7:4","synthesized":"Therefore, my brothers, you also died to the law through the body of Christ, that you might belong to another, to Him who was raised from the dead, in order that we might bear fruit to God.","sources":{"KJV":{"text":"Wherefore, my brethren, ye also are become dead to the law by the body of Christ; that ye should be married to another, even to him who is raised from the dead, that we should bring forth fruit unto God."},"BSB":{"text":"Therefore, my brothers, you also died to the law through the body of Christ, that you might belong to another, to Him who was raised from the dead, in order that we might bear fruit to God."}},"definableWords":["law","Christ","God"],"peopleInVerse":[]},"5":{"text":"For when we were in the flesh, the motions of sins, which were by the law, did work in our members to bring forth fruit unto death.","ref":"Romans 7:5","synthesized":"For when we lived according to the flesh, the sinful passions aroused by the law were at work in our bodies, bearing fruit for death.","sources":{"KJV":{"text":"For when we were in the flesh, the motions of sins, which were by the law, did work in our members to bring forth fruit unto death."},"BSB":{"text":"For when we lived according to the flesh, the sinful passions aroused by the law were at work in our bodies, bearing fruit for death."}},"definableWords":["flesh","law","work","death"],"peopleInVerse":[]},"6":{"text":"But now we are delivered from the law, that being dead wherein we were held; that we should serve in newness of spirit, and not in the oldness of the letter.","ref":"Romans 7:6","synthesized":"But now, having died to what bound us, we have been released from the law, so that we serve in the new way of the Spirit, and not in the old way of the written code.","sources":{"KJV":{"text":"But now we are delivered from the law, that being dead wherein we were held; that we should serve in newness of spirit, and not in the oldness of the letter."},"BSB":{"text":"But now, having died to what bound us, we have been released from the law, so that we serve in the new way of the Spirit, and not in the old way of the written code."}},"definableWords":["law","way","Spirit"],"peopleInVerse":[]},"7":{"text":"What shall we say then? Is the law sin? God forbid. Nay, I had not known sin, but by the law: for I had not known lust, except the law had said, Thou shalt not covet.","ref":"Romans 7:7","synthesized":"What then shall we say? Is the law sin? Certainly not! Indeed, I would not have been mindful of sin if not for the law. For I would not have been aware of coveting if the law had not said, “Do not covet.”","sources":{"KJV":{"text":"What shall we say then? Is the law sin? God forbid. Nay, I had not known sin, but by the law: for I had not known lust, except the law had said, Thou shalt not covet."},"BSB":{"text":"What then shall we say? Is the law sin? Certainly not! Indeed, I would not have been mindful of sin if not for the law. For I would not have been aware of coveting if the law had not said, “Do not covet.”"}},"definableWords":["law","sin"],"peopleInVerse":[]},"8":{"text":"But sin, taking occasion by the commandment, wrought in me all manner of concupiscence. For without the law sin was dead.","ref":"Romans 7:8","synthesized":"But sin, seizing its opportunity through the commandment, produced in me every kind of covetous desire. For apart from the law, sin is dead.","sources":{"KJV":{"text":"But sin, taking occasion by the commandment, wrought in me all manner of concupiscence. For without the law sin was dead."},"BSB":{"text":"But sin, seizing its opportunity through the commandment, produced in me every kind of covetous desire. For apart from the law, sin is dead."}},"definableWords":["sin","commandment","law"],"peopleInVerse":[]},"9":{"text":"For I was alive without the law once: but when the commandment came, sin revived, and I died.","ref":"Romans 7:9","synthesized":"Once I was alive apart from the law; but when the commandment came, sin sprang to life and I died.","sources":{"KJV":{"text":"For I was alive without the law once: but when the commandment came, sin revived, and I died."},"BSB":{"text":"Once I was alive apart from the law; but when the commandment came, sin sprang to life and I died."}},"definableWords":["law","commandment","sin","life"],"peopleInVerse":[]},"10":{"text":"And the commandment, which was ordained to life, I found to be unto death.","ref":"Romans 7:10","synthesized":"So I discovered that the very commandment that was meant to bring life actually brought death.","sources":{"KJV":{"text":"And the commandment, which was ordained to life, I found to be unto death."},"BSB":{"text":"So I discovered that the very commandment that was meant to bring life actually brought death."}},"definableWords":["commandment","life","death"],"peopleInVerse":[]},"11":{"text":"For sin, taking occasion by the commandment, deceived me, and by it slew me.","ref":"Romans 7:11","synthesized":"For sin, seizing its opportunity through the commandment, deceived me and through the commandment put me to death.","sources":{"KJV":{"text":"For sin, taking occasion by the commandment, deceived me, and by it slew me."},"BSB":{"text":"For sin, seizing its opportunity through the commandment, deceived me and through the commandment put me to death."}},"definableWords":["sin","commandment","death"],"peopleInVerse":[]},"12":{"text":"Wherefore the law is holy, and the commandment holy, and just, and good.","ref":"Romans 7:12","synthesized":"So then, the law is holy, and the commandment is holy, righteous, and good.","sources":{"KJV":{"text":"Wherefore the law is holy, and the commandment holy, and just, and good."},"BSB":{"text":"So then, the law is holy, and the commandment is holy, righteous, and good."}},"definableWords":["law","holy","commandment","righteous","good"],"peopleInVerse":[]},"13":{"text":"Was then that which is good made death unto me? God forbid. But sin, that it might appear sin, working death in me by that which is good; that sin by the commandment might become exceeding sinful.","ref":"Romans 7:13","synthesized":"Did that which is good, then, become death to me? Certainly not! But in order that sin might be exposed as sin, it produced death in me through what was good, so that through the commandment sin might become utterly sinful.","sources":{"KJV":{"text":"Was then that which is good made death unto me? God forbid. But sin, that it might appear sin, working death in me by that which is good; that sin by the commandment might become exceeding sinful."},"BSB":{"text":"Did that which is good, then, become death to me? Certainly not! But in order that sin might be exposed as sin, it produced death in me through what was good, so that through the commandment sin might become utterly sinful."}},"definableWords":["good","death","sin","commandment"],"peopleInVerse":[]},"14":{"text":"For we know that the law is spiritual: but I am carnal, sold under sin.","ref":"Romans 7:14","synthesized":"We know that the law is spiritual; but I am unspiritual, sold as a slave to sin.","sources":{"KJV":{"text":"For we know that the law is spiritual: but I am carnal, sold under sin."},"BSB":{"text":"We know that the law is spiritual; but I am unspiritual, sold as a slave to sin."}},"definableWords":["law","sin"],"peopleInVerse":[]},"15":{"text":"For that which I do I allow not: for what I would, that do I not; but what I hate, that do I.","ref":"Romans 7:15","synthesized":"I do not understand what I do. For what I want to do, I do not do. But what I hate, I do.","sources":{"KJV":{"text":"For that which I do I allow not: for what I would, that do I not; but what I hate, that do I."},"BSB":{"text":"I do not understand what I do. For what I want to do, I do not do. But what I hate, I do."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"If then I do that which I would not, I consent unto the law that it is good.","ref":"Romans 7:16","synthesized":"And if I do what I do not want to do, I admit that the law is good.","sources":{"KJV":{"text":"If then I do that which I would not, I consent unto the law that it is good."},"BSB":{"text":"And if I do what I do not want to do, I admit that the law is good."}},"definableWords":["law","good"],"peopleInVerse":[]},"17":{"text":"Now then it is no more I that do it, but sin that dwelleth in me.","ref":"Romans 7:17","synthesized":"In that case, it is no longer I who do it, but it is sin living in me that does it.","sources":{"KJV":{"text":"Now then it is no more I that do it, but sin that dwelleth in me."},"BSB":{"text":"In that case, it is no longer I who do it, but it is sin living in me that does it."}},"definableWords":["sin","living"],"peopleInVerse":[]},"18":{"text":"For I know that in me (that is, in my flesh,) dwelleth no good thing: for to will is present with me; but how to perform that which is good I find not.","ref":"Romans 7:18","synthesized":"I know that nothing good lives in me, that is, in my flesh; for I have the desire to do what is good, but I cannot carry it out.","sources":{"KJV":{"text":"For I know that in me (that is, in my flesh,) dwelleth no good thing: for to will is present with me; but how to perform that which is good I find not."},"BSB":{"text":"I know that nothing good lives in me, that is, in my flesh; for I have the desire to do what is good, but I cannot carry it out."}},"definableWords":["good","flesh"],"peopleInVerse":[]},"19":{"text":"For the good that I would I do not: but the evil which I would not, that I do.","ref":"Romans 7:19","synthesized":"For I do not do the good I want to do. Instead, I keep on doing the evil I do not want to do.","sources":{"KJV":{"text":"For the good that I would I do not: but the evil which I would not, that I do."},"BSB":{"text":"For I do not do the good I want to do. Instead, I keep on doing the evil I do not want to do."}},"definableWords":["good","keep","evil"],"peopleInVerse":[]},"20":{"text":"Now if I do that I would not, it is no more I that do it, but sin that dwelleth in me.","ref":"Romans 7:20","synthesized":"And if I do what I do not want, it is no longer I who do it, but it is sin living in me that does it.","sources":{"KJV":{"text":"Now if I do that I would not, it is no more I that do it, but sin that dwelleth in me."},"BSB":{"text":"And if I do what I do not want, it is no longer I who do it, but it is sin living in me that does it."}},"definableWords":["sin","living"],"peopleInVerse":[]},"21":{"text":"I find then a law, that, when I would do good, evil is present with me.","ref":"Romans 7:21","synthesized":"So this is the principle I have discovered: When I want to do good, evil is right there with me.","sources":{"KJV":{"text":"I find then a law, that, when I would do good, evil is present with me."},"BSB":{"text":"So this is the principle I have discovered: When I want to do good, evil is right there with me."}},"definableWords":["good","evil"],"peopleInVerse":[]},"22":{"text":"For I delight in the law of God after the inward man:","ref":"Romans 7:22","synthesized":"For in my inner being I delight in God’s law.","sources":{"KJV":{"text":"For I delight in the law of God after the inward man:"},"BSB":{"text":"For in my inner being I delight in God’s law."}},"definableWords":["God","law"],"peopleInVerse":[]},"23":{"text":"But I see another law in my members, warring against the law of my mind, and bringing me into captivity to the law of sin which is in my members.","ref":"Romans 7:23","synthesized":"But I see another law at work in my body, warring against the law of my mind and holding me captive to the law of sin that dwells within me.","sources":{"KJV":{"text":"But I see another law in my members, warring against the law of my mind, and bringing me into captivity to the law of sin which is in my members."},"BSB":{"text":"But I see another law at work in my body, warring against the law of my mind and holding me captive to the law of sin that dwells within me."}},"definableWords":["see","law","work","mind","sin"],"peopleInVerse":[]},"24":{"text":"O wretched man that I am! who shall deliver me from the body of this death?","ref":"Romans 7:24","synthesized":"What a wretched man I am! Who will rescue me from this body of death?","sources":{"KJV":{"text":"O wretched man that I am! who shall deliver me from the body of this death?"},"BSB":{"text":"What a wretched man I am! Who will rescue me from this body of death?"}},"definableWords":["man","death"],"peopleInVerse":[]},"25":{"text":"I thank God through Jesus Christ our Lord. So then with the mind I myself serve the law of God; but with the flesh the law of sin.","ref":"Romans 7:25","synthesized":"Thanks be to God, through Jesus Christ our Lord!  So then, with my mind I serve the law of God, but with my flesh I serve the law of sin.","sources":{"KJV":{"text":"I thank God through Jesus Christ our Lord. So then with the mind I myself serve the law of God; but with the flesh the law of sin."},"BSB":{"text":"Thanks be to God, through Jesus Christ our Lord!  So then, with my mind I serve the law of God, but with my flesh I serve the law of sin."}},"definableWords":["God","Christ","Lord","mind","law","flesh","sin"],"peopleInVerse":["Jesus"]}}},"8":{"chapter":"8","title":"NO SEPARATION FROM GOD'S LOVE","verses":{"1":{"text":"There is therefore now no condemnation to them which are in Christ Jesus, who walk not after the flesh, but after the Spirit.","ref":"Romans 8:1","synthesized":"Therefore, there is now no condemnation for those who are in Christ Jesus.","sources":{"KJV":{"text":"There is therefore now no condemnation to them which are in Christ Jesus, who walk not after the flesh, but after the Spirit."},"BSB":{"text":"Therefore, there is now no condemnation for those who are in Christ Jesus."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"],"kingdomLens":"The towering chapter of Romans. 'There is therefore now no condemnation' (v.1). 'The Spirit itself beareth witness with our spirit, that we are the children of God' (v.16). 'All things work together for good' (v.28). It builds to one of the great climaxes in scripture: 'I am persuaded, that neither death, nor life, nor angels, nor principalities... shall be able to separate us from the love of God, which is in Christ Jesus our Lord' (vv.38-39).","cultural":{"title":"Nothing shall separate us from the love of God","detail":"Paul wrote this from Corinth around AD 57, sending it to a church he had not yet visited. The Roman church included Jews and Gentiles, slaves and freedmen — Paul's argument that 'there is no respect of persons with God' (Rom 2:11) was politically explosive in an empire built on hierarchy.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"For the law of the Spirit of life in Christ Jesus hath made me free from the law of sin and death.","ref":"Romans 8:2","synthesized":"For in Christ Jesus the law of the Spirit of life set you free from the law of sin and death.","sources":{"KJV":{"text":"For the law of the Spirit of life in Christ Jesus hath made me free from the law of sin and death."},"BSB":{"text":"For in Christ Jesus the law of the Spirit of life set you free from the law of sin and death."}},"definableWords":["Christ","law","Spirit","life","sin","death"],"peopleInVerse":["Jesus"]},"3":{"text":"For what the law could not do, in that it was weak through the flesh, God sending his own Son in the likeness of sinful flesh, and for sin, condemned sin in the flesh:","ref":"Romans 8:3","synthesized":"For what the law was powerless to do in that it was weakened by the flesh, God did by sending His own Son in the likeness of sinful man, as an offering for sin. He thus condemned sin in the flesh,","sources":{"KJV":{"text":"For what the law could not do, in that it was weak through the flesh, God sending his own Son in the likeness of sinful flesh, and for sin, condemned sin in the flesh:"},"BSB":{"text":"For what the law was powerless to do in that it was weakened by the flesh, God did by sending His own Son in the likeness of sinful man, as an offering for sin. He thus condemned sin in the flesh,"}},"definableWords":["law","flesh","God","Son","likeness","man","offering","sin"],"peopleInVerse":[]},"4":{"text":"That the righteousness of the law might be fulfilled in us, who walk not after the flesh, but after the Spirit.","ref":"Romans 8:4","synthesized":"so that the righteous standard of the law might be fulfilled in us, who do not walk according to the flesh but according to the Spirit.","sources":{"KJV":{"text":"That the righteousness of the law might be fulfilled in us, who walk not after the flesh, but after the Spirit."},"BSB":{"text":"so that the righteous standard of the law might be fulfilled in us, who do not walk according to the flesh but according to the Spirit."}},"definableWords":["righteous","law","walk","flesh","Spirit"],"peopleInVerse":[]},"5":{"text":"For they that are after the flesh do mind the things of the flesh; but they that are after the Spirit the things of the Spirit.","ref":"Romans 8:5","synthesized":"Those who live according to the flesh set their minds on the things of the flesh; but those who live according to the Spirit set their minds on the things of the Spirit.","sources":{"KJV":{"text":"For they that are after the flesh do mind the things of the flesh; but they that are after the Spirit the things of the Spirit."},"BSB":{"text":"Those who live according to the flesh set their minds on the things of the flesh; but those who live according to the Spirit set their minds on the things of the Spirit."}},"definableWords":["live","flesh","Spirit","spirit"],"peopleInVerse":[]},"6":{"text":"For to be carnally minded is death; but to be spiritually minded is life and peace.","ref":"Romans 8:6","synthesized":"The mind of the flesh is death, but the mind of the Spirit is life and peace,","sources":{"KJV":{"text":"For to be carnally minded is death; but to be spiritually minded is life and peace."},"BSB":{"text":"The mind of the flesh is death, but the mind of the Spirit is life and peace,"}},"definableWords":["mind","flesh","death","Spirit","life","peace"],"peopleInVerse":[]},"7":{"text":"Because the carnal mind is enmity against God: for it is not subject to the law of God, neither indeed can be.","ref":"Romans 8:7","synthesized":"because the mind of the flesh is hostile to God: It does not submit to God’s law, nor can it do so.","sources":{"KJV":{"text":"Because the carnal mind is enmity against God: for it is not subject to the law of God, neither indeed can be."},"BSB":{"text":"because the mind of the flesh is hostile to God: It does not submit to God’s law, nor can it do so."}},"definableWords":["mind","flesh","God","law"],"peopleInVerse":[]},"8":{"text":"So then they that are in the flesh cannot please God.","ref":"Romans 8:8","synthesized":"Those controlled by the flesh cannot please God.","sources":{"KJV":{"text":"So then they that are in the flesh cannot please God."},"BSB":{"text":"Those controlled by the flesh cannot please God."}},"definableWords":["flesh","God"],"peopleInVerse":[]},"9":{"text":"But ye are not in the flesh, but in the Spirit, if so be that the Spirit of God dwell in you. Now if any man have not the Spirit of Christ, he is none of his.","ref":"Romans 8:9","synthesized":"You, however, are controlled not by the flesh, but by the Spirit, if the Spirit of God lives in you. And if anyone does not have the Spirit of Christ, he does not belong to Christ.","sources":{"KJV":{"text":"But ye are not in the flesh, but in the Spirit, if so be that the Spirit of God dwell in you. Now if any man have not the Spirit of Christ, he is none of his."},"BSB":{"text":"You, however, are controlled not by the flesh, but by the Spirit, if the Spirit of God lives in you. And if anyone does not have the Spirit of Christ, he does not belong to Christ."}},"definableWords":["flesh","Spirit","spirit","God","Christ"],"peopleInVerse":[]},"10":{"text":"And if Christ be in you, the body is dead because of sin; but the Spirit is life because of righteousness.","ref":"Romans 8:10","synthesized":"But if Christ is in you, your body is dead because of sin, yet your spirit is alive because of righteousness.","sources":{"KJV":{"text":"And if Christ be in you, the body is dead because of sin; but the Spirit is life because of righteousness."},"BSB":{"text":"But if Christ is in you, your body is dead because of sin, yet your spirit is alive because of righteousness."}},"definableWords":["Christ","sin","spirit","righteousness"],"peopleInVerse":[]},"11":{"text":"But if the Spirit of him that raised up Jesus from the dead dwell in you, he that raised up Christ from the dead shall also quicken your mortal bodies by his Spirit that dwelleth in you.","ref":"Romans 8:11","synthesized":"And if the Spirit of Him who raised Jesus from the dead is living in you, He who raised Christ Jesus from the dead will also give life to your mortal bodies through His Spirit, who lives in you.","sources":{"KJV":{"text":"But if the Spirit of him that raised up Jesus from the dead dwell in you, he that raised up Christ from the dead shall also quicken your mortal bodies by his Spirit that dwelleth in you."},"BSB":{"text":"And if the Spirit of Him who raised Jesus from the dead is living in you, He who raised Christ Jesus from the dead will also give life to your mortal bodies through His Spirit, who lives in you."}},"definableWords":["Spirit","living","Christ","life","spirit"],"peopleInVerse":["Jesus"]},"12":{"text":"Therefore, brethren, we are debtors, not to the flesh, to live after the flesh.","ref":"Romans 8:12","synthesized":"Therefore, brothers, we have an obligation, but it is not to the flesh, to live according to it.","sources":{"KJV":{"text":"Therefore, brethren, we are debtors, not to the flesh, to live after the flesh."},"BSB":{"text":"Therefore, brothers, we have an obligation, but it is not to the flesh, to live according to it."}},"definableWords":["flesh","live"],"peopleInVerse":[]},"13":{"text":"For if ye live after the flesh, ye shall die: but if ye through the Spirit do mortify the deeds of the body, ye shall live.","ref":"Romans 8:13","synthesized":"For if you live according to the flesh, you will die; but if by the Spirit you put to death the deeds of the body, you will live.","sources":{"KJV":{"text":"For if ye live after the flesh, ye shall die: but if ye through the Spirit do mortify the deeds of the body, ye shall live."},"BSB":{"text":"For if you live according to the flesh, you will die; but if by the Spirit you put to death the deeds of the body, you will live."}},"definableWords":["live","flesh","die","Spirit","death"],"peopleInVerse":[]},"14":{"text":"For as many as are led by the Spirit of God, they are the sons of God.","ref":"Romans 8:14","synthesized":"For all who are led by the Spirit of God are sons of God.","sources":{"KJV":{"text":"For as many as are led by the Spirit of God, they are the sons of God."},"BSB":{"text":"For all who are led by the Spirit of God are sons of God."}},"definableWords":["Spirit","God","sons"],"peopleInVerse":[]},"15":{"text":"For ye have not received the spirit of bondage again to fear; but ye have received the Spirit of adoption, whereby we cry, Abba, Father.","ref":"Romans 8:15","synthesized":"For you did not receive a spirit of slavery that returns you to fear, but you received the Spirit of sonship, by whom we cry, “Abba! Father!”","sources":{"KJV":{"text":"For ye have not received the spirit of bondage again to fear; but ye have received the Spirit of adoption, whereby we cry, Abba, Father."},"BSB":{"text":"For you did not receive a spirit of slavery that returns you to fear, but you received the Spirit of sonship, by whom we cry, “Abba! Father!”"}},"definableWords":["spirit","fear","Spirit","Father"],"peopleInVerse":[]},"16":{"text":"The Spirit itself beareth witness with our spirit, that we are the children of God:","ref":"Romans 8:16","synthesized":"The Spirit Himself testifies with our spirit that we are God’s children.","sources":{"KJV":{"text":"The Spirit itself beareth witness with our spirit, that we are the children of God:"},"BSB":{"text":"The Spirit Himself testifies with our spirit that we are God’s children."}},"definableWords":["Spirit","spirit","God"],"peopleInVerse":[]},"17":{"text":"And if children, then heirs; heirs of God, and joint-heirs with Christ; if so be that we suffer with him, that we may be also glorified together.","ref":"Romans 8:17","synthesized":"And if we are children, then we are heirs: heirs of God and co-heirs with Christ—if indeed we suffer with Him, so that we may also be glorified with Him.","sources":{"KJV":{"text":"And if children, then heirs; heirs of God, and joint-heirs with Christ; if so be that we suffer with him, that we may be also glorified together."},"BSB":{"text":"And if we are children, then we are heirs: heirs of God and co-heirs with Christ—if indeed we suffer with Him, so that we may also be glorified with Him."}},"definableWords":["God","Christ"],"peopleInVerse":[]},"18":{"text":"For I reckon that the sufferings of this present time are not worthy to be compared with the glory which shall be revealed in us.","ref":"Romans 8:18","synthesized":"I consider that our present sufferings are not comparable to the glory that will be revealed in us.","sources":{"KJV":{"text":"For I reckon that the sufferings of this present time are not worthy to be compared with the glory which shall be revealed in us."},"BSB":{"text":"I consider that our present sufferings are not comparable to the glory that will be revealed in us."}},"definableWords":["glory"],"peopleInVerse":[]},"19":{"text":"For the earnest expectation of the creature waiteth for the manifestation of the sons of God.","ref":"Romans 8:19","synthesized":"The creation waits in eager expectation for the revelation of the sons of God.","sources":{"KJV":{"text":"For the earnest expectation of the creature waiteth for the manifestation of the sons of God."},"BSB":{"text":"The creation waits in eager expectation for the revelation of the sons of God."}},"definableWords":["sons","God"],"peopleInVerse":[]},"20":{"text":"For the creature was made subject to vanity, not willingly, but by reason of him who hath subjected the same in hope,","ref":"Romans 8:20","synthesized":"For the creation was subjected to futility, not by its own will, but because of the One who subjected it, in hope","sources":{"KJV":{"text":"For the creature was made subject to vanity, not willingly, but by reason of him who hath subjected the same in hope,"},"BSB":{"text":"For the creation was subjected to futility, not by its own will, but because of the One who subjected it, in hope"}},"definableWords":["one","hope"],"peopleInVerse":[]},"21":{"text":"Because the creature itself also shall be delivered from the bondage of corruption into the glorious liberty of the children of God.","ref":"Romans 8:21","synthesized":"that the creation itself will be set free from its bondage to decay and brought into the glorious freedom of the children of God.","sources":{"KJV":{"text":"Because the creature itself also shall be delivered from the bondage of corruption into the glorious liberty of the children of God."},"BSB":{"text":"that the creation itself will be set free from its bondage to decay and brought into the glorious freedom of the children of God."}},"definableWords":["God"],"peopleInVerse":[]},"22":{"text":"For we know that the whole creation groaneth and travaileth in pain together until now.","ref":"Romans 8:22","synthesized":"We know that the whole creation has been groaning together in the pains of childbirth until the present time.","sources":{"KJV":{"text":"For we know that the whole creation groaneth and travaileth in pain together until now."},"BSB":{"text":"We know that the whole creation has been groaning together in the pains of childbirth until the present time."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"And not only they, but ourselves also, which have the firstfruits of the Spirit, even we ourselves groan within ourselves, waiting for the adoption, to wit, the redemption of our body.","ref":"Romans 8:23","synthesized":"Not only that, but we ourselves, who have the firstfruits of the Spirit, groan inwardly as we wait eagerly for our adoption as sons, the redemption of our bodies.","sources":{"KJV":{"text":"And not only they, but ourselves also, which have the firstfruits of the Spirit, even we ourselves groan within ourselves, waiting for the adoption, to wit, the redemption of our body."},"BSB":{"text":"Not only that, but we ourselves, who have the firstfruits of the Spirit, groan inwardly as we wait eagerly for our adoption as sons, the redemption of our bodies."}},"definableWords":["Spirit","wait","sons","redemption"],"peopleInVerse":[]},"24":{"text":"For we are saved by hope: but hope that is seen is not hope: for what a man seeth, why doth he yet hope for?","ref":"Romans 8:24","synthesized":"For in this hope we were saved; but hope that is seen is no hope at all. Who hopes for what he can already see?","sources":{"KJV":{"text":"For we are saved by hope: but hope that is seen is not hope: for what a man seeth, why doth he yet hope for?"},"BSB":{"text":"For in this hope we were saved; but hope that is seen is no hope at all. Who hopes for what he can already see?"}},"definableWords":["hope","see"],"peopleInVerse":[]},"25":{"text":"But if we hope for that we see not, then do we with patience wait for it.","ref":"Romans 8:25","synthesized":"But if we hope for what we do not yet see, we wait for it patiently.","sources":{"KJV":{"text":"But if we hope for that we see not, then do we with patience wait for it."},"BSB":{"text":"But if we hope for what we do not yet see, we wait for it patiently."}},"definableWords":["hope","see","wait"],"peopleInVerse":[]},"26":{"text":"Likewise the Spirit also helpeth our infirmities: for we know not what we should pray for as we ought: but the Spirit itself maketh intercession for us with groanings which cannot be uttered.","ref":"Romans 8:26","synthesized":"In the same way, the Spirit helps us in our weakness. For we do not know how we ought to pray, but the Spirit Himself intercedes for us with groans too deep for words.","sources":{"KJV":{"text":"Likewise the Spirit also helpeth our infirmities: for we know not what we should pray for as we ought: but the Spirit itself maketh intercession for us with groanings which cannot be uttered."},"BSB":{"text":"In the same way, the Spirit helps us in our weakness. For we do not know how we ought to pray, but the Spirit Himself intercedes for us with groans too deep for words."}},"definableWords":["way","Spirit","spirit","deep"],"peopleInVerse":[]},"27":{"text":"And he that searcheth the hearts knoweth what is the mind of the Spirit, because he maketh intercession for the saints according to the will of God.","ref":"Romans 8:27","synthesized":"And He who searches our hearts knows the mind of the Spirit, because the Spirit intercedes for the saints according to the will of God.","sources":{"KJV":{"text":"And he that searcheth the hearts knoweth what is the mind of the Spirit, because he maketh intercession for the saints according to the will of God."},"BSB":{"text":"And He who searches our hearts knows the mind of the Spirit, because the Spirit intercedes for the saints according to the will of God."}},"definableWords":["mind","Spirit","spirit","God"],"peopleInVerse":[]},"28":{"text":"And we know that all things work together for good to them that love God, to them who are the called according to his purpose.","ref":"Romans 8:28","synthesized":"And we know that God works all things together for the good of those who love Him, who are called according to His purpose.","sources":{"KJV":{"text":"And we know that all things work together for good to them that love God, to them who are the called according to his purpose."},"BSB":{"text":"And we know that God works all things together for the good of those who love Him, who are called according to His purpose."}},"definableWords":["God","works","good","love"],"peopleInVerse":[]},"29":{"text":"For whom he did foreknow, he also did predestinate to be conformed to the image of his Son, that he might be the firstborn among many brethren.","ref":"Romans 8:29","synthesized":"For those God foreknew, He also predestined to be conformed to the image of His Son, so that He would be the firstborn among many brothers.","sources":{"KJV":{"text":"For whom he did foreknow, he also did predestinate to be conformed to the image of his Son, that he might be the firstborn among many brethren."},"BSB":{"text":"For those God foreknew, He also predestined to be conformed to the image of His Son, so that He would be the firstborn among many brothers."}},"definableWords":["God","image","Son"],"peopleInVerse":[]},"30":{"text":"Moreover whom he did predestinate, them he also called: and whom he called, them he also justified: and whom he justified, them he also glorified.","ref":"Romans 8:30","synthesized":"And those He predestined, He also called; those He called, He also justified; those He justified, He also glorified.","sources":{"KJV":{"text":"Moreover whom he did predestinate, them he also called: and whom he called, them he also justified: and whom he justified, them he also glorified."},"BSB":{"text":"And those He predestined, He also called; those He called, He also justified; those He justified, He also glorified."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"What shall we then say to these things? If God be for us, who can be against us?","ref":"Romans 8:31","synthesized":"What then shall we say in response to these things? If God is for us, who can be against us?","sources":{"KJV":{"text":"What shall we then say to these things? If God be for us, who can be against us?"},"BSB":{"text":"What then shall we say in response to these things? If God is for us, who can be against us?"}},"definableWords":["God"],"peopleInVerse":[]},"32":{"text":"He that spared not his own Son, but delivered him up for us all, how shall he not with him also freely give us all things?","ref":"Romans 8:32","synthesized":"He who did not spare His own Son but gave Him up for us all, how will He not also, along with Him, freely give us all things?","sources":{"KJV":{"text":"He that spared not his own Son, but delivered him up for us all, how shall he not with him also freely give us all things?"},"BSB":{"text":"He who did not spare His own Son but gave Him up for us all, how will He not also, along with Him, freely give us all things?"}},"definableWords":["Son"],"peopleInVerse":[]},"33":{"text":"Who shall lay any thing to the charge of God’s elect? It is God that justifieth.","ref":"Romans 8:33","synthesized":"Who will bring any charge against God’s elect? It is God who justifies.","sources":{"KJV":{"text":"Who shall lay any thing to the charge of God’s elect? It is God that justifieth."},"BSB":{"text":"Who will bring any charge against God’s elect? It is God who justifies."}},"definableWords":["charge","God"],"peopleInVerse":[]},"34":{"text":"Who is he that condemneth? It is Christ that died, yea rather, that is risen again, who is even at the right hand of God, who also maketh intercession for us.","ref":"Romans 8:34","synthesized":"Who is there to condemn us? For Christ Jesus, who died, and more than that was raised to life, is at the right hand of God—and He is interceding for us.","sources":{"KJV":{"text":"Who is he that condemneth? It is Christ that died, yea rather, that is risen again, who is even at the right hand of God, who also maketh intercession for us."},"BSB":{"text":"Who is there to condemn us? For Christ Jesus, who died, and more than that was raised to life, is at the right hand of God—and He is interceding for us."}},"definableWords":["Christ","life","God"],"peopleInVerse":["Jesus"]},"35":{"text":"Who shall separate us from the love of Christ? shall tribulation, or distress, or persecution, or famine, or nakedness, or peril, or sword?","ref":"Romans 8:35","synthesized":"Who shall separate us from the love of Christ? Shall trouble or distress or persecution or famine or nakedness or danger or sword?","sources":{"KJV":{"text":"Who shall separate us from the love of Christ? shall tribulation, or distress, or persecution, or famine, or nakedness, or peril, or sword?"},"BSB":{"text":"Who shall separate us from the love of Christ? Shall trouble or distress or persecution or famine or nakedness or danger or sword?"}},"definableWords":["love","Christ","or"],"peopleInVerse":[]},"36":{"text":"As it is written, For thy sake we are killed all the day long; we are accounted as sheep for the slaughter.","ref":"Romans 8:36","synthesized":"As it is written:  “For Your sake we face death all day long; we are considered as sheep to be slaughtered.”","sources":{"KJV":{"text":"As it is written, For thy sake we are killed all the day long; we are accounted as sheep for the slaughter."},"BSB":{"text":"As it is written:  “For Your sake we face death all day long; we are considered as sheep to be slaughtered.”"}},"definableWords":["death","day"],"peopleInVerse":[]},"37":{"text":"Nay, in all these things we are more than conquerors through him that loved us.","ref":"Romans 8:37","synthesized":"No, in all these things we are more than conquerors through Him who loved us.","sources":{"KJV":{"text":"Nay, in all these things we are more than conquerors through him that loved us."},"BSB":{"text":"No, in all these things we are more than conquerors through Him who loved us."}},"definableWords":[],"peopleInVerse":[]},"38":{"text":"For I am persuaded, that neither death, nor life, nor angels, nor principalities, nor powers, nor things present, nor things to come,","ref":"Romans 8:38","synthesized":"For I am convinced that neither death nor life, neither angels nor principalities, neither the present nor the future, nor any powers,","sources":{"KJV":{"text":"For I am persuaded, that neither death, nor life, nor angels, nor principalities, nor powers, nor things present, nor things to come,"},"BSB":{"text":"For I am convinced that neither death nor life, neither angels nor principalities, neither the present nor the future, nor any powers,"}},"definableWords":["death","life"],"peopleInVerse":[]},"39":{"text":"Nor height, nor depth, nor any other creature, shall be able to separate us from the love of God, which is in Christ Jesus our Lord.","ref":"Romans 8:39","synthesized":"neither height nor depth, nor anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord.","sources":{"KJV":{"text":"Nor height, nor depth, nor any other creature, shall be able to separate us from the love of God, which is in Christ Jesus our Lord."},"BSB":{"text":"neither height nor depth, nor anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord."}},"definableWords":["love","God","Christ","Lord"],"peopleInVerse":["Jesus"]}}},"9":{"chapter":"9","title":"GOD'S SOVEREIGN CHOICE","verses":{"1":{"text":"I say the truth in Christ, I lie not, my conscience also bearing me witness in the Holy Ghost,","ref":"Romans 9:1","synthesized":"I speak the truth in Christ; I am not lying, as confirmed by my conscience in the Holy Spirit.","sources":{"KJV":{"text":"I say the truth in Christ, I lie not, my conscience also bearing me witness in the Holy Ghost,"},"BSB":{"text":"I speak the truth in Christ; I am not lying, as confirmed by my conscience in the Holy Spirit."}},"definableWords":["truth","Christ","holy","Spirit"],"peopleInVerse":[]},"2":{"text":"That I have great heaviness and continual sorrow in my heart.","ref":"Romans 9:2","synthesized":"I have deep sorrow and unceasing anguish in my heart.","sources":{"KJV":{"text":"That I have great heaviness and continual sorrow in my heart."},"BSB":{"text":"I have deep sorrow and unceasing anguish in my heart."}},"definableWords":["deep","heart"],"peopleInVerse":[]},"3":{"text":"For I could wish that myself were accursed from Christ for my brethren, my kinsmen according to the flesh:","ref":"Romans 9:3","synthesized":"For I could wish that I myself were cursed and cut off from Christ for the sake of my brothers, my own flesh and blood,","sources":{"KJV":{"text":"For I could wish that myself were accursed from Christ for my brethren, my kinsmen according to the flesh:"},"BSB":{"text":"For I could wish that I myself were cursed and cut off from Christ for the sake of my brothers, my own flesh and blood,"}},"definableWords":["cursed","Christ","flesh","blood"],"peopleInVerse":[]},"4":{"text":"Who are Israelites; to whom pertaineth the adoption, and the glory, and the covenants, and the giving of the law, and the service of God, and the promises;","ref":"Romans 9:4","synthesized":"the people of Israel. Theirs is the adoption as sons; theirs the divine glory and the covenants; theirs the giving of the law, the temple worship, and the promises.","sources":{"KJV":{"text":"Who are Israelites; to whom pertaineth the adoption, and the glory, and the covenants, and the giving of the law, and the service of God, and the promises;"},"BSB":{"text":"the people of Israel. Theirs is the adoption as sons; theirs the divine glory and the covenants; theirs the giving of the law, the temple worship, and the promises."}},"definableWords":["people","Israel","sons","glory","law","temple","worship"],"peopleInVerse":[]},"5":{"text":"Whose are the fathers, and of whom as concerning the flesh Christ came, who is over all, God blessed for ever. Amen.","ref":"Romans 9:5","synthesized":"Theirs are the patriarchs, and from them proceeds the human descent of Christ, who is God over all, forever worthy of praise! Amen.","sources":{"KJV":{"text":"Whose are the fathers, and of whom as concerning the flesh Christ came, who is over all, God blessed for ever. Amen."},"BSB":{"text":"Theirs are the patriarchs, and from them proceeds the human descent of Christ, who is God over all, forever worthy of praise! Amen."}},"definableWords":["Christ","God","praise"],"peopleInVerse":[]},"6":{"text":"Not as though the word of God hath taken none effect. For they are not all Israel, which are of Israel:","ref":"Romans 9:6","synthesized":"It is not as though God’s word has failed. For not all who are descended from Israel are Israel.","sources":{"KJV":{"text":"Not as though the word of God hath taken none effect. For they are not all Israel, which are of Israel:"},"BSB":{"text":"It is not as though God’s word has failed. For not all who are descended from Israel are Israel."}},"definableWords":["God","word","Israel"],"peopleInVerse":[]},"7":{"text":"Neither, because they are the seed of Abraham, are they all children: but, In Isaac shall thy seed be called.","ref":"Romans 9:7","synthesized":"Nor because they are Abraham’s descendants are they all his children. On the contrary, “Through Isaac your offspring will be reckoned.”","sources":{"KJV":{"text":"Neither, because they are the seed of Abraham, are they all children: but, In Isaac shall thy seed be called."},"BSB":{"text":"Nor because they are Abraham’s descendants are they all his children. On the contrary, “Through Isaac your offspring will be reckoned.”"}},"definableWords":["Abraham","Isaac"],"peopleInVerse":["Abraham","Isaac"]},"8":{"text":"That is, They which are the children of the flesh, these are not the children of God: but the children of the promise are counted for the seed.","ref":"Romans 9:8","synthesized":"So it is not the children of the flesh who are God’s children, but it is the children of the promise who are regarded as offspring.","sources":{"KJV":{"text":"That is, They which are the children of the flesh, these are not the children of God: but the children of the promise are counted for the seed."},"BSB":{"text":"So it is not the children of the flesh who are God’s children, but it is the children of the promise who are regarded as offspring."}},"definableWords":["flesh","God","promise"],"peopleInVerse":[]},"9":{"text":"For this is the word of promise, At this time will I come, and Sarah shall have a son.","ref":"Romans 9:9","synthesized":"For this is what the promise stated: “At the appointed time I will return, and Sarah will have a son.”","sources":{"KJV":{"text":"For this is the word of promise, At this time will I come, and Sarah shall have a son."},"BSB":{"text":"For this is what the promise stated: “At the appointed time I will return, and Sarah will have a son.”"}},"definableWords":["promise","Sarah","son"],"peopleInVerse":["Sarah"]},"10":{"text":"And not only this; but when Rebecca also had conceived by one, even by our father Isaac;","ref":"Romans 9:10","synthesized":"Not only that, but Rebecca’s children were conceived by one man, our father Isaac.","sources":{"KJV":{"text":"And not only this; but when Rebecca also had conceived by one, even by our father Isaac;"},"BSB":{"text":"Not only that, but Rebecca’s children were conceived by one man, our father Isaac."}},"definableWords":["one","man","father","Isaac"],"peopleInVerse":["Isaac"]},"11":{"text":"(For the children being not yet born, neither having done any good or evil, that the purpose of God according to election might stand, not of works, but of him that calleth;)","ref":"Romans 9:11","synthesized":"Yet before the twins were born or had done anything good or bad, in order that God’s plan of election might stand,","sources":{"KJV":{"text":"(For the children being not yet born, neither having done any good or evil, that the purpose of God according to election might stand, not of works, but of him that calleth;)"},"BSB":{"text":"Yet before the twins were born or had done anything good or bad, in order that God’s plan of election might stand,"}},"definableWords":["or","good","God","stand"],"peopleInVerse":[]},"12":{"text":"It was said unto her, The elder shall serve the younger.","ref":"Romans 9:12","synthesized":"not by works but by Him who calls, she was told, “The older will serve the younger.”","sources":{"KJV":{"text":"It was said unto her, The elder shall serve the younger."},"BSB":{"text":"not by works but by Him who calls, she was told, “The older will serve the younger.”"}},"definableWords":["works"],"peopleInVerse":[]},"13":{"text":"As it is written, Jacob have I loved, but Esau have I hated.","ref":"Romans 9:13","synthesized":"So it is written: “Jacob I loved, but Esau I hated.”","sources":{"KJV":{"text":"As it is written, Jacob have I loved, but Esau have I hated."},"BSB":{"text":"So it is written: “Jacob I loved, but Esau I hated.”"}},"definableWords":["Jacob","Esau"],"peopleInVerse":["Jacob","Esau"]},"14":{"text":"What shall we say then? Is there unrighteousness with God? God forbid.","ref":"Romans 9:14","synthesized":"What then shall we say? Is God unjust? Certainly not!","sources":{"KJV":{"text":"What shall we say then? Is there unrighteousness with God? God forbid."},"BSB":{"text":"What then shall we say? Is God unjust? Certainly not!"}},"definableWords":["God"],"peopleInVerse":[]},"15":{"text":"For he saith to Moses, I will have mercy on whom I will have mercy, and I will have compassion on whom I will have compassion.","ref":"Romans 9:15","synthesized":"For He says to Moses:  “I will have mercy on whom I have mercy, and I will have compassion on whom I have compassion.”","sources":{"KJV":{"text":"For he saith to Moses, I will have mercy on whom I will have mercy, and I will have compassion on whom I will have compassion."},"BSB":{"text":"For He says to Moses:  “I will have mercy on whom I have mercy, and I will have compassion on whom I have compassion.”"}},"definableWords":["mercy"],"peopleInVerse":["Moses"]},"16":{"text":"So then it is not of him that willeth, nor of him that runneth, but of God that sheweth mercy.","ref":"Romans 9:16","synthesized":"So then, it does not depend on man’s desire or effort, but on God’s mercy.","sources":{"KJV":{"text":"So then it is not of him that willeth, nor of him that runneth, but of God that sheweth mercy."},"BSB":{"text":"So then, it does not depend on man’s desire or effort, but on God’s mercy."}},"definableWords":["man","or","God","mercy"],"peopleInVerse":[]},"17":{"text":"For the scripture saith unto Pharaoh, Even for this same purpose have I raised thee up, that I might shew my power in thee, and that my name might be declared throughout all the earth.","ref":"Romans 9:17","synthesized":"For the Scripture says to Pharaoh: “I raised you up for this very purpose, that I might display My power in you, and that My name might be proclaimed in all the earth.”","sources":{"KJV":{"text":"For the scripture saith unto Pharaoh, Even for this same purpose have I raised thee up, that I might shew my power in thee, and that my name might be declared throughout all the earth."},"BSB":{"text":"For the Scripture says to Pharaoh: “I raised you up for this very purpose, that I might display My power in you, and that My name might be proclaimed in all the earth.”"}},"definableWords":["Pharaoh","name","earth"],"peopleInVerse":["Pharaoh"]},"18":{"text":"Therefore hath he mercy on whom he will have mercy, and whom he will he hardeneth.","ref":"Romans 9:18","synthesized":"Therefore God has mercy on whom He wants to have mercy, and He hardens whom He wants to harden.","sources":{"KJV":{"text":"Therefore hath he mercy on whom he will have mercy, and whom he will he hardeneth."},"BSB":{"text":"Therefore God has mercy on whom He wants to have mercy, and He hardens whom He wants to harden."}},"definableWords":["God","mercy"],"peopleInVerse":[]},"19":{"text":"Thou wilt say then unto me, Why doth he yet find fault? For who hath resisted his will?","ref":"Romans 9:19","synthesized":"One of you will say to me, “Then why does God still find fault? For who can resist His will?”","sources":{"KJV":{"text":"Thou wilt say then unto me, Why doth he yet find fault? For who hath resisted his will?"},"BSB":{"text":"One of you will say to me, “Then why does God still find fault? For who can resist His will?”"}},"definableWords":["one","God"],"peopleInVerse":[]},"20":{"text":"Nay but, O man, who art thou that repliest against God? Shall the thing formed say to him that formed it, Why hast thou made me thus?","ref":"Romans 9:20","synthesized":"But who are you, O man, to talk back to God? Shall what is formed say to Him who formed it, “Why did You make me like this?”","sources":{"KJV":{"text":"Nay but, O man, who art thou that repliest against God? Shall the thing formed say to him that formed it, Why hast thou made me thus?"},"BSB":{"text":"But who are you, O man, to talk back to God? Shall what is formed say to Him who formed it, “Why did You make me like this?”"}},"definableWords":["man","God","formed","make"],"peopleInVerse":[]},"21":{"text":"Hath not the potter power over the clay, of the same lump to make one vessel unto honour, and another unto dishonour?","ref":"Romans 9:21","synthesized":"Does not the potter have the right to make from the same lump of clay one vessel for special occasions and another for common use?","sources":{"KJV":{"text":"Hath not the potter power over the clay, of the same lump to make one vessel unto honour, and another unto dishonour?"},"BSB":{"text":"Does not the potter have the right to make from the same lump of clay one vessel for special occasions and another for common use?"}},"definableWords":["make","one"],"peopleInVerse":[]},"22":{"text":"What if God, willing to shew his wrath, and to make his power known, endured with much longsuffering the vessels of wrath fitted to destruction:","ref":"Romans 9:22","synthesized":"What if God, intending to show His wrath and make His power known, bore with great patience the vessels of His wrath, prepared for destruction?","sources":{"KJV":{"text":"What if God, willing to shew his wrath, and to make his power known, endured with much longsuffering the vessels of wrath fitted to destruction:"},"BSB":{"text":"What if God, intending to show His wrath and make His power known, bore with great patience the vessels of His wrath, prepared for destruction?"}},"definableWords":["God","wrath","make","great","patience"],"peopleInVerse":[]},"23":{"text":"And that he might make known the riches of his glory on the vessels of mercy, which he had afore prepared unto glory,","ref":"Romans 9:23","synthesized":"What if He did this to make the riches of His glory known to the vessels of His mercy, whom He prepared in advance for glory—","sources":{"KJV":{"text":"And that he might make known the riches of his glory on the vessels of mercy, which he had afore prepared unto glory,"},"BSB":{"text":"What if He did this to make the riches of His glory known to the vessels of His mercy, whom He prepared in advance for glory—"}},"definableWords":["make","glory","mercy"],"peopleInVerse":[]},"24":{"text":"Even us, whom he hath called, not of the Jews only, but also of the Gentiles?","ref":"Romans 9:24","synthesized":"including us, whom He has called not only from the Jews, but also from the Gentiles?","sources":{"KJV":{"text":"Even us, whom he hath called, not of the Jews only, but also of the Gentiles?"},"BSB":{"text":"including us, whom He has called not only from the Jews, but also from the Gentiles?"}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"As he saith also in Osee, I will call them my people, which were not my people; and her beloved, which was not beloved.","ref":"Romans 9:25","synthesized":"As He says in Hosea:  “I will call them ‘My People’ who are not My people, and I will call her ‘My Beloved’ who is not My beloved,”","sources":{"KJV":{"text":"As he saith also in Osee, I will call them my people, which were not my people; and her beloved, which was not beloved."},"BSB":{"text":"As He says in Hosea:  “I will call them ‘My People’ who are not My people, and I will call her ‘My Beloved’ who is not My beloved,”"}},"definableWords":["people"],"peopleInVerse":[]},"26":{"text":"And it shall come to pass, that in the place where it was said unto them, Ye are not my people; there shall they be called the children of the living God.","ref":"Romans 9:26","synthesized":"and,  “It will happen that in the very place where it was said to them, ‘You are not My people,’ they will be called ‘sons of the living God.’”","sources":{"KJV":{"text":"And it shall come to pass, that in the place where it was said unto them, Ye are not my people; there shall they be called the children of the living God."},"BSB":{"text":"and,  “It will happen that in the very place where it was said to them, ‘You are not My people,’ they will be called ‘sons of the living God.’”"}},"definableWords":["people","sons","living","God"],"peopleInVerse":[]},"27":{"text":"Esaias also crieth concerning Israel, Though the number of the children of Israel be as the sand of the sea, a remnant shall be saved:","ref":"Romans 9:27","synthesized":"Isaiah cries out concerning Israel:  “Though the number of the Israelites is like the sand of the sea, only the remnant will be saved.","sources":{"KJV":{"text":"Esaias also crieth concerning Israel, Though the number of the children of Israel be as the sand of the sea, a remnant shall be saved:"},"BSB":{"text":"Isaiah cries out concerning Israel:  “Though the number of the Israelites is like the sand of the sea, only the remnant will be saved."}},"definableWords":["Israel","Israelites","sea","remnant"],"peopleInVerse":["Isaiah"]},"28":{"text":"For he will finish the work, and cut it short in righteousness: because a short work will the Lord make upon the earth.","ref":"Romans 9:28","synthesized":"For the Lord will carry out His sentence on the earth thoroughly and decisively.”","sources":{"KJV":{"text":"For he will finish the work, and cut it short in righteousness: because a short work will the Lord make upon the earth."},"BSB":{"text":"For the Lord will carry out His sentence on the earth thoroughly and decisively.”"}},"definableWords":["Lord","earth"],"peopleInVerse":[]},"29":{"text":"And as Esaias said before, Except the Lord of Sabaoth had left us a seed, we had been as Sodoma, and been made like unto Gomorrha.","ref":"Romans 9:29","synthesized":"It is just as Isaiah foretold:  “Unless the Lord of Hosts had left us descendants, we would have become like Sodom, we would have resembled Gomorrah.”","sources":{"KJV":{"text":"And as Esaias said before, Except the Lord of Sabaoth had left us a seed, we had been as Sodoma, and been made like unto Gomorrha."},"BSB":{"text":"It is just as Isaiah foretold:  “Unless the Lord of Hosts had left us descendants, we would have become like Sodom, we would have resembled Gomorrah.”"}},"definableWords":["Lord","Sodom","Gomorrah"],"peopleInVerse":["Isaiah"]},"30":{"text":"What shall we say then? That the Gentiles, which followed not after righteousness, have attained to righteousness, even the righteousness which is of faith.","ref":"Romans 9:30","synthesized":"What then will we say? That the Gentiles, who did not pursue righteousness, have obtained it, a righteousness that is by faith;","sources":{"KJV":{"text":"What shall we say then? That the Gentiles, which followed not after righteousness, have attained to righteousness, even the righteousness which is of faith."},"BSB":{"text":"What then will we say? That the Gentiles, who did not pursue righteousness, have obtained it, a righteousness that is by faith;"}},"definableWords":["righteousness","faith"],"peopleInVerse":[]},"31":{"text":"But Israel, which followed after the law of righteousness, hath not attained to the law of righteousness.","ref":"Romans 9:31","synthesized":"but Israel, who pursued a law of righteousness, has not attained it.","sources":{"KJV":{"text":"But Israel, which followed after the law of righteousness, hath not attained to the law of righteousness."},"BSB":{"text":"but Israel, who pursued a law of righteousness, has not attained it."}},"definableWords":["Israel","law","righteousness"],"peopleInVerse":[]},"32":{"text":"Wherefore? Because they sought it not by faith, but as it were by the works of the law. For they stumbled at that stumblingstone;","ref":"Romans 9:32","synthesized":"Why not? Because their pursuit was not by faith, but as if it were by works. They stumbled over the stumbling stone,","sources":{"KJV":{"text":"Wherefore? Because they sought it not by faith, but as it were by the works of the law. For they stumbled at that stumblingstone;"},"BSB":{"text":"Why not? Because their pursuit was not by faith, but as if it were by works. They stumbled over the stumbling stone,"}},"definableWords":["faith","works","stone"],"peopleInVerse":[]},"33":{"text":"As it is written, Behold, I lay in Sion a stumblingstone and rock of offence: and whosoever believeth on him shall not be ashamed.","ref":"Romans 9:33","synthesized":"as it is written:  “See, I lay in Zion a stone of stumbling and a rock of offense; and the one who believes in Him will never be put to shame.”","sources":{"KJV":{"text":"As it is written, Behold, I lay in Sion a stumblingstone and rock of offence: and whosoever believeth on him shall not be ashamed."},"BSB":{"text":"as it is written:  “See, I lay in Zion a stone of stumbling and a rock of offense; and the one who believes in Him will never be put to shame.”"}},"definableWords":["see","Zion","stone","one"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"WHOSOEVER SHALL CALL UPON THE NAME","verses":{"1":{"text":"Brethren, my heart’s desire and prayer to God for Israel is, that they might be saved.","ref":"Romans 10:1","synthesized":"Brothers, my heart’s desire and prayer to God for the Israelites is for their salvation.","sources":{"KJV":{"text":"Brethren, my heart’s desire and prayer to God for Israel is, that they might be saved."},"BSB":{"text":"Brothers, my heart’s desire and prayer to God for the Israelites is for their salvation."}},"definableWords":["heart","prayer","God","Israelites","salvation"],"peopleInVerse":[]},"2":{"text":"For I bear them record that they have a zeal of God, but not according to knowledge.","ref":"Romans 10:2","synthesized":"For I testify about them that they are zealous for God, but not on the basis of knowledge.","sources":{"KJV":{"text":"For I bear them record that they have a zeal of God, but not according to knowledge."},"BSB":{"text":"For I testify about them that they are zealous for God, but not on the basis of knowledge."}},"definableWords":["God","knowledge"],"peopleInVerse":[]},"3":{"text":"For they being ignorant of God’s righteousness, and going about to establish their own righteousness, have not submitted themselves unto the righteousness of God.","ref":"Romans 10:3","synthesized":"Because they were ignorant of God’s righteousness and sought to establish their own, they did not submit to God’s righteousness.","sources":{"KJV":{"text":"For they being ignorant of God’s righteousness, and going about to establish their own righteousness, have not submitted themselves unto the righteousness of God."},"BSB":{"text":"Because they were ignorant of God’s righteousness and sought to establish their own, they did not submit to God’s righteousness."}},"definableWords":["God","righteousness"],"peopleInVerse":[]},"4":{"text":"For Christ is the end of the law for righteousness to every one that believeth.","ref":"Romans 10:4","synthesized":"For Christ is the end of the law, to bring righteousness to everyone who believes.","sources":{"KJV":{"text":"For Christ is the end of the law for righteousness to every one that believeth."},"BSB":{"text":"For Christ is the end of the law, to bring righteousness to everyone who believes."}},"definableWords":["Christ","law","righteousness"],"peopleInVerse":[]},"5":{"text":"For Moses describeth the righteousness which is of the law, That the man which doeth those things shall live by them.","ref":"Romans 10:5","synthesized":"For concerning the righteousness that is by the law, Moses writes: “The man who does these things will live by them.”","sources":{"KJV":{"text":"For Moses describeth the righteousness which is of the law, That the man which doeth those things shall live by them."},"BSB":{"text":"For concerning the righteousness that is by the law, Moses writes: “The man who does these things will live by them.”"}},"definableWords":["righteousness","law","man","live"],"peopleInVerse":["Moses"]},"6":{"text":"But the righteousness which is of faith speaketh on this wise, Say not in thine heart, Who shall ascend into heaven? (that is, to bring Christ down from above:)","ref":"Romans 10:6","synthesized":"But the righteousness that is by faith says: “Do not say in your heart, ‘Who will ascend into heaven?’ (that is, to bring Christ down)","sources":{"KJV":{"text":"But the righteousness which is of faith speaketh on this wise, Say not in thine heart, Who shall ascend into heaven? (that is, to bring Christ down from above:)"},"BSB":{"text":"But the righteousness that is by faith says: “Do not say in your heart, ‘Who will ascend into heaven?’ (that is, to bring Christ down)"}},"definableWords":["righteousness","faith","heart","heaven","Christ"],"peopleInVerse":[]},"7":{"text":"Or, Who shall descend into the deep? (that is, to bring up Christ again from the dead.)","ref":"Romans 10:7","synthesized":"or, ‘Who will descend into the Abyss?’ (that is, to bring Christ up from the dead).”","sources":{"KJV":{"text":"Or, Who shall descend into the deep? (that is, to bring up Christ again from the dead.)"},"BSB":{"text":"or, ‘Who will descend into the Abyss?’ (that is, to bring Christ up from the dead).”"}},"definableWords":["or","Christ"],"peopleInVerse":[]},"8":{"text":"But what saith it? The word is nigh thee, even in thy mouth, and in thy heart: that is, the word of faith, which we preach;","ref":"Romans 10:8","synthesized":"But what does it say? “The word is near you; it is in your mouth and in your heart,” that is, the word of faith we are proclaiming:","sources":{"KJV":{"text":"But what saith it? The word is nigh thee, even in thy mouth, and in thy heart: that is, the word of faith, which we preach;"},"BSB":{"text":"But what does it say? “The word is near you; it is in your mouth and in your heart,” that is, the word of faith we are proclaiming:"}},"definableWords":["word","heart","faith"],"peopleInVerse":[]},"9":{"text":"That if thou shalt confess with thy mouth the Lord Jesus, and shalt believe in thine heart that God hath raised him from the dead, thou shalt be saved.","ref":"Romans 10:9","synthesized":"that if you confess with your mouth, “Jesus is Lord,” and believe in your heart that God raised Him from the dead, you will be saved.","sources":{"KJV":{"text":"That if thou shalt confess with thy mouth the Lord Jesus, and shalt believe in thine heart that God hath raised him from the dead, thou shalt be saved."},"BSB":{"text":"that if you confess with your mouth, “Jesus is Lord,” and believe in your heart that God raised Him from the dead, you will be saved."}},"definableWords":["Lord","heart","God"],"peopleInVerse":["Jesus"]},"10":{"text":"For with the heart man believeth unto righteousness; and with the mouth confession is made unto salvation.","ref":"Romans 10:10","synthesized":"For with your heart you believe and are justified, and with your mouth you confess and are saved.","sources":{"KJV":{"text":"For with the heart man believeth unto righteousness; and with the mouth confession is made unto salvation."},"BSB":{"text":"For with your heart you believe and are justified, and with your mouth you confess and are saved."}},"definableWords":["heart"],"peopleInVerse":[]},"11":{"text":"For the scripture saith, Whosoever believeth on him shall not be ashamed.","ref":"Romans 10:11","synthesized":"It is just as the Scripture says: “Anyone who believes in Him will never be put to shame.”","sources":{"KJV":{"text":"For the scripture saith, Whosoever believeth on him shall not be ashamed."},"BSB":{"text":"It is just as the Scripture says: “Anyone who believes in Him will never be put to shame.”"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For there is no difference between the Jew and the Greek: for the same Lord over all is rich unto all that call upon him.","ref":"Romans 10:12","synthesized":"For there is no difference between Jew and Greek: The same Lord is Lord of all, and gives richly to all who call on Him,","sources":{"KJV":{"text":"For there is no difference between the Jew and the Greek: for the same Lord over all is rich unto all that call upon him."},"BSB":{"text":"For there is no difference between Jew and Greek: The same Lord is Lord of all, and gives richly to all who call on Him,"}},"definableWords":["Jew","Greek","Lord"],"peopleInVerse":[]},"13":{"text":"For whosoever shall call upon the name of the Lord shall be saved.","ref":"Romans 10:13","synthesized":"for, “Everyone who calls on the name of the Lord will be saved.”","sources":{"KJV":{"text":"For whosoever shall call upon the name of the Lord shall be saved."},"BSB":{"text":"for, “Everyone who calls on the name of the Lord will be saved.”"}},"definableWords":["name","Lord"],"peopleInVerse":[]},"14":{"text":"How then shall they call on him in whom they have not believed? and how shall they believe in him of whom they have not heard? and how shall they hear without a preacher?","ref":"Romans 10:14","synthesized":"How then can they call on the One in whom they have not believed? And how can they believe in the One of whom they have not heard? And how can they hear without someone to preach?","sources":{"KJV":{"text":"How then shall they call on him in whom they have not believed? and how shall they believe in him of whom they have not heard? and how shall they hear without a preacher?"},"BSB":{"text":"How then can they call on the One in whom they have not believed? And how can they believe in the One of whom they have not heard? And how can they hear without someone to preach?"}},"definableWords":["one","believed","hear"],"peopleInVerse":[]},"15":{"text":"And how shall they preach, except they be sent? as it is written, How beautiful are the feet of them that preach the gospel of peace, and bring glad tidings of good things!","ref":"Romans 10:15","synthesized":"And how can they preach unless they are sent? As it is written: “How beautiful are the feet of those who bring good news!”","sources":{"KJV":{"text":"And how shall they preach, except they be sent? as it is written, How beautiful are the feet of them that preach the gospel of peace, and bring glad tidings of good things!"},"BSB":{"text":"And how can they preach unless they are sent? As it is written: “How beautiful are the feet of those who bring good news!”"}},"definableWords":["good"],"peopleInVerse":[]},"16":{"text":"But they have not all obeyed the gospel. For Esaias saith, Lord, who hath believed our report?","ref":"Romans 10:16","synthesized":"But not all of them welcomed the good news. For Isaiah says, “Lord, who has believed our message?”","sources":{"KJV":{"text":"But they have not all obeyed the gospel. For Esaias saith, Lord, who hath believed our report?"},"BSB":{"text":"But not all of them welcomed the good news. For Isaiah says, “Lord, who has believed our message?”"}},"definableWords":["good","Lord","believed"],"peopleInVerse":["Isaiah"]},"17":{"text":"So then faith cometh by hearing, and hearing by the word of God.","ref":"Romans 10:17","synthesized":"Consequently, faith comes by hearing, and hearing by the word of Christ.","sources":{"KJV":{"text":"So then faith cometh by hearing, and hearing by the word of God."},"BSB":{"text":"Consequently, faith comes by hearing, and hearing by the word of Christ."}},"definableWords":["faith","word","Christ"],"peopleInVerse":[]},"18":{"text":"But I say, Have they not heard? Yes verily, their sound went into all the earth, and their words unto the ends of the world.","ref":"Romans 10:18","synthesized":"But I ask, did they not hear? Indeed they did:  “Their voice has gone out into all the earth, their words to the ends of the world.”","sources":{"KJV":{"text":"But I say, Have they not heard? Yes verily, their sound went into all the earth, and their words unto the ends of the world."},"BSB":{"text":"But I ask, did they not hear? Indeed they did:  “Their voice has gone out into all the earth, their words to the ends of the world.”"}},"definableWords":["hear","voice","earth"],"peopleInVerse":[]},"19":{"text":"But I say, Did not Israel know? First Moses saith, I will provoke you to jealousy by them that are no people, and by a foolish nation I will anger you.","ref":"Romans 10:19","synthesized":"I ask instead, did Israel not understand? First, Moses says:  “I will make you jealous by those who are not a nation; I will make you angry by a nation without understanding.”","sources":{"KJV":{"text":"But I say, Did not Israel know? First Moses saith, I will provoke you to jealousy by them that are no people, and by a foolish nation I will anger you."},"BSB":{"text":"I ask instead, did Israel not understand? First, Moses says:  “I will make you jealous by those who are not a nation; I will make you angry by a nation without understanding.”"}},"definableWords":["Israel","make","nation"],"peopleInVerse":["Moses"]},"20":{"text":"But Esaias is very bold, and saith, I was found of them that sought me not; I was made manifest unto them that asked not after me.","ref":"Romans 10:20","synthesized":"And Isaiah boldly says:  “I was found by those who did not seek Me; I revealed Myself to those who did not ask for Me.”","sources":{"KJV":{"text":"But Esaias is very bold, and saith, I was found of them that sought me not; I was made manifest unto them that asked not after me."},"BSB":{"text":"And Isaiah boldly says:  “I was found by those who did not seek Me; I revealed Myself to those who did not ask for Me.”"}},"definableWords":["seek"],"peopleInVerse":["Isaiah"]},"21":{"text":"But to Israel he saith, All day long I have stretched forth my hands unto a disobedient and gainsaying people.","ref":"Romans 10:21","synthesized":"But as for Israel he says:  “All day long I have held out My hands to a disobedient and obstinate people.”","sources":{"KJV":{"text":"But to Israel he saith, All day long I have stretched forth my hands unto a disobedient and gainsaying people."},"BSB":{"text":"But as for Israel he says:  “All day long I have held out My hands to a disobedient and obstinate people.”"}},"definableWords":["Israel","day","people"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"ISRAEL — GRAFTED IN, BROKEN OFF, GRAFTED IN AGAIN","verses":{"1":{"text":"I say then, Hath God cast away his people? God forbid. For I also am an Israelite, of the seed of Abraham, of the tribe of Benjamin.","ref":"Romans 11:1","synthesized":"I ask then, did God reject His people? Certainly not! I am an Israelite myself, a descendant of Abraham, from the tribe of Benjamin.","sources":{"KJV":{"text":"I say then, Hath God cast away his people? God forbid. For I also am an Israelite, of the seed of Abraham, of the tribe of Benjamin."},"BSB":{"text":"I ask then, did God reject His people? Certainly not! I am an Israelite myself, a descendant of Abraham, from the tribe of Benjamin."}},"definableWords":["God","people","Abraham","tribe","Benjamin"],"peopleInVerse":["Abraham"]},"2":{"text":"God hath not cast away his people which he foreknew. Wot ye not what the scripture saith of Elias? how he maketh intercession to God against Israel, saying,","ref":"Romans 11:2","synthesized":"God did not reject His people, whom He foreknew. Do you not know what the Scripture says about Elijah, how he appealed to God against Israel:","sources":{"KJV":{"text":"God hath not cast away his people which he foreknew. Wot ye not what the scripture saith of Elias? how he maketh intercession to God against Israel, saying,"},"BSB":{"text":"God did not reject His people, whom He foreknew. Do you not know what the Scripture says about Elijah, how he appealed to God against Israel:"}},"definableWords":["God","people","Israel"],"peopleInVerse":["Elijah"]},"3":{"text":"Lord, they have killed thy prophets, and digged down thine altars; and I am left alone, and they seek my life.","ref":"Romans 11:3","synthesized":"“Lord, they have killed Your prophets and torn down Your altars. I am the only one left, and they are seeking my life as well”?","sources":{"KJV":{"text":"Lord, they have killed thy prophets, and digged down thine altars; and I am left alone, and they seek my life."},"BSB":{"text":"“Lord, they have killed Your prophets and torn down Your altars. I am the only one left, and they are seeking my life as well”?"}},"definableWords":["Lord","one","life"],"peopleInVerse":[]},"4":{"text":"But what saith the answer of God unto him? I have reserved to myself seven thousand men, who have not bowed the knee to the image of Baal.","ref":"Romans 11:4","synthesized":"And what was the divine reply to him? “I have reserved for Myself seven thousand men who have not bowed the knee to Baal.”","sources":{"KJV":{"text":"But what saith the answer of God unto him? I have reserved to myself seven thousand men, who have not bowed the knee to the image of Baal."},"BSB":{"text":"And what was the divine reply to him? “I have reserved for Myself seven thousand men who have not bowed the knee to Baal.”"}},"definableWords":["men"],"peopleInVerse":[]},"5":{"text":"Even so then at this present time also there is a remnant according to the election of grace.","ref":"Romans 11:5","synthesized":"In the same way, at the present time there is a remnant chosen by grace.","sources":{"KJV":{"text":"Even so then at this present time also there is a remnant according to the election of grace."},"BSB":{"text":"In the same way, at the present time there is a remnant chosen by grace."}},"definableWords":["way","remnant","grace"],"peopleInVerse":[]},"6":{"text":"And if by grace, then is it no more of works: otherwise grace is no more grace. But if it be of works, then is it no more grace: otherwise work is no more work.","ref":"Romans 11:6","synthesized":"And if it is by grace, then it is no longer by works. Otherwise, grace would no longer be grace.","sources":{"KJV":{"text":"And if by grace, then is it no more of works: otherwise grace is no more grace. But if it be of works, then is it no more grace: otherwise work is no more work."},"BSB":{"text":"And if it is by grace, then it is no longer by works. Otherwise, grace would no longer be grace."}},"definableWords":["grace","works"],"peopleInVerse":[]},"7":{"text":"What then? Israel hath not obtained that which he seeketh for; but the election hath obtained it, and the rest were blinded.","ref":"Romans 11:7","synthesized":"What then? What Israel was seeking, it failed to obtain, but the elect did. The others were hardened,","sources":{"KJV":{"text":"What then? Israel hath not obtained that which he seeketh for; but the election hath obtained it, and the rest were blinded."},"BSB":{"text":"What then? What Israel was seeking, it failed to obtain, but the elect did. The others were hardened,"}},"definableWords":["Israel"],"peopleInVerse":[]},"8":{"text":"(According as it is written, God hath given them the spirit of slumber, eyes that they should not see, and ears that they should not hear;) unto this day.","ref":"Romans 11:8","synthesized":"as it is written:  “God gave them a spirit of stupor, eyes that could not see, and ears that could not hear, to this very day.”","sources":{"KJV":{"text":"(According as it is written, God hath given them the spirit of slumber, eyes that they should not see, and ears that they should not hear;) unto this day."},"BSB":{"text":"as it is written:  “God gave them a spirit of stupor, eyes that could not see, and ears that could not hear, to this very day.”"}},"definableWords":["God","spirit","see","hear","day"],"peopleInVerse":[]},"9":{"text":"And David saith, Let their table be made a snare, and a trap, and a stumblingblock, and a recompence unto them:","ref":"Romans 11:9","synthesized":"And David says:  “May their table become a snare and a trap, a stumbling block and a retribution to them.","sources":{"KJV":{"text":"And David saith, Let their table be made a snare, and a trap, and a stumblingblock, and a recompence unto them:"},"BSB":{"text":"And David says:  “May their table become a snare and a trap, a stumbling block and a retribution to them."}},"definableWords":[],"peopleInVerse":["David"]},"10":{"text":"Let their eyes be darkened, that they may not see, and bow down their back alway.","ref":"Romans 11:10","synthesized":"May their eyes be darkened so they cannot see, and their backs be bent forever.”","sources":{"KJV":{"text":"Let their eyes be darkened, that they may not see, and bow down their back alway."},"BSB":{"text":"May their eyes be darkened so they cannot see, and their backs be bent forever.”"}},"definableWords":["see"],"peopleInVerse":[]},"11":{"text":"I say then, Have they stumbled that they should fall? God forbid: but rather through their fall salvation is come unto the Gentiles, for to provoke them to jealousy.","ref":"Romans 11:11","synthesized":"I ask then, did they stumble so as to fall beyond recovery? Certainly not! However, because of their trespass, salvation has come to the Gentiles to make Israel jealous.","sources":{"KJV":{"text":"I say then, Have they stumbled that they should fall? God forbid: but rather through their fall salvation is come unto the Gentiles, for to provoke them to jealousy."},"BSB":{"text":"I ask then, did they stumble so as to fall beyond recovery? Certainly not! However, because of their trespass, salvation has come to the Gentiles to make Israel jealous."}},"definableWords":["salvation","make","Israel"],"peopleInVerse":[]},"12":{"text":"Now if the fall of them be the riches of the world, and the diminishing of them the riches of the Gentiles; how much more their fulness?","ref":"Romans 11:12","synthesized":"But if their trespass means riches for the world, and their failure means riches for the Gentiles, how much greater riches will their fullness bring!","sources":{"KJV":{"text":"Now if the fall of them be the riches of the world, and the diminishing of them the riches of the Gentiles; how much more their fulness?"},"BSB":{"text":"But if their trespass means riches for the world, and their failure means riches for the Gentiles, how much greater riches will their fullness bring!"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"For I speak to you Gentiles, inasmuch as I am the apostle of the Gentiles, I magnify mine office:","ref":"Romans 11:13","synthesized":"I am speaking to you Gentiles. Inasmuch as I am the apostle to the Gentiles, I magnify my ministry","sources":{"KJV":{"text":"For I speak to you Gentiles, inasmuch as I am the apostle of the Gentiles, I magnify mine office:"},"BSB":{"text":"I am speaking to you Gentiles. Inasmuch as I am the apostle to the Gentiles, I magnify my ministry"}},"definableWords":["apostle"],"peopleInVerse":[]},"14":{"text":"If by any means I may provoke to emulation them which are my flesh, and might save some of them.","ref":"Romans 11:14","synthesized":"in the hope that I may provoke my own people to jealousy and save some of them.","sources":{"KJV":{"text":"If by any means I may provoke to emulation them which are my flesh, and might save some of them."},"BSB":{"text":"in the hope that I may provoke my own people to jealousy and save some of them."}},"definableWords":["hope","people"],"peopleInVerse":[]},"15":{"text":"For if the casting away of them be the reconciling of the world, what shall the receiving of them be, but life from the dead?","ref":"Romans 11:15","synthesized":"For if their rejection is the reconciliation of the world, what will their acceptance be but life from the dead?","sources":{"KJV":{"text":"For if the casting away of them be the reconciling of the world, what shall the receiving of them be, but life from the dead?"},"BSB":{"text":"For if their rejection is the reconciliation of the world, what will their acceptance be but life from the dead?"}},"definableWords":["life"],"peopleInVerse":[]},"16":{"text":"For if the firstfruit be holy, the lump is also holy: and if the root be holy, so are the branches.","ref":"Romans 11:16","synthesized":"If the first part of the dough is holy, so is the whole batch; if the root is holy, so are the branches.","sources":{"KJV":{"text":"For if the firstfruit be holy, the lump is also holy: and if the root be holy, so are the branches."},"BSB":{"text":"If the first part of the dough is holy, so is the whole batch; if the root is holy, so are the branches."}},"definableWords":["holy"],"peopleInVerse":[]},"17":{"text":"And if some of the branches be broken off, and thou, being a wild olive tree, wert graffed in among them, and with them partakest of the root and fatness of the olive tree;","ref":"Romans 11:17","synthesized":"Now if some branches have been broken off, and you, a wild olive shoot, have been grafted in among the others to share in the nourishment of the olive root,","sources":{"KJV":{"text":"And if some of the branches be broken off, and thou, being a wild olive tree, wert graffed in among them, and with them partakest of the root and fatness of the olive tree;"},"BSB":{"text":"Now if some branches have been broken off, and you, a wild olive shoot, have been grafted in among the others to share in the nourishment of the olive root,"}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Boast not against the branches. But if thou boast, thou bearest not the root, but the root thee.","ref":"Romans 11:18","synthesized":"do not boast over those branches. If you do, remember this: You do not support the root, but the root supports you.","sources":{"KJV":{"text":"Boast not against the branches. But if thou boast, thou bearest not the root, but the root thee."},"BSB":{"text":"do not boast over those branches. If you do, remember this: You do not support the root, but the root supports you."}},"definableWords":["remember"],"peopleInVerse":[]},"19":{"text":"Thou wilt say then, The branches were broken off, that I might be graffed in.","ref":"Romans 11:19","synthesized":"You will say then, “Branches were broken off so that I could be grafted in.”","sources":{"KJV":{"text":"Thou wilt say then, The branches were broken off, that I might be graffed in."},"BSB":{"text":"You will say then, “Branches were broken off so that I could be grafted in.”"}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Well; because of unbelief they were broken off, and thou standest by faith. Be not highminded, but fear:","ref":"Romans 11:20","synthesized":"That is correct: They were broken off because of unbelief, but you stand by faith. Do not be arrogant, but be afraid.","sources":{"KJV":{"text":"Well; because of unbelief they were broken off, and thou standest by faith. Be not highminded, but fear:"},"BSB":{"text":"That is correct: They were broken off because of unbelief, but you stand by faith. Do not be arrogant, but be afraid."}},"definableWords":["stand","faith"],"peopleInVerse":[]},"21":{"text":"For if God spared not the natural branches, take heed lest he also spare not thee.","ref":"Romans 11:21","synthesized":"For if God did not spare the natural branches, He will certainly not spare you either.","sources":{"KJV":{"text":"For if God spared not the natural branches, take heed lest he also spare not thee."},"BSB":{"text":"For if God did not spare the natural branches, He will certainly not spare you either."}},"definableWords":["God"],"peopleInVerse":[]},"22":{"text":"Behold therefore the goodness and severity of God: on them which fell, severity; but toward thee, goodness, if thou continue in his goodness: otherwise thou also shalt be cut off.","ref":"Romans 11:22","synthesized":"Take notice, therefore, of the kindness and severity of God: severity to those who fell, but kindness to you, if you continue in His kindness. Otherwise you also will be cut off.","sources":{"KJV":{"text":"Behold therefore the goodness and severity of God: on them which fell, severity; but toward thee, goodness, if thou continue in his goodness: otherwise thou also shalt be cut off."},"BSB":{"text":"Take notice, therefore, of the kindness and severity of God: severity to those who fell, but kindness to you, if you continue in His kindness. Otherwise you also will be cut off."}},"definableWords":["kindness","God"],"peopleInVerse":[]},"23":{"text":"And they also, if they abide not still in unbelief, shall be graffed in: for God is able to graff them in again.","ref":"Romans 11:23","synthesized":"And if they do not persist in unbelief, they will be grafted in, for God is able to graft them in again.","sources":{"KJV":{"text":"And they also, if they abide not still in unbelief, shall be graffed in: for God is able to graff them in again."},"BSB":{"text":"And if they do not persist in unbelief, they will be grafted in, for God is able to graft them in again."}},"definableWords":["God"],"peopleInVerse":[]},"24":{"text":"For if thou wert cut out of the olive tree which is wild by nature, and wert graffed contrary to nature into a good olive tree: how much more shall these, which be the natural branches, be graffed into their own olive tree?","ref":"Romans 11:24","synthesized":"For if you were cut from a wild olive tree, and contrary to nature were grafted into one that is cultivated, how much more readily will these, the natural branches, be grafted into their own olive tree!","sources":{"KJV":{"text":"For if thou wert cut out of the olive tree which is wild by nature, and wert graffed contrary to nature into a good olive tree: how much more shall these, which be the natural branches, be graffed into their own olive tree?"},"BSB":{"text":"For if you were cut from a wild olive tree, and contrary to nature were grafted into one that is cultivated, how much more readily will these, the natural branches, be grafted into their own olive tree!"}},"definableWords":["tree","one"],"peopleInVerse":[]},"25":{"text":"For I would not, brethren, that ye should be ignorant of this mystery, lest ye should be wise in your own conceits; that blindness in part is happened to Israel, until the fulness of the Gentiles be come in.","ref":"Romans 11:25","synthesized":"I do not want you to be ignorant of this mystery, brothers, so that you will not be conceited: A hardening in part has come to Israel, until the full number of the Gentiles has come in.","sources":{"KJV":{"text":"For I would not, brethren, that ye should be ignorant of this mystery, lest ye should be wise in your own conceits; that blindness in part is happened to Israel, until the fulness of the Gentiles be come in."},"BSB":{"text":"I do not want you to be ignorant of this mystery, brothers, so that you will not be conceited: A hardening in part has come to Israel, until the full number of the Gentiles has come in."}},"definableWords":["Israel"],"peopleInVerse":[]},"26":{"text":"And so all Israel shall be saved: as it is written, There shall come out of Sion the Deliverer, and shall turn away ungodliness from Jacob:","ref":"Romans 11:26","synthesized":"And so all Israel will be saved, as it is written:  “The Deliverer will come from Zion; He will remove godlessness from Jacob.","sources":{"KJV":{"text":"And so all Israel shall be saved: as it is written, There shall come out of Sion the Deliverer, and shall turn away ungodliness from Jacob:"},"BSB":{"text":"And so all Israel will be saved, as it is written:  “The Deliverer will come from Zion; He will remove godlessness from Jacob."}},"definableWords":["Israel","Zion","Jacob"],"peopleInVerse":["Jacob"]},"27":{"text":"For this is my covenant unto them, when I shall take away their sins.","ref":"Romans 11:27","synthesized":"And this is My covenant with them when I take away their sins.”","sources":{"KJV":{"text":"For this is my covenant unto them, when I shall take away their sins."},"BSB":{"text":"And this is My covenant with them when I take away their sins.”"}},"definableWords":["covenant"],"peopleInVerse":[]},"28":{"text":"As concerning the gospel, they are enemies for your sakes: but as touching the election, they are beloved for the fathers’ sakes.","ref":"Romans 11:28","synthesized":"Regarding the gospel, they are enemies on your account; but regarding election, they are loved on account of the patriarchs.","sources":{"KJV":{"text":"As concerning the gospel, they are enemies for your sakes: but as touching the election, they are beloved for the fathers’ sakes."},"BSB":{"text":"Regarding the gospel, they are enemies on your account; but regarding election, they are loved on account of the patriarchs."}},"definableWords":["gospel"],"peopleInVerse":[]},"29":{"text":"For the gifts and calling of God are without repentance.","ref":"Romans 11:29","synthesized":"For God’s gifts and His call are irrevocable.","sources":{"KJV":{"text":"For the gifts and calling of God are without repentance."},"BSB":{"text":"For God’s gifts and His call are irrevocable."}},"definableWords":["God"],"peopleInVerse":[]},"30":{"text":"For as ye in times past have not believed God, yet have now obtained mercy through their unbelief:","ref":"Romans 11:30","synthesized":"Just as you who formerly disobeyed God have now received mercy through their disobedience,","sources":{"KJV":{"text":"For as ye in times past have not believed God, yet have now obtained mercy through their unbelief:"},"BSB":{"text":"Just as you who formerly disobeyed God have now received mercy through their disobedience,"}},"definableWords":["God","mercy"],"peopleInVerse":[]},"31":{"text":"Even so have these also now not believed, that through your mercy they also may obtain mercy.","ref":"Romans 11:31","synthesized":"so they too have now disobeyed, in order that they too may now receive mercy through the mercy shown to you.","sources":{"KJV":{"text":"Even so have these also now not believed, that through your mercy they also may obtain mercy."},"BSB":{"text":"so they too have now disobeyed, in order that they too may now receive mercy through the mercy shown to you."}},"definableWords":["mercy"],"peopleInVerse":[]},"32":{"text":"For God hath concluded them all in unbelief, that he might have mercy upon all.","ref":"Romans 11:32","synthesized":"For God has consigned everyone to disobedience so that He may have mercy on everyone.","sources":{"KJV":{"text":"For God hath concluded them all in unbelief, that he might have mercy upon all."},"BSB":{"text":"For God has consigned everyone to disobedience so that He may have mercy on everyone."}},"definableWords":["God","mercy"],"peopleInVerse":[]},"33":{"text":"O the depth of the riches both of the wisdom and knowledge of God! how unsearchable are his judgments, and his ways past finding out!","ref":"Romans 11:33","synthesized":"O, the depth of the riches of the wisdom and knowledge of God! How unsearchable are His judgments, and untraceable His ways!","sources":{"KJV":{"text":"O the depth of the riches both of the wisdom and knowledge of God! how unsearchable are his judgments, and his ways past finding out!"},"BSB":{"text":"O, the depth of the riches of the wisdom and knowledge of God! How unsearchable are His judgments, and untraceable His ways!"}},"definableWords":["wisdom","knowledge","God"],"peopleInVerse":[]},"34":{"text":"For who hath known the mind of the Lord? or who hath been his counsellor?","ref":"Romans 11:34","synthesized":"“Who has known the mind of the Lord? Or who has been His counselor?”","sources":{"KJV":{"text":"For who hath known the mind of the Lord? or who hath been his counsellor?"},"BSB":{"text":"“Who has known the mind of the Lord? Or who has been His counselor?”"}},"definableWords":["mind","Lord","or"],"peopleInVerse":[]},"35":{"text":"Or who hath first given to him, and it shall be recompensed unto him again?","ref":"Romans 11:35","synthesized":"“Who has first given to God, that God should repay him?”","sources":{"KJV":{"text":"Or who hath first given to him, and it shall be recompensed unto him again?"},"BSB":{"text":"“Who has first given to God, that God should repay him?”"}},"definableWords":["God"],"peopleInVerse":[]},"36":{"text":"For of him, and through him, and to him, are all things: to whom be glory for ever. Amen.","ref":"Romans 11:36","synthesized":"For from Him and through Him and to Him are all things. To Him be the glory forever! Amen.","sources":{"KJV":{"text":"For of him, and through him, and to him, are all things: to whom be glory for ever. Amen."},"BSB":{"text":"For from Him and through Him and to Him are all things. To Him be the glory forever! Amen."}},"definableWords":["glory"],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"LIVING SACRIFICES","verses":{"1":{"text":"I beseech you therefore, brethren, by the mercies of God, that ye present your bodies a living sacrifice, holy, acceptable unto God, which is your reasonable service.","ref":"Romans 12:1","synthesized":"Therefore I urge you, brothers, on account of God’s mercy, to offer your bodies as living sacrifices, holy and pleasing to God, which is your spiritual service of worship.","sources":{"KJV":{"text":"I beseech you therefore, brethren, by the mercies of God, that ye present your bodies a living sacrifice, holy, acceptable unto God, which is your reasonable service."},"BSB":{"text":"Therefore I urge you, brothers, on account of God’s mercy, to offer your bodies as living sacrifices, holy and pleasing to God, which is your spiritual service of worship."}},"definableWords":["God","mercy","living","holy","worship"],"peopleInVerse":[]},"2":{"text":"And be not conformed to this world: but be ye transformed by the renewing of your mind, that ye may prove what is that good, and acceptable, and perfect, will of God.","ref":"Romans 12:2","synthesized":"Do not be conformed to this world, but be transformed by the renewing of your mind. Then you will be able to test and approve what is the good, pleasing, and perfect will of God.","sources":{"KJV":{"text":"And be not conformed to this world: but be ye transformed by the renewing of your mind, that ye may prove what is that good, and acceptable, and perfect, will of God."},"BSB":{"text":"Do not be conformed to this world, but be transformed by the renewing of your mind. Then you will be able to test and approve what is the good, pleasing, and perfect will of God."}},"definableWords":["mind","good","God"],"peopleInVerse":[]},"3":{"text":"For I say, through the grace given unto me, to every man that is among you, not to think of himself more highly than he ought to think; but to think soberly, according as God hath dealt to every man the measure of faith.","ref":"Romans 12:3","synthesized":"For by the grace given me I say to every one of you: Do not think of yourself more highly than you ought, but think of yourself with sober judgment, according to the measure of faith God has given you.","sources":{"KJV":{"text":"For I say, through the grace given unto me, to every man that is among you, not to think of himself more highly than he ought to think; but to think soberly, according as God hath dealt to every man the measure of faith."},"BSB":{"text":"For by the grace given me I say to every one of you: Do not think of yourself more highly than you ought, but think of yourself with sober judgment, according to the measure of faith God has given you."}},"definableWords":["grace","one","judgment","faith","God"],"peopleInVerse":[]},"4":{"text":"For as we have many members in one body, and all members have not the same office:","ref":"Romans 12:4","synthesized":"Just as each of us has one body with many members, and not all members have the same function,","sources":{"KJV":{"text":"For as we have many members in one body, and all members have not the same office:"},"BSB":{"text":"Just as each of us has one body with many members, and not all members have the same function,"}},"definableWords":["one"],"peopleInVerse":[]},"5":{"text":"So we, being many, are one body in Christ, and every one members one of another.","ref":"Romans 12:5","synthesized":"so in Christ we who are many are one body, and each member belongs to one another.","sources":{"KJV":{"text":"So we, being many, are one body in Christ, and every one members one of another."},"BSB":{"text":"so in Christ we who are many are one body, and each member belongs to one another."}},"definableWords":["Christ","one"],"peopleInVerse":[]},"6":{"text":"Having then gifts differing according to the grace that is given to us, whether prophecy, let us prophesy according to the proportion of faith;","ref":"Romans 12:6","synthesized":"We have different gifts according to the grace given us. If one’s gift is prophecy, let him use it in proportion to his faith;","sources":{"KJV":{"text":"Having then gifts differing according to the grace that is given to us, whether prophecy, let us prophesy according to the proportion of faith;"},"BSB":{"text":"We have different gifts according to the grace given us. If one’s gift is prophecy, let him use it in proportion to his faith;"}},"definableWords":["grace","one","faith"],"peopleInVerse":[]},"7":{"text":"Or ministry, let us wait on our ministering: or he that teacheth, on teaching;","ref":"Romans 12:7","synthesized":"if it is serving, let him serve; if it is teaching, let him teach;","sources":{"KJV":{"text":"Or ministry, let us wait on our ministering: or he that teacheth, on teaching;"},"BSB":{"text":"if it is serving, let him serve; if it is teaching, let him teach;"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Or he that exhorteth, on exhortation: he that giveth, let him do it with simplicity; he that ruleth, with diligence; he that sheweth mercy, with cheerfulness.","ref":"Romans 12:8","synthesized":"if it is encouraging, let him encourage; if it is giving, let him give generously; if it is leading, let him lead with diligence; if it is showing mercy, let him do it cheerfully.","sources":{"KJV":{"text":"Or he that exhorteth, on exhortation: he that giveth, let him do it with simplicity; he that ruleth, with diligence; he that sheweth mercy, with cheerfulness."},"BSB":{"text":"if it is encouraging, let him encourage; if it is giving, let him give generously; if it is leading, let him lead with diligence; if it is showing mercy, let him do it cheerfully."}},"definableWords":["mercy"],"peopleInVerse":[]},"9":{"text":"Let love be without dissimulation. Abhor that which is evil; cleave to that which is good.","ref":"Romans 12:9","synthesized":"Love must be sincere. Detest what is evil; cling to what is good.","sources":{"KJV":{"text":"Let love be without dissimulation. Abhor that which is evil; cleave to that which is good."},"BSB":{"text":"Love must be sincere. Detest what is evil; cling to what is good."}},"definableWords":["love","evil","good"],"peopleInVerse":[]},"10":{"text":"Be kindly affectioned one to another with brotherly love; in honour preferring one another;","ref":"Romans 12:10","synthesized":"Be devoted to one another in brotherly love. Outdo yourselves in honoring one another.","sources":{"KJV":{"text":"Be kindly affectioned one to another with brotherly love; in honour preferring one another;"},"BSB":{"text":"Be devoted to one another in brotherly love. Outdo yourselves in honoring one another."}},"definableWords":["one","love"],"peopleInVerse":[]},"11":{"text":"Not slothful in business; fervent in spirit; serving the Lord;","ref":"Romans 12:11","synthesized":"Do not let your zeal subside; keep your spiritual fervor, serving the Lord.","sources":{"KJV":{"text":"Not slothful in business; fervent in spirit; serving the Lord;"},"BSB":{"text":"Do not let your zeal subside; keep your spiritual fervor, serving the Lord."}},"definableWords":["keep","Lord"],"peopleInVerse":[]},"12":{"text":"Rejoicing in hope; patient in tribulation; continuing instant in prayer;","ref":"Romans 12:12","synthesized":"Be joyful in hope, patient in affliction, persistent in prayer.","sources":{"KJV":{"text":"Rejoicing in hope; patient in tribulation; continuing instant in prayer;"},"BSB":{"text":"Be joyful in hope, patient in affliction, persistent in prayer."}},"definableWords":["hope","prayer"],"peopleInVerse":[]},"13":{"text":"Distributing to the necessity of saints; given to hospitality.","ref":"Romans 12:13","synthesized":"Share with the saints who are in need. Practice hospitality.","sources":{"KJV":{"text":"Distributing to the necessity of saints; given to hospitality."},"BSB":{"text":"Share with the saints who are in need. Practice hospitality."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Bless them which persecute you: bless, and curse not.","ref":"Romans 12:14","synthesized":"Bless those who persecute you. Bless and do not curse.","sources":{"KJV":{"text":"Bless them which persecute you: bless, and curse not."},"BSB":{"text":"Bless those who persecute you. Bless and do not curse."}},"definableWords":["bless","curse"],"peopleInVerse":[]},"15":{"text":"Rejoice with them that do rejoice, and weep with them that weep.","ref":"Romans 12:15","synthesized":"Rejoice with those who rejoice; weep with those who weep.","sources":{"KJV":{"text":"Rejoice with them that do rejoice, and weep with them that weep."},"BSB":{"text":"Rejoice with those who rejoice; weep with those who weep."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Be of the same mind one toward another. Mind not high things, but condescend to men of low estate. Be not wise in your own conceits.","ref":"Romans 12:16","synthesized":"Live in harmony with one another. Do not be proud, but enjoy the company of the lowly. Do not be conceited.","sources":{"KJV":{"text":"Be of the same mind one toward another. Mind not high things, but condescend to men of low estate. Be not wise in your own conceits."},"BSB":{"text":"Live in harmony with one another. Do not be proud, but enjoy the company of the lowly. Do not be conceited."}},"definableWords":["live","one"],"peopleInVerse":[]},"17":{"text":"Recompense to no man evil for evil. Provide things honest in the sight of all men.","ref":"Romans 12:17","synthesized":"Do not repay anyone evil for evil. Carefully consider what is right in the eyes of everybody.","sources":{"KJV":{"text":"Recompense to no man evil for evil. Provide things honest in the sight of all men."},"BSB":{"text":"Do not repay anyone evil for evil. Carefully consider what is right in the eyes of everybody."}},"definableWords":["evil"],"peopleInVerse":[]},"18":{"text":"If it be possible, as much as lieth in you, live peaceably with all men.","ref":"Romans 12:18","synthesized":"If it is possible on your part, live at peace with everyone.","sources":{"KJV":{"text":"If it be possible, as much as lieth in you, live peaceably with all men."},"BSB":{"text":"If it is possible on your part, live at peace with everyone."}},"definableWords":["live","peace"],"peopleInVerse":[]},"19":{"text":"Dearly beloved, avenge not yourselves, but rather give place unto wrath: for it is written, Vengeance is mine; I will repay, saith the Lord.","ref":"Romans 12:19","synthesized":"Do not avenge yourselves, beloved, but leave room for God’s wrath. For it is written: “Vengeance is Mine; I will repay, says the Lord.”","sources":{"KJV":{"text":"Dearly beloved, avenge not yourselves, but rather give place unto wrath: for it is written, Vengeance is mine; I will repay, saith the Lord."},"BSB":{"text":"Do not avenge yourselves, beloved, but leave room for God’s wrath. For it is written: “Vengeance is Mine; I will repay, says the Lord.”"}},"definableWords":["God","wrath","Lord"],"peopleInVerse":[]},"20":{"text":"Therefore if thine enemy hunger, feed him; if he thirst, give him drink: for in so doing thou shalt heap coals of fire on his head.","ref":"Romans 12:20","synthesized":"On the contrary,  “If your enemy is hungry, feed him; if he is thirsty, give him a drink. For in so doing, you will heap burning coals on his head.”","sources":{"KJV":{"text":"Therefore if thine enemy hunger, feed him; if he thirst, give him drink: for in so doing thou shalt heap coals of fire on his head."},"BSB":{"text":"On the contrary,  “If your enemy is hungry, feed him; if he is thirsty, give him a drink. For in so doing, you will heap burning coals on his head.”"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Be not overcome of evil, but overcome evil with good.","ref":"Romans 12:21","synthesized":"Do not be overcome by evil, but overcome evil with good.","sources":{"KJV":{"text":"Be not overcome of evil, but overcome evil with good."},"BSB":{"text":"Do not be overcome by evil, but overcome evil with good."}},"definableWords":["overcome","evil","good"],"peopleInVerse":[]}}},"13":{"chapter":"13","title":"OBEY GOVERNING AUTHORITIES","verses":{"1":{"text":"Let every soul be subject unto the higher powers. For there is no power but of God: the powers that be are ordained of God.","ref":"Romans 13:1","synthesized":"Everyone must submit himself to the governing authorities, for there is no authority except that which is from God. The authorities that exist have been appointed by God.","sources":{"KJV":{"text":"Let every soul be subject unto the higher powers. For there is no power but of God: the powers that be are ordained of God."},"BSB":{"text":"Everyone must submit himself to the governing authorities, for there is no authority except that which is from God. The authorities that exist have been appointed by God."}},"definableWords":["God"],"peopleInVerse":[]},"2":{"text":"Whosoever therefore resisteth the power, resisteth the ordinance of God: and they that resist shall receive to themselves damnation.","ref":"Romans 13:2","synthesized":"Consequently, whoever resists authority is opposing what God has set in place, and those who do so will bring judgment on themselves.","sources":{"KJV":{"text":"Whosoever therefore resisteth the power, resisteth the ordinance of God: and they that resist shall receive to themselves damnation."},"BSB":{"text":"Consequently, whoever resists authority is opposing what God has set in place, and those who do so will bring judgment on themselves."}},"definableWords":["God","judgment"],"peopleInVerse":[]},"3":{"text":"For rulers are not a terror to good works, but to the evil. Wilt thou then not be afraid of the power? do that which is good, and thou shalt have praise of the same:","ref":"Romans 13:3","synthesized":"For rulers are not a terror to good conduct, but to bad. Do you want to be unafraid of the one in authority? Then do what is right, and you will have his approval.","sources":{"KJV":{"text":"For rulers are not a terror to good works, but to the evil. Wilt thou then not be afraid of the power? do that which is good, and thou shalt have praise of the same:"},"BSB":{"text":"For rulers are not a terror to good conduct, but to bad. Do you want to be unafraid of the one in authority? Then do what is right, and you will have his approval."}},"definableWords":["good","one"],"peopleInVerse":[]},"4":{"text":"For he is the minister of God to thee for good. But if thou do that which is evil, be afraid; for he beareth not the sword in vain: for he is the minister of God, a revenger to execute wrath upon him that doeth evil.","ref":"Romans 13:4","synthesized":"For he is God’s servant for your good. But if you do wrong, be afraid, for he does not carry the sword in vain. He is God’s servant, an agent of retribution to the wrongdoer.","sources":{"KJV":{"text":"For he is the minister of God to thee for good. But if thou do that which is evil, be afraid; for he beareth not the sword in vain: for he is the minister of God, a revenger to execute wrath upon him that doeth evil."},"BSB":{"text":"For he is God’s servant for your good. But if you do wrong, be afraid, for he does not carry the sword in vain. He is God’s servant, an agent of retribution to the wrongdoer."}},"definableWords":["God","servant","good"],"peopleInVerse":[]},"5":{"text":"Wherefore ye must needs be subject, not only for wrath, but also for conscience sake.","ref":"Romans 13:5","synthesized":"Therefore it is necessary to submit to authority, not only to avoid punishment, but also as a matter of conscience.","sources":{"KJV":{"text":"Wherefore ye must needs be subject, not only for wrath, but also for conscience sake."},"BSB":{"text":"Therefore it is necessary to submit to authority, not only to avoid punishment, but also as a matter of conscience."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"For for this cause pay ye tribute also: for they are God’s ministers, attending continually upon this very thing.","ref":"Romans 13:6","synthesized":"This is also why you pay taxes. For the authorities are God’s servants, who devote themselves to their work.","sources":{"KJV":{"text":"For for this cause pay ye tribute also: for they are God’s ministers, attending continually upon this very thing."},"BSB":{"text":"This is also why you pay taxes. For the authorities are God’s servants, who devote themselves to their work."}},"definableWords":["God","servants","work"],"peopleInVerse":[]},"7":{"text":"Render therefore to all their dues: tribute to whom tribute is due; custom to whom custom; fear to whom fear; honour to whom honour.","ref":"Romans 13:7","synthesized":"Pay everyone what you owe him: taxes to whom taxes are due, revenue to whom revenue is due, respect to whom respect is due, honor to whom honor is due.","sources":{"KJV":{"text":"Render therefore to all their dues: tribute to whom tribute is due; custom to whom custom; fear to whom fear; honour to whom honour."},"BSB":{"text":"Pay everyone what you owe him: taxes to whom taxes are due, revenue to whom revenue is due, respect to whom respect is due, honor to whom honor is due."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Owe no man any thing, but to love one another: for he that loveth another hath fulfilled the law.","ref":"Romans 13:8","synthesized":"Be indebted to no one, except to one another in love. For he who loves his neighbor has fulfilled the law.","sources":{"KJV":{"text":"Owe no man any thing, but to love one another: for he that loveth another hath fulfilled the law."},"BSB":{"text":"Be indebted to no one, except to one another in love. For he who loves his neighbor has fulfilled the law."}},"definableWords":["one","love","law"],"peopleInVerse":[]},"9":{"text":"For this, Thou shalt not commit adultery, Thou shalt not kill, Thou shalt not steal, Thou shalt not bear false witness, Thou shalt not covet; and if there be any other commandment, it is briefly comprehended in this saying, namely, Thou shalt love thy neighbour as thyself.","ref":"Romans 13:9","synthesized":"The commandments “Do not commit adultery,” “Do not murder,” “Do not steal,” “Do not covet,” and any other commandments, are summed up in this one decree: “Love your neighbor as yourself.”","sources":{"KJV":{"text":"For this, Thou shalt not commit adultery, Thou shalt not kill, Thou shalt not steal, Thou shalt not bear false witness, Thou shalt not covet; and if there be any other commandment, it is briefly comprehended in this saying, namely, Thou shalt love thy neighbour as thyself."},"BSB":{"text":"The commandments “Do not commit adultery,” “Do not murder,” “Do not steal,” “Do not covet,” and any other commandments, are summed up in this one decree: “Love your neighbor as yourself.”"}},"definableWords":["one","love"],"peopleInVerse":[]},"10":{"text":"Love worketh no ill to his neighbour: therefore love is the fulfilling of the law.","ref":"Romans 13:10","synthesized":"Love does no wrong to its neighbor. Therefore love is the fulfillment of the law.","sources":{"KJV":{"text":"Love worketh no ill to his neighbour: therefore love is the fulfilling of the law."},"BSB":{"text":"Love does no wrong to its neighbor. Therefore love is the fulfillment of the law."}},"definableWords":["love","law"],"peopleInVerse":[]},"11":{"text":"And that, knowing the time, that now it is high time to awake out of sleep: for now is our salvation nearer than when we believed.","ref":"Romans 13:11","synthesized":"And do this, understanding the occasion. The hour has come for you to wake up from your slumber, for our salvation is nearer now than when we first believed.","sources":{"KJV":{"text":"And that, knowing the time, that now it is high time to awake out of sleep: for now is our salvation nearer than when we believed."},"BSB":{"text":"And do this, understanding the occasion. The hour has come for you to wake up from your slumber, for our salvation is nearer now than when we first believed."}},"definableWords":["salvation","believed"],"peopleInVerse":[]},"12":{"text":"The night is far spent, the day is at hand: let us therefore cast off the works of darkness, and let us put on the armour of light.","ref":"Romans 13:12","synthesized":"The night is nearly over; the day has drawn near. So let us lay aside the deeds of darkness and put on the armor of light.","sources":{"KJV":{"text":"The night is far spent, the day is at hand: let us therefore cast off the works of darkness, and let us put on the armour of light."},"BSB":{"text":"The night is nearly over; the day has drawn near. So let us lay aside the deeds of darkness and put on the armor of light."}},"definableWords":["night","day","darkness","light"],"peopleInVerse":[]},"13":{"text":"Let us walk honestly, as in the day; not in rioting and drunkenness, not in chambering and wantonness, not in strife and envying.","ref":"Romans 13:13","synthesized":"Let us behave decently, as in the daytime, not in carousing and drunkenness, not in sexual immorality and debauchery, not in dissension and jealousy.","sources":{"KJV":{"text":"Let us walk honestly, as in the day; not in rioting and drunkenness, not in chambering and wantonness, not in strife and envying."},"BSB":{"text":"Let us behave decently, as in the daytime, not in carousing and drunkenness, not in sexual immorality and debauchery, not in dissension and jealousy."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"But put ye on the Lord Jesus Christ, and make not provision for the flesh, to fulfil the lusts thereof.","ref":"Romans 13:14","synthesized":"Instead, clothe yourselves with the Lord Jesus Christ, and make no provision for the desires of the flesh.","sources":{"KJV":{"text":"But put ye on the Lord Jesus Christ, and make not provision for the flesh, to fulfil the lusts thereof."},"BSB":{"text":"Instead, clothe yourselves with the Lord Jesus Christ, and make no provision for the desires of the flesh."}},"definableWords":["Lord","Christ","make","flesh"],"peopleInVerse":["Jesus"]}}},"14":{"chapter":"14","title":"RECEIVE THE WEAK IN FAITH","verses":{"1":{"text":"Him that is weak in the faith receive ye, but not to doubtful disputations.","ref":"Romans 14:1","synthesized":"Accept him whose faith is weak, without passing judgment on his opinions.","sources":{"KJV":{"text":"Him that is weak in the faith receive ye, but not to doubtful disputations."},"BSB":{"text":"Accept him whose faith is weak, without passing judgment on his opinions."}},"definableWords":["faith","judgment"],"peopleInVerse":[]},"2":{"text":"For one believeth that he may eat all things: another, who is weak, eateth herbs.","ref":"Romans 14:2","synthesized":"For one person has faith to eat all things, while another, who is weak, eats only vegetables.","sources":{"KJV":{"text":"For one believeth that he may eat all things: another, who is weak, eateth herbs."},"BSB":{"text":"For one person has faith to eat all things, while another, who is weak, eats only vegetables."}},"definableWords":["one","faith"],"peopleInVerse":[]},"3":{"text":"Let not him that eateth despise him that eateth not; and let not him which eateth not judge him that eateth: for God hath received him.","ref":"Romans 14:3","synthesized":"The one who eats everything must not belittle the one who does not, and the one who does not eat everything must not judge the one who does, for God has accepted him.","sources":{"KJV":{"text":"Let not him that eateth despise him that eateth not; and let not him which eateth not judge him that eateth: for God hath received him."},"BSB":{"text":"The one who eats everything must not belittle the one who does not, and the one who does not eat everything must not judge the one who does, for God has accepted him."}},"definableWords":["one","God"],"peopleInVerse":[]},"4":{"text":"Who art thou that judgest another man’s servant? to his own master he standeth or falleth. Yea, he shall be holden up: for God is able to make him stand.","ref":"Romans 14:4","synthesized":"Who are you to judge someone else’s servant? To his own master he stands or falls. And he will stand, for the Lord is able to make him stand.","sources":{"KJV":{"text":"Who art thou that judgest another man’s servant? to his own master he standeth or falleth. Yea, he shall be holden up: for God is able to make him stand."},"BSB":{"text":"Who are you to judge someone else’s servant? To his own master he stands or falls. And he will stand, for the Lord is able to make him stand."}},"definableWords":["servant","or","stand","Lord","make"],"peopleInVerse":[]},"5":{"text":"One man esteemeth one day above another: another esteemeth every day alike. Let every man be fully persuaded in his own mind.","ref":"Romans 14:5","synthesized":"One person regards a certain day above the others, while someone else considers every day alike. Each one should be fully convinced in his own mind.","sources":{"KJV":{"text":"One man esteemeth one day above another: another esteemeth every day alike. Let every man be fully persuaded in his own mind."},"BSB":{"text":"One person regards a certain day above the others, while someone else considers every day alike. Each one should be fully convinced in his own mind."}},"definableWords":["one","day","mind"],"peopleInVerse":[]},"6":{"text":"He that regardeth the day, regardeth it unto the Lord; and he that regardeth not the day, to the Lord he doth not regard it. He that eateth, eateth to the Lord, for he giveth God thanks; and he that eateth not, to the Lord he eateth not, and giveth God thanks.","ref":"Romans 14:6","synthesized":"He who observes a special day does so to the Lord; he who eats does so to the Lord, for he gives thanks to God; and he who abstains does so to the Lord and gives thanks to God.","sources":{"KJV":{"text":"He that regardeth the day, regardeth it unto the Lord; and he that regardeth not the day, to the Lord he doth not regard it. He that eateth, eateth to the Lord, for he giveth God thanks; and he that eateth not, to the Lord he eateth not, and giveth God thanks."},"BSB":{"text":"He who observes a special day does so to the Lord; he who eats does so to the Lord, for he gives thanks to God; and he who abstains does so to the Lord and gives thanks to God."}},"definableWords":["day","Lord","God"],"peopleInVerse":[]},"7":{"text":"For none of us liveth to himself, and no man dieth to himself.","ref":"Romans 14:7","synthesized":"For none of us lives to himself alone, and none of us dies to himself alone.","sources":{"KJV":{"text":"For none of us liveth to himself, and no man dieth to himself."},"BSB":{"text":"For none of us lives to himself alone, and none of us dies to himself alone."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For whether we live, we live unto the Lord; and whether we die, we die unto the Lord: whether we live therefore, or die, we are the Lord’s.","ref":"Romans 14:8","synthesized":"If we live, we live to the Lord, and if we die, we die to the Lord. So whether we live or die, we belong to the Lord.","sources":{"KJV":{"text":"For whether we live, we live unto the Lord; and whether we die, we die unto the Lord: whether we live therefore, or die, we are the Lord’s."},"BSB":{"text":"If we live, we live to the Lord, and if we die, we die to the Lord. So whether we live or die, we belong to the Lord."}},"definableWords":["live","Lord","die","or"],"peopleInVerse":[]},"9":{"text":"For to this end Christ both died, and rose, and revived, that he might be Lord both of the dead and living.","ref":"Romans 14:9","synthesized":"For this reason Christ died and returned to life, that He might be the Lord of both the dead and the living.","sources":{"KJV":{"text":"For to this end Christ both died, and rose, and revived, that he might be Lord both of the dead and living."},"BSB":{"text":"For this reason Christ died and returned to life, that He might be the Lord of both the dead and the living."}},"definableWords":["Christ","life","Lord","living"],"peopleInVerse":[]},"10":{"text":"But why dost thou judge thy brother? or why dost thou set at nought thy brother? for we shall all stand before the judgment seat of Christ.","ref":"Romans 14:10","synthesized":"Why, then, do you judge your brother? Or why do you belittle your brother? For we will all stand before God’s judgment seat.","sources":{"KJV":{"text":"But why dost thou judge thy brother? or why dost thou set at nought thy brother? for we shall all stand before the judgment seat of Christ."},"BSB":{"text":"Why, then, do you judge your brother? Or why do you belittle your brother? For we will all stand before God’s judgment seat."}},"definableWords":["brother","or","stand","God","judgment"],"peopleInVerse":[]},"11":{"text":"For it is written, As I live, saith the Lord, every knee shall bow to me, and every tongue shall confess to God.","ref":"Romans 14:11","synthesized":"It is written:  “As surely as I live, says the Lord, every knee will bow before Me; every tongue will confess to God.”","sources":{"KJV":{"text":"For it is written, As I live, saith the Lord, every knee shall bow to me, and every tongue shall confess to God."},"BSB":{"text":"It is written:  “As surely as I live, says the Lord, every knee will bow before Me; every tongue will confess to God.”"}},"definableWords":["live","Lord","God"],"peopleInVerse":[]},"12":{"text":"So then every one of us shall give account of himself to God.","ref":"Romans 14:12","synthesized":"So then, each of us will give an account of himself to God.","sources":{"KJV":{"text":"So then every one of us shall give account of himself to God."},"BSB":{"text":"So then, each of us will give an account of himself to God."}},"definableWords":["God"],"peopleInVerse":[]},"13":{"text":"Let us not therefore judge one another any more: but judge this rather, that no man put a stumblingblock or an occasion to fall in his brother’s way.","ref":"Romans 14:13","synthesized":"Therefore let us stop judging one another. Instead, make up your mind not to put any stumbling block or obstacle in your brother’s way.","sources":{"KJV":{"text":"Let us not therefore judge one another any more: but judge this rather, that no man put a stumblingblock or an occasion to fall in his brother’s way."},"BSB":{"text":"Therefore let us stop judging one another. Instead, make up your mind not to put any stumbling block or obstacle in your brother’s way."}},"definableWords":["one","make","mind","or","brother","way"],"peopleInVerse":[]},"14":{"text":"I know, and am persuaded by the Lord Jesus, that there is nothing unclean of itself: but to him that esteemeth any thing to be unclean, to him it is unclean.","ref":"Romans 14:14","synthesized":"I am convinced and fully persuaded in the Lord Jesus that nothing is unclean in itself. But if anyone regards something as unclean, then for him it is unclean.","sources":{"KJV":{"text":"I know, and am persuaded by the Lord Jesus, that there is nothing unclean of itself: but to him that esteemeth any thing to be unclean, to him it is unclean."},"BSB":{"text":"I am convinced and fully persuaded in the Lord Jesus that nothing is unclean in itself. But if anyone regards something as unclean, then for him it is unclean."}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"15":{"text":"But if thy brother be grieved with thy meat, now walkest thou not charitably. Destroy not him with thy meat, for whom Christ died.","ref":"Romans 14:15","synthesized":"If your brother is distressed by what you eat, you are no longer acting in love. Do not by your eating destroy your brother, for whom Christ died.","sources":{"KJV":{"text":"But if thy brother be grieved with thy meat, now walkest thou not charitably. Destroy not him with thy meat, for whom Christ died."},"BSB":{"text":"If your brother is distressed by what you eat, you are no longer acting in love. Do not by your eating destroy your brother, for whom Christ died."}},"definableWords":["brother","love","Christ"],"peopleInVerse":[]},"16":{"text":"Let not then your good be evil spoken of:","ref":"Romans 14:16","synthesized":"Do not allow what you consider good, then, to be spoken of as evil.","sources":{"KJV":{"text":"Let not then your good be evil spoken of:"},"BSB":{"text":"Do not allow what you consider good, then, to be spoken of as evil."}},"definableWords":["good","evil"],"peopleInVerse":[]},"17":{"text":"For the kingdom of God is not meat and drink; but righteousness, and peace, and joy in the Holy Ghost.","ref":"Romans 14:17","synthesized":"For the kingdom of God is not a matter of eating and drinking, but of righteousness, peace, and joy in the Holy Spirit.","sources":{"KJV":{"text":"For the kingdom of God is not meat and drink; but righteousness, and peace, and joy in the Holy Ghost."},"BSB":{"text":"For the kingdom of God is not a matter of eating and drinking, but of righteousness, peace, and joy in the Holy Spirit."}},"definableWords":["kingdom","God","righteousness","peace","joy","holy","Spirit"],"peopleInVerse":[]},"18":{"text":"For he that in these things serveth Christ is acceptable to God, and approved of men.","ref":"Romans 14:18","synthesized":"For whoever serves Christ in this way is pleasing to God and approved by men.","sources":{"KJV":{"text":"For he that in these things serveth Christ is acceptable to God, and approved of men."},"BSB":{"text":"For whoever serves Christ in this way is pleasing to God and approved by men."}},"definableWords":["Christ","way","God","men"],"peopleInVerse":[]},"19":{"text":"Let us therefore follow after the things which make for peace, and things wherewith one may edify another.","ref":"Romans 14:19","synthesized":"So then, let us pursue what leads to peace and to mutual edification.","sources":{"KJV":{"text":"Let us therefore follow after the things which make for peace, and things wherewith one may edify another."},"BSB":{"text":"So then, let us pursue what leads to peace and to mutual edification."}},"definableWords":["peace"],"peopleInVerse":[]},"20":{"text":"For meat destroy not the work of God. All things indeed are pure; but it is evil for that man who eateth with offence.","ref":"Romans 14:20","synthesized":"Do not destroy the work of God for the sake of food. All food is clean, but it is wrong for a man to let his eating be a stumbling block.","sources":{"KJV":{"text":"For meat destroy not the work of God. All things indeed are pure; but it is evil for that man who eateth with offence."},"BSB":{"text":"Do not destroy the work of God for the sake of food. All food is clean, but it is wrong for a man to let his eating be a stumbling block."}},"definableWords":["work","God","man"],"peopleInVerse":[]},"21":{"text":"It is good neither to eat flesh, nor to drink wine, nor any thing whereby thy brother stumbleth, or is offended, or is made weak.","ref":"Romans 14:21","synthesized":"It is better not to eat meat or drink wine or to do anything to cause your brother to stumble.","sources":{"KJV":{"text":"It is good neither to eat flesh, nor to drink wine, nor any thing whereby thy brother stumbleth, or is offended, or is made weak."},"BSB":{"text":"It is better not to eat meat or drink wine or to do anything to cause your brother to stumble."}},"definableWords":["or","brother"],"peopleInVerse":[]},"22":{"text":"Hast thou faith? have it to thyself before God. Happy is he that condemneth not himself in that thing which he alloweth.","ref":"Romans 14:22","synthesized":"Keep your belief about such matters between yourself and God. Blessed is the one who does not condemn himself by what he approves.","sources":{"KJV":{"text":"Hast thou faith? have it to thyself before God. Happy is he that condemneth not himself in that thing which he alloweth."},"BSB":{"text":"Keep your belief about such matters between yourself and God. Blessed is the one who does not condemn himself by what he approves."}},"definableWords":["keep","God","blessed","one"],"peopleInVerse":[]},"23":{"text":"And he that doubteth is damned if he eat, because he eateth not of faith: for whatsoever is not of faith is sin.","ref":"Romans 14:23","synthesized":"But the one who has doubts is condemned if he eats, because his eating is not from faith; and everything that is not from faith is sin.","sources":{"KJV":{"text":"And he that doubteth is damned if he eat, because he eateth not of faith: for whatsoever is not of faith is sin."},"BSB":{"text":"But the one who has doubts is condemned if he eats, because his eating is not from faith; and everything that is not from faith is sin."}},"definableWords":["one","faith","sin"],"peopleInVerse":[]}}},"15":{"chapter":"15","title":"WE WHO ARE STRONG — BEAR THE INFIRMITIES","verses":{"1":{"text":"We then that are strong ought to bear the infirmities of the weak, and not to please ourselves.","ref":"Romans 15:1","synthesized":"We who are strong ought to bear with the shortcomings of the weak and not to please ourselves.","sources":{"KJV":{"text":"We then that are strong ought to bear the infirmities of the weak, and not to please ourselves."},"BSB":{"text":"We who are strong ought to bear with the shortcomings of the weak and not to please ourselves."}},"definableWords":["strong"],"peopleInVerse":[]},"2":{"text":"Let every one of us please his neighbour for his good to edification.","ref":"Romans 15:2","synthesized":"Each of us should please his neighbor for his good, to build him up.","sources":{"KJV":{"text":"Let every one of us please his neighbour for his good to edification."},"BSB":{"text":"Each of us should please his neighbor for his good, to build him up."}},"definableWords":["good"],"peopleInVerse":[]},"3":{"text":"For even Christ pleased not himself; but, as it is written, The reproaches of them that reproached thee fell on me.","ref":"Romans 15:3","synthesized":"For even Christ did not please Himself, but as it is written: “The insults of those who insult You have fallen on Me.”","sources":{"KJV":{"text":"For even Christ pleased not himself; but, as it is written, The reproaches of them that reproached thee fell on me."},"BSB":{"text":"For even Christ did not please Himself, but as it is written: “The insults of those who insult You have fallen on Me.”"}},"definableWords":["Christ"],"peopleInVerse":[]},"4":{"text":"For whatsoever things were written aforetime were written for our learning, that we through patience and comfort of the scriptures might have hope.","ref":"Romans 15:4","synthesized":"For everything that was written in the past was written for our instruction, so that through endurance and the encouragement of the Scriptures, we might have hope.","sources":{"KJV":{"text":"For whatsoever things were written aforetime were written for our learning, that we through patience and comfort of the scriptures might have hope."},"BSB":{"text":"For everything that was written in the past was written for our instruction, so that through endurance and the encouragement of the Scriptures, we might have hope."}},"definableWords":["hope"],"peopleInVerse":[]},"5":{"text":"Now the God of patience and consolation grant you to be likeminded one toward another according to Christ Jesus:","ref":"Romans 15:5","synthesized":"Now may the God who gives endurance and encouragement grant you harmony with one another in Christ Jesus,","sources":{"KJV":{"text":"Now the God of patience and consolation grant you to be likeminded one toward another according to Christ Jesus:"},"BSB":{"text":"Now may the God who gives endurance and encouragement grant you harmony with one another in Christ Jesus,"}},"definableWords":["God","one","Christ"],"peopleInVerse":["Jesus"]},"6":{"text":"That ye may with one mind and one mouth glorify God, even the Father of our Lord Jesus Christ.","ref":"Romans 15:6","synthesized":"so that with one mind and one voice you may glorify the God and Father of our Lord Jesus Christ.","sources":{"KJV":{"text":"That ye may with one mind and one mouth glorify God, even the Father of our Lord Jesus Christ."},"BSB":{"text":"so that with one mind and one voice you may glorify the God and Father of our Lord Jesus Christ."}},"definableWords":["one","mind","voice","God","Father","Lord","Christ"],"peopleInVerse":["Jesus"]},"7":{"text":"Wherefore receive ye one another, as Christ also received us to the glory of God.","ref":"Romans 15:7","synthesized":"Accept one another, then, just as Christ accepted you, in order to bring glory to God.","sources":{"KJV":{"text":"Wherefore receive ye one another, as Christ also received us to the glory of God."},"BSB":{"text":"Accept one another, then, just as Christ accepted you, in order to bring glory to God."}},"definableWords":["one","Christ","glory","God"],"peopleInVerse":[]},"8":{"text":"Now I say that Jesus Christ was a minister of the circumcision for the truth of God, to confirm the promises made unto the fathers:","ref":"Romans 15:8","synthesized":"For I tell you that Christ has become a servant of the circumcised on behalf of God’s truth, to confirm the promises made to the patriarchs,","sources":{"KJV":{"text":"Now I say that Jesus Christ was a minister of the circumcision for the truth of God, to confirm the promises made unto the fathers:"},"BSB":{"text":"For I tell you that Christ has become a servant of the circumcised on behalf of God’s truth, to confirm the promises made to the patriarchs,"}},"definableWords":["Christ","servant","circumcised","God","truth","made"],"peopleInVerse":[]},"9":{"text":"And that the Gentiles might glorify God for his mercy; as it is written, For this cause I will confess to thee among the Gentiles, and sing unto thy name.","ref":"Romans 15:9","synthesized":"so that the Gentiles may glorify God for His mercy. As it is written:  “Therefore I will praise You among the Gentiles; I will sing hymns to Your name.”","sources":{"KJV":{"text":"And that the Gentiles might glorify God for his mercy; as it is written, For this cause I will confess to thee among the Gentiles, and sing unto thy name."},"BSB":{"text":"so that the Gentiles may glorify God for His mercy. As it is written:  “Therefore I will praise You among the Gentiles; I will sing hymns to Your name.”"}},"definableWords":["God","mercy","praise","name"],"peopleInVerse":[]},"10":{"text":"And again he saith, Rejoice, ye Gentiles, with his people.","ref":"Romans 15:10","synthesized":"Again, it says:  “Rejoice, O Gentiles, with His people.”","sources":{"KJV":{"text":"And again he saith, Rejoice, ye Gentiles, with his people."},"BSB":{"text":"Again, it says:  “Rejoice, O Gentiles, with His people.”"}},"definableWords":["people"],"peopleInVerse":[]},"11":{"text":"And again, Praise the Lord, all ye Gentiles; and laud him, all ye people.","ref":"Romans 15:11","synthesized":"And again:  “Praise the Lord, all you Gentiles, and extol Him, all you peoples.”","sources":{"KJV":{"text":"And again, Praise the Lord, all ye Gentiles; and laud him, all ye people."},"BSB":{"text":"And again:  “Praise the Lord, all you Gentiles, and extol Him, all you peoples.”"}},"definableWords":["praise","Lord"],"peopleInVerse":[]},"12":{"text":"And again, Esaias saith, There shall be a root of Jesse, and he that shall rise to reign over the Gentiles; in him shall the Gentiles trust.","ref":"Romans 15:12","synthesized":"And once more, Isaiah says:  “The Root of Jesse will appear, One who will arise to rule over the Gentiles; in Him the Gentiles will put their hope.”","sources":{"KJV":{"text":"And again, Esaias saith, There shall be a root of Jesse, and he that shall rise to reign over the Gentiles; in him shall the Gentiles trust."},"BSB":{"text":"And once more, Isaiah says:  “The Root of Jesse will appear, One who will arise to rule over the Gentiles; in Him the Gentiles will put their hope.”"}},"definableWords":["one","rule","hope"],"peopleInVerse":["Isaiah"]},"13":{"text":"Now the God of hope fill you with all joy and peace in believing, that ye may abound in hope, through the power of the Holy Ghost.","ref":"Romans 15:13","synthesized":"Now may the God of hope fill you with all joy and peace as you believe in Him, so that you may overflow with hope by the power of the Holy Spirit.","sources":{"KJV":{"text":"Now the God of hope fill you with all joy and peace in believing, that ye may abound in hope, through the power of the Holy Ghost."},"BSB":{"text":"Now may the God of hope fill you with all joy and peace as you believe in Him, so that you may overflow with hope by the power of the Holy Spirit."}},"definableWords":["God","hope","fill","joy","peace","holy","Spirit"],"peopleInVerse":[]},"14":{"text":"And I myself also am persuaded of you, my brethren, that ye also are full of goodness, filled with all knowledge, able also to admonish one another.","ref":"Romans 15:14","synthesized":"I myself am convinced, my brothers, that you yourselves are full of goodness, brimming with knowledge, and able to instruct one another.","sources":{"KJV":{"text":"And I myself also am persuaded of you, my brethren, that ye also are full of goodness, filled with all knowledge, able also to admonish one another."},"BSB":{"text":"I myself am convinced, my brothers, that you yourselves are full of goodness, brimming with knowledge, and able to instruct one another."}},"definableWords":["knowledge","one"],"peopleInVerse":[]},"15":{"text":"Nevertheless, brethren, I have written the more boldly unto you in some sort, as putting you in mind, because of the grace that is given to me of God,","ref":"Romans 15:15","synthesized":"However, I have written you a bold reminder on some points, because of the grace God has given me","sources":{"KJV":{"text":"Nevertheless, brethren, I have written the more boldly unto you in some sort, as putting you in mind, because of the grace that is given to me of God,"},"BSB":{"text":"However, I have written you a bold reminder on some points, because of the grace God has given me"}},"definableWords":["grace","God"],"peopleInVerse":[]},"16":{"text":"That I should be the minister of Jesus Christ to the Gentiles, ministering the gospel of God, that the offering up of the Gentiles might be acceptable, being sanctified by the Holy Ghost.","ref":"Romans 15:16","synthesized":"to be a minister of Christ Jesus to the Gentiles in the priestly service of the gospel of God, so that the Gentiles might become an offering acceptable to God, sanctified by the Holy Spirit.","sources":{"KJV":{"text":"That I should be the minister of Jesus Christ to the Gentiles, ministering the gospel of God, that the offering up of the Gentiles might be acceptable, being sanctified by the Holy Ghost."},"BSB":{"text":"to be a minister of Christ Jesus to the Gentiles in the priestly service of the gospel of God, so that the Gentiles might become an offering acceptable to God, sanctified by the Holy Spirit."}},"definableWords":["Christ","gospel","God","offering","holy","Spirit"],"peopleInVerse":["Jesus"]},"17":{"text":"I have therefore whereof I may glory through Jesus Christ in those things which pertain to God.","ref":"Romans 15:17","synthesized":"Therefore I exult in Christ Jesus in my service to God.","sources":{"KJV":{"text":"I have therefore whereof I may glory through Jesus Christ in those things which pertain to God."},"BSB":{"text":"Therefore I exult in Christ Jesus in my service to God."}},"definableWords":["Christ","God"],"peopleInVerse":["Jesus"]},"18":{"text":"For I will not dare to speak of any of those things which Christ hath not wrought by me, to make the Gentiles obedient, by word and deed,","ref":"Romans 15:18","synthesized":"I will not presume to speak of anything except what Christ has accomplished through me in leading the Gentiles to obedience by word and deed,","sources":{"KJV":{"text":"For I will not dare to speak of any of those things which Christ hath not wrought by me, to make the Gentiles obedient, by word and deed,"},"BSB":{"text":"I will not presume to speak of anything except what Christ has accomplished through me in leading the Gentiles to obedience by word and deed,"}},"definableWords":["Christ","word"],"peopleInVerse":[]},"19":{"text":"Through mighty signs and wonders, by the power of the Spirit of God; so that from Jerusalem, and round about unto Illyricum, I have fully preached the gospel of Christ.","ref":"Romans 15:19","synthesized":"by the power of signs and wonders, and by the power of the Spirit of God. So from Jerusalem all the way around to Illyricum, I have fully proclaimed the gospel of Christ.","sources":{"KJV":{"text":"Through mighty signs and wonders, by the power of the Spirit of God; so that from Jerusalem, and round about unto Illyricum, I have fully preached the gospel of Christ."},"BSB":{"text":"by the power of signs and wonders, and by the power of the Spirit of God. So from Jerusalem all the way around to Illyricum, I have fully proclaimed the gospel of Christ."}},"definableWords":["Spirit","God","Jerusalem","way","gospel","Christ"],"peopleInVerse":[]},"20":{"text":"Yea, so have I strived to preach the gospel, not where Christ was named, lest I should build upon another man’s foundation:","ref":"Romans 15:20","synthesized":"In this way I have aspired to preach the gospel where Christ was not known, so that I would not be building on someone else’s foundation.","sources":{"KJV":{"text":"Yea, so have I strived to preach the gospel, not where Christ was named, lest I should build upon another man’s foundation:"},"BSB":{"text":"In this way I have aspired to preach the gospel where Christ was not known, so that I would not be building on someone else’s foundation."}},"definableWords":["way","gospel","Christ"],"peopleInVerse":[]},"21":{"text":"But as it is written, To whom he was not spoken of, they shall see: and they that have not heard shall understand.","ref":"Romans 15:21","synthesized":"Rather, as it is written:  “Those who were not told about Him will see, and those who have not heard will understand.”","sources":{"KJV":{"text":"But as it is written, To whom he was not spoken of, they shall see: and they that have not heard shall understand."},"BSB":{"text":"Rather, as it is written:  “Those who were not told about Him will see, and those who have not heard will understand.”"}},"definableWords":["see"],"peopleInVerse":[]},"22":{"text":"For which cause also I have been much hindered from coming to you.","ref":"Romans 15:22","synthesized":"That is why I have often been hindered from coming to you.","sources":{"KJV":{"text":"For which cause also I have been much hindered from coming to you."},"BSB":{"text":"That is why I have often been hindered from coming to you."}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"But now having no more place in these parts, and having a great desire these many years to come unto you;","ref":"Romans 15:23","synthesized":"But now that there are no further opportunities for me in these regions, and since I have longed for many years to visit you,","sources":{"KJV":{"text":"But now having no more place in these parts, and having a great desire these many years to come unto you;"},"BSB":{"text":"But now that there are no further opportunities for me in these regions, and since I have longed for many years to visit you,"}},"definableWords":["years"],"peopleInVerse":[]},"24":{"text":"Whensoever I take my journey into Spain, I will come to you: for I trust to see you in my journey, and to be brought on my way thitherward by you, if first I be somewhat filled with your company.","ref":"Romans 15:24","synthesized":"I hope to see you on my way to Spain. And after I have enjoyed your company for a while, you can equip me for my journey.","sources":{"KJV":{"text":"Whensoever I take my journey into Spain, I will come to you: for I trust to see you in my journey, and to be brought on my way thitherward by you, if first I be somewhat filled with your company."},"BSB":{"text":"I hope to see you on my way to Spain. And after I have enjoyed your company for a while, you can equip me for my journey."}},"definableWords":["hope","see","way"],"peopleInVerse":[]},"25":{"text":"But now I go unto Jerusalem to minister unto the saints.","ref":"Romans 15:25","synthesized":"Now, however, I am on my way to Jerusalem to serve the saints there.","sources":{"KJV":{"text":"But now I go unto Jerusalem to minister unto the saints."},"BSB":{"text":"Now, however, I am on my way to Jerusalem to serve the saints there."}},"definableWords":["way","Jerusalem"],"peopleInVerse":[]},"26":{"text":"For it hath pleased them of Macedonia and Achaia to make a certain contribution for the poor saints which are at Jerusalem.","ref":"Romans 15:26","synthesized":"For Macedonia and Achaia were pleased to make a contribution for the poor among the saints in Jerusalem.","sources":{"KJV":{"text":"For it hath pleased them of Macedonia and Achaia to make a certain contribution for the poor saints which are at Jerusalem."},"BSB":{"text":"For Macedonia and Achaia were pleased to make a contribution for the poor among the saints in Jerusalem."}},"definableWords":["make","Jerusalem"],"peopleInVerse":[]},"27":{"text":"It hath pleased them verily; and their debtors they are. For if the Gentiles have been made partakers of their spiritual things, their duty is also to minister unto them in carnal things.","ref":"Romans 15:27","synthesized":"They were pleased to do it, and indeed they owe it to them. For if the Gentiles have shared in their spiritual blessings, they are obligated to minister to them with material blessings.","sources":{"KJV":{"text":"It hath pleased them verily; and their debtors they are. For if the Gentiles have been made partakers of their spiritual things, their duty is also to minister unto them in carnal things."},"BSB":{"text":"They were pleased to do it, and indeed they owe it to them. For if the Gentiles have shared in their spiritual blessings, they are obligated to minister to them with material blessings."}},"definableWords":[],"peopleInVerse":[]},"28":{"text":"When therefore I have performed this, and have sealed to them this fruit, I will come by you into Spain.","ref":"Romans 15:28","synthesized":"So after I have completed this service and have safely delivered this bounty to them, I will set off to Spain by way of you.","sources":{"KJV":{"text":"When therefore I have performed this, and have sealed to them this fruit, I will come by you into Spain."},"BSB":{"text":"So after I have completed this service and have safely delivered this bounty to them, I will set off to Spain by way of you."}},"definableWords":["way"],"peopleInVerse":[]},"29":{"text":"And I am sure that, when I come unto you, I shall come in the fulness of the blessing of the gospel of Christ.","ref":"Romans 15:29","synthesized":"I know that when I come to you, I will come in the fullness of the blessing of Christ.","sources":{"KJV":{"text":"And I am sure that, when I come unto you, I shall come in the fulness of the blessing of the gospel of Christ."},"BSB":{"text":"I know that when I come to you, I will come in the fullness of the blessing of Christ."}},"definableWords":["blessing","Christ"],"peopleInVerse":[]},"30":{"text":"Now I beseech you, brethren, for the Lord Jesus Christ’s sake, and for the love of the Spirit, that ye strive together with me in your prayers to God for me;","ref":"Romans 15:30","synthesized":"Now I urge you, brothers, by our Lord Jesus Christ and by the love of the Spirit, to join me in my struggle by praying to God for me.","sources":{"KJV":{"text":"Now I beseech you, brethren, for the Lord Jesus Christ’s sake, and for the love of the Spirit, that ye strive together with me in your prayers to God for me;"},"BSB":{"text":"Now I urge you, brothers, by our Lord Jesus Christ and by the love of the Spirit, to join me in my struggle by praying to God for me."}},"definableWords":["Lord","Christ","love","Spirit","God"],"peopleInVerse":["Jesus"]},"31":{"text":"That I may be delivered from them that do not believe in Judaea; and that my service which I have for Jerusalem may be accepted of the saints;","ref":"Romans 15:31","synthesized":"Pray that I may be delivered from the unbelievers in Judea, and that my service in Jerusalem may be acceptable to the saints there,","sources":{"KJV":{"text":"That I may be delivered from them that do not believe in Judaea; and that my service which I have for Jerusalem may be accepted of the saints;"},"BSB":{"text":"Pray that I may be delivered from the unbelievers in Judea, and that my service in Jerusalem may be acceptable to the saints there,"}},"definableWords":["Judea","Jerusalem"],"peopleInVerse":[]},"32":{"text":"That I may come unto you with joy by the will of God, and may with you be refreshed.","ref":"Romans 15:32","synthesized":"so that by God’s will I may come to you with joy and together with you be refreshed.","sources":{"KJV":{"text":"That I may come unto you with joy by the will of God, and may with you be refreshed."},"BSB":{"text":"so that by God’s will I may come to you with joy and together with you be refreshed."}},"definableWords":["God","joy"],"peopleInVerse":[]},"33":{"text":"Now the God of peace be with you all. Amen.","ref":"Romans 15:33","synthesized":"The God of peace be with all of you. Amen.","sources":{"KJV":{"text":"Now the God of peace be with you all. Amen."},"BSB":{"text":"The God of peace be with all of you. Amen."}},"definableWords":["God","peace"],"peopleInVerse":[]}}},"16":{"chapter":"16","title":"PAUL'S CLOSING GREETINGS","verses":{"1":{"text":"I commend unto you Phebe our sister, which is a servant of the church which is at Cenchrea:","ref":"Romans 16:1","synthesized":"I commend to you our sister Phoebe, a servant of the church in Cenchrea.","sources":{"KJV":{"text":"I commend unto you Phebe our sister, which is a servant of the church which is at Cenchrea:"},"BSB":{"text":"I commend to you our sister Phoebe, a servant of the church in Cenchrea."}},"definableWords":["sister","servant","church"],"peopleInVerse":[]},"2":{"text":"That ye receive her in the Lord, as becometh saints, and that ye assist her in whatsoever business she hath need of you: for she hath been a succourer of many, and of myself also.","ref":"Romans 16:2","synthesized":"Welcome her in the Lord in a manner worthy of the saints, and assist her with anything she may need from you. For she has been a great help to many people, including me.","sources":{"KJV":{"text":"That ye receive her in the Lord, as becometh saints, and that ye assist her in whatsoever business she hath need of you: for she hath been a succourer of many, and of myself also."},"BSB":{"text":"Welcome her in the Lord in a manner worthy of the saints, and assist her with anything she may need from you. For she has been a great help to many people, including me."}},"definableWords":["Lord","great","people"],"peopleInVerse":[]},"3":{"text":"Greet Priscilla and Aquila my helpers in Christ Jesus:","ref":"Romans 16:3","synthesized":"Greet Prisca and Aquila, my fellow workers in Christ Jesus,","sources":{"KJV":{"text":"Greet Priscilla and Aquila my helpers in Christ Jesus:"},"BSB":{"text":"Greet Prisca and Aquila, my fellow workers in Christ Jesus,"}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"4":{"text":"Who have for my life laid down their own necks: unto whom not only I give thanks, but also all the churches of the Gentiles.","ref":"Romans 16:4","synthesized":"who have risked their lives for me. Not only I but all the churches of the Gentiles are grateful to them.","sources":{"KJV":{"text":"Who have for my life laid down their own necks: unto whom not only I give thanks, but also all the churches of the Gentiles."},"BSB":{"text":"who have risked their lives for me. Not only I but all the churches of the Gentiles are grateful to them."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"Likewise greet the church that is in their house. Salute my well-beloved Epaenetus, who is the firstfruits of Achaia unto Christ.","ref":"Romans 16:5","synthesized":"Greet also the church that meets at their house.  Greet my beloved Epenetus, who was the first convert to Christ in the province of Asia.","sources":{"KJV":{"text":"Likewise greet the church that is in their house. Salute my well-beloved Epaenetus, who is the firstfruits of Achaia unto Christ."},"BSB":{"text":"Greet also the church that meets at their house.  Greet my beloved Epenetus, who was the first convert to Christ in the province of Asia."}},"definableWords":["church","house","Christ"],"peopleInVerse":[]},"6":{"text":"Greet Mary, who bestowed much labour on us.","ref":"Romans 16:6","synthesized":"Greet Mary, who has worked very hard for you.","sources":{"KJV":{"text":"Greet Mary, who bestowed much labour on us."},"BSB":{"text":"Greet Mary, who has worked very hard for you."}},"definableWords":[],"peopleInVerse":["Mary"]},"7":{"text":"Salute Andronicus and Junia, my kinsmen, and my fellow-prisoners, who are of note among the apostles, who also were in Christ before me.","ref":"Romans 16:7","synthesized":"Greet Andronicus and Junia, my fellow countrymen and fellow prisoners. They are outstanding among the apostles, and they were in Christ before I was.","sources":{"KJV":{"text":"Salute Andronicus and Junia, my kinsmen, and my fellow-prisoners, who are of note among the apostles, who also were in Christ before me."},"BSB":{"text":"Greet Andronicus and Junia, my fellow countrymen and fellow prisoners. They are outstanding among the apostles, and they were in Christ before I was."}},"definableWords":["Christ"],"peopleInVerse":[]},"8":{"text":"Greet Amplias my beloved in the Lord.","ref":"Romans 16:8","synthesized":"Greet Ampliatus, my beloved in the Lord.","sources":{"KJV":{"text":"Greet Amplias my beloved in the Lord."},"BSB":{"text":"Greet Ampliatus, my beloved in the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"9":{"text":"Salute Urbane, our helper in Christ, and Stachys my beloved.","ref":"Romans 16:9","synthesized":"Greet Urbanus, our fellow worker in Christ, and my beloved Stachys.","sources":{"KJV":{"text":"Salute Urbane, our helper in Christ, and Stachys my beloved."},"BSB":{"text":"Greet Urbanus, our fellow worker in Christ, and my beloved Stachys."}},"definableWords":["Christ"],"peopleInVerse":[]},"10":{"text":"Salute Apelles approved in Christ. Salute them which are of Aristobulus’ household.","ref":"Romans 16:10","synthesized":"Greet Apelles, who is approved in Christ.  Greet those who belong to the household of Aristobulus.","sources":{"KJV":{"text":"Salute Apelles approved in Christ. Salute them which are of Aristobulus’ household."},"BSB":{"text":"Greet Apelles, who is approved in Christ.  Greet those who belong to the household of Aristobulus."}},"definableWords":["Christ"],"peopleInVerse":[]},"11":{"text":"Salute Herodion my kinsman. Greet them that be of the household of Narcissus, which are in the Lord.","ref":"Romans 16:11","synthesized":"Greet Herodion, my fellow countryman.  Greet those from the household of Narcissus who are in the Lord.","sources":{"KJV":{"text":"Salute Herodion my kinsman. Greet them that be of the household of Narcissus, which are in the Lord."},"BSB":{"text":"Greet Herodion, my fellow countryman.  Greet those from the household of Narcissus who are in the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"12":{"text":"Salute Tryphena and Tryphosa, who labour in the Lord. Salute the beloved Persis, which laboured much in the Lord.","ref":"Romans 16:12","synthesized":"Greet Tryphena and Tryphosa, women who have worked hard in the Lord.  Greet my beloved Persis, who has worked very hard in the Lord.","sources":{"KJV":{"text":"Salute Tryphena and Tryphosa, who labour in the Lord. Salute the beloved Persis, which laboured much in the Lord."},"BSB":{"text":"Greet Tryphena and Tryphosa, women who have worked hard in the Lord.  Greet my beloved Persis, who has worked very hard in the Lord."}},"definableWords":["women","Lord"],"peopleInVerse":[]},"13":{"text":"Salute Rufus chosen in the Lord, and his mother and mine.","ref":"Romans 16:13","synthesized":"Greet Rufus, chosen in the Lord, and his mother, who has been a mother to me as well.","sources":{"KJV":{"text":"Salute Rufus chosen in the Lord, and his mother and mine."},"BSB":{"text":"Greet Rufus, chosen in the Lord, and his mother, who has been a mother to me as well."}},"definableWords":["Lord","mother"],"peopleInVerse":[]},"14":{"text":"Salute Asyncritus, Phlegon, Hermas, Patrobas, Hermes, and the brethren which are with them.","ref":"Romans 16:14","synthesized":"Greet Asyncritus, Phlegon, Hermes, Patrobas, Hermas, and the brothers with them.","sources":{"KJV":{"text":"Salute Asyncritus, Phlegon, Hermas, Patrobas, Hermes, and the brethren which are with them."},"BSB":{"text":"Greet Asyncritus, Phlegon, Hermes, Patrobas, Hermas, and the brothers with them."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Salute Philologus, and Julia, Nereus, and his sister, and Olympas, and all the saints which are with them.","ref":"Romans 16:15","synthesized":"Greet Philologus and Julia, Nereus and his sister, and Olympas and all the saints with them.","sources":{"KJV":{"text":"Salute Philologus, and Julia, Nereus, and his sister, and Olympas, and all the saints which are with them."},"BSB":{"text":"Greet Philologus and Julia, Nereus and his sister, and Olympas and all the saints with them."}},"definableWords":["sister"],"peopleInVerse":[]},"16":{"text":"Salute one another with an holy kiss. The churches of Christ salute you.","ref":"Romans 16:16","synthesized":"Greet one another with a holy kiss.  All the churches of Christ send you greetings.","sources":{"KJV":{"text":"Salute one another with an holy kiss. The churches of Christ salute you."},"BSB":{"text":"Greet one another with a holy kiss.  All the churches of Christ send you greetings."}},"definableWords":["one","holy","Christ"],"peopleInVerse":[]},"17":{"text":"Now I beseech you, brethren, mark them which cause divisions and offences contrary to the doctrine which ye have learned; and avoid them.","ref":"Romans 16:17","synthesized":"Now I urge you, brothers, to watch out for those who create divisions and obstacles that are contrary to the teaching you have learned. Turn away from them.","sources":{"KJV":{"text":"Now I beseech you, brethren, mark them which cause divisions and offences contrary to the doctrine which ye have learned; and avoid them."},"BSB":{"text":"Now I urge you, brothers, to watch out for those who create divisions and obstacles that are contrary to the teaching you have learned. Turn away from them."}},"definableWords":["create"],"peopleInVerse":[]},"18":{"text":"For they that are such serve not our Lord Jesus Christ, but their own belly; and by good words and fair speeches deceive the hearts of the simple.","ref":"Romans 16:18","synthesized":"For such people are not serving our Lord Christ, but their own appetites. By smooth talk and flattery they deceive the hearts of the naive.","sources":{"KJV":{"text":"For they that are such serve not our Lord Jesus Christ, but their own belly; and by good words and fair speeches deceive the hearts of the simple."},"BSB":{"text":"For such people are not serving our Lord Christ, but their own appetites. By smooth talk and flattery they deceive the hearts of the naive."}},"definableWords":["people","Lord","Christ"],"peopleInVerse":[]},"19":{"text":"For your obedience is come abroad unto all men. I am glad therefore on your behalf: but yet I would have you wise unto that which is good, and simple concerning evil.","ref":"Romans 16:19","synthesized":"Everyone has heard about your obedience, so I rejoice over you. But I want you to be wise about what is good and innocent about what is evil.","sources":{"KJV":{"text":"For your obedience is come abroad unto all men. I am glad therefore on your behalf: but yet I would have you wise unto that which is good, and simple concerning evil."},"BSB":{"text":"Everyone has heard about your obedience, so I rejoice over you. But I want you to be wise about what is good and innocent about what is evil."}},"definableWords":["good","evil"],"peopleInVerse":[]},"20":{"text":"And the God of peace shall bruise Satan under your feet shortly. The grace of our Lord Jesus Christ be with you. Amen.","ref":"Romans 16:20","synthesized":"The God of peace will soon crush Satan under your feet. The grace of our Lord Jesus Christ be with you.","sources":{"KJV":{"text":"And the God of peace shall bruise Satan under your feet shortly. The grace of our Lord Jesus Christ be with you. Amen."},"BSB":{"text":"The God of peace will soon crush Satan under your feet. The grace of our Lord Jesus Christ be with you."}},"definableWords":["God","peace","Satan","grace","Lord","Christ"],"peopleInVerse":["Jesus"]},"21":{"text":"Timotheus my workfellow, and Lucius, and Jason, and Sosipater, my kinsmen, salute you.","ref":"Romans 16:21","synthesized":"Timothy, my fellow worker, sends you greetings, as do Lucius, Jason, and Sosipater, my fellow countrymen.","sources":{"KJV":{"text":"Timotheus my workfellow, and Lucius, and Jason, and Sosipater, my kinsmen, salute you."},"BSB":{"text":"Timothy, my fellow worker, sends you greetings, as do Lucius, Jason, and Sosipater, my fellow countrymen."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"I Tertius, who wrote this epistle, salute you in the Lord.","ref":"Romans 16:22","synthesized":"I, Tertius, who wrote down this letter, greet you in the Lord.","sources":{"KJV":{"text":"I Tertius, who wrote this epistle, salute you in the Lord."},"BSB":{"text":"I, Tertius, who wrote down this letter, greet you in the Lord."}},"definableWords":["Lord"],"peopleInVerse":[]},"23":{"text":"Gaius mine host, and of the whole church, saluteth you. Erastus the chamberlain of the city saluteth you, and Quartus a brother.","ref":"Romans 16:23","synthesized":"Gaius, who has hosted me and all the church, sends you greetings.  Erastus, the city treasurer, sends you greetings, as does our brother Quartus.","sources":{"KJV":{"text":"Gaius mine host, and of the whole church, saluteth you. Erastus the chamberlain of the city saluteth you, and Quartus a brother."},"BSB":{"text":"Gaius, who has hosted me and all the church, sends you greetings.  Erastus, the city treasurer, sends you greetings, as does our brother Quartus."}},"definableWords":["church","brother"],"peopleInVerse":[]},"24":{"text":"The grace of our Lord Jesus Christ be with you all. Amen.","ref":"Romans 16:24","synthesized":"The grace of our Lord Jesus Christ be with you all. Amen.","sources":{"KJV":{"text":"The grace of our Lord Jesus Christ be with you all. Amen."}},"definableWords":["grace","Lord","Christ"],"peopleInVerse":["Jesus"]},"25":{"text":"Now to him that is of power to stablish you according to my gospel, and the preaching of Jesus Christ, according to the revelation of the mystery, which was kept secret since the world began,","ref":"Romans 16:25","synthesized":"Now to Him who is able to strengthen you by my gospel and by the proclamation of Jesus Christ, according to the revelation of the mystery concealed for ages past","sources":{"KJV":{"text":"Now to him that is of power to stablish you according to my gospel, and the preaching of Jesus Christ, according to the revelation of the mystery, which was kept secret since the world began,"},"BSB":{"text":"Now to Him who is able to strengthen you by my gospel and by the proclamation of Jesus Christ, according to the revelation of the mystery concealed for ages past"}},"definableWords":["gospel","Christ"],"peopleInVerse":["Jesus"]},"26":{"text":"But now is made manifest, and by the scriptures of the prophets, according to the commandment of the everlasting God, made known to all nations for the obedience of faith:","ref":"Romans 16:26","synthesized":"but now revealed and made known through the writings of the prophets by the command of the eternal God, in order to lead all nations to the obedience that comes from faith—","sources":{"KJV":{"text":"But now is made manifest, and by the scriptures of the prophets, according to the commandment of the everlasting God, made known to all nations for the obedience of faith:"},"BSB":{"text":"but now revealed and made known through the writings of the prophets by the command of the eternal God, in order to lead all nations to the obedience that comes from faith—"}},"definableWords":["made","eternal","God","nations","faith"],"peopleInVerse":[]},"27":{"text":"To God only wise, be glory through Jesus Christ for ever. Amen.","ref":"Romans 16:27","synthesized":"to the only wise God be glory forever through Jesus Christ! Amen.","sources":{"KJV":{"text":"To God only wise, be glory through Jesus Christ for ever. Amen."},"BSB":{"text":"to the only wise God be glory forever through Jesus Christ! Amen."}},"definableWords":["God","glory","Christ"],"peopleInVerse":["Jesus"]}}}};